WITH new_rows (seq, topic_id, qtext, opts, correct, expl, subtheme, srccode) AS (
 VALUES
(1, 'ANA-TRZ',
   'Układ przewodzący serca należy do:',
   '[{"id": "a", "text": "Osierdzia włóknistego"}, {"id": "b", "text": "Nasierdzia"}, {"id": "c", "text": "Szkieletu serca"}, {"id": "d", "text": "Wsierdzia"}, {"id": "e", "text": "Śródsierdzia"}]'::jsonb,
   'e',
   $E$Układ przewodzący (węzeł zatokowo-przedsionkowy, przedsionkowo-komorowy, pęczek Hisa, włókna Purkiniego) leży w **śródsierdziu** (myocardium) — warstwie mięśniowej serca, zbudowany ze zmodyfikowanych kardiomiocytów. **Wsierdzie** (endocardium) wyściela jamy od wewnątrz, **nasierdzie** to blaszka trzewna osierdzia surowiczego, **szkielet serca** to struktury włókniste pierścieni zastawkowych. Mimo specjalizacji do przewodzenia bodźców elementy te pozostają tkanką mięśniową, stąd lokalizacja w warstwie środkowej.$E$,
   'serce', 'ANATLEK-1'),
(2, 'ANA-NAC',
   'Mięśnie podgnykowe unerwione są głównie przez:',
   '[{"id": "a", "text": "pętlę szyjną"}, {"id": "b", "text": "n. dodatkowy"}, {"id": "c", "text": "n. żuchwowo-gnykowy"}, {"id": "d", "text": "nn. nadobojczykowe"}, {"id": "e", "text": "n. twarzowy"}]'::jsonb,
   'a',
   $E$Mięśnie podgnykowe (mostkowo-gnykowy, mostkowo-tarczowy, tarczowo-gnykowy, łopatkowo-gnykowy) unerwia **pętla szyjna** (ansa cervicalis) z włókien **C1–C3**. Wyjątek: m. tarczowo-gnykowy zaopatruje gałąź C1 biegnąca z n. podjęzykowym. Korzeń górny pętli (radix superior) towarzyszy XII, korzeń dolny pochodzi z C2–C3. **N. żuchwowo-gnykowy** (gałąź V3) unerwia mięsień nadgnykowy o tej nazwie, nie podgnykowe.$E$,
   'mięśnie i unerwienie szyi', 'ANATLEK-2'),
(3, 'ANA-OBW',
   'Mięśniem „przewodnikiem” (towarzyszącym) dla nerwu dodatkowego na szyi jest mięsień:',
   '[{"id": "a", "text": "Mostkowo-obojczykowo-sutkowy"}, {"id": "b", "text": "Dźwigacz łopatki"}, {"id": "c", "text": "Tarczowo-gnykowy"}, {"id": "d", "text": "Mostkowo-tarczowy"}, {"id": "e", "text": "Łopatkowo-gnykowy"}]'::jsonb,
   'b',
   $E$W trójkącie tylnym szyi n. dodatkowy (XI) biegnie po powierzchni **m. dźwigacza łopatki**, który stanowi orientacyjny "przewodnik" przy poszukiwaniu nerwu śródoperacyjnie. Nerw wychodzi spod tylnego brzegu **m. MOS** (który unerwia), przecina trójkąt boczny i wnika do **m. czworobocznego**. Dźwigacz łopatki sam jest unerwiony przez n. grzbietowy łopatki (C5) oraz gałęzie splotu szyjnego, nie przez XI — pełni rolę topograficznego punktu odniesienia.$E$,
   'nerw dodatkowy', 'ANATLEK-3'),
(4, 'ANA-KON',
   'Kanał kostno-mięśniowy dla nerwu łokciowego tworzą:',
   '[{"id": "a", "text": "Głowy mięśnia zginacza łokciowego nadgarstka i kość łokciowa"}, {"id": "b", "text": "Mięsień dłoniowy długi i kość łokciowa"}, {"id": "c", "text": "Mięsień nawracacz i kość promieniowa"}, {"id": "d", "text": "Głowy mięśnia nawrotnego obłego i kość łokciowa"}, {"id": "e", "text": "Mięśnie zginacze palców i kość promieniowa"}]'::jsonb,
   'a',
   $E$Po przejściu za **nadkłykciem przyśrodkowym** kości ramiennej n. łokciowy wnika między **głowę ramienną i łokciową m. zginacza łokciowego nadgarstka** (FCU), tworzące kanał Mouchet (cubital tunnel na przedramieniu). To miejsce typowego ucisku nerwu. W obrębie samego rowka nadkłykciowego nerw leży powierzchownie (objaw "trącenia łokciem"). Dalej biegnie z t. łokciową ku nadgarstkowi do kanału Guyona.$E$,
   'nerw łokciowy', 'ANATLEK-4'),
(5, 'ANA-KON',
   'Nerw pośrodkowy układa się w stosunku do tętnicy ramiennej:',
   '[{"id": "a", "text": "Cały czas bocznie"}, {"id": "b", "text": "Cały czas przyśrodkowo"}, {"id": "c", "text": "Początkowo przyśrodkowo i następnie bocznie"}, {"id": "d", "text": "Poniżej, równolegle"}, {"id": "e", "text": "Początkowo bocznie i następnie przyśrodkowo"}]'::jsonb,
   'e',
   $E$Na ramieniu n. pośrodkowy leży najpierw **bocznie** od t. ramiennej (w górnej części), następnie krzyżuje ją od przodu i w dolnej części układa się **przyśrodkowo**, by w dole łokciowym leżeć przyśrodkowo od tętnicy. Powstaje z połączenia korzeni z pęczka bocznego i przyśrodkowego splotu ramiennego ("widełki" obejmujące tętnicę pachową). Topografia istotna przy dostępach naczyniowych i blokadach.$E$,
   'nerw pośrodkowy', 'ANATLEK-5'),
(6, 'ANA-NER',
   'Przez otwór rylcowo-sutkowy przechodzi nerw czaszkowy:',
   '[{"id": "a", "text": "I"}, {"id": "b", "text": "VI"}, {"id": "c", "text": "VII"}, {"id": "d", "text": "III"}, {"id": "e", "text": "V1"}]'::jsonb,
   'c',
   $E$Przez **otwór rylcowo-sutkowy** (foramen stylomastoideum) kości skroniowej wychodzi z czaszki n. twarzowy (**VII**) po przejściu przez kanał nerwu twarzowego. Tuż za otworem oddaje gałąź do m. potyliczno-czołowego, n. uszny tylny i wnika do ślinianki przyusznej, gdzie tworzy splot przyuszniczy (gęsia stopka) z 5 grupami gałęzi mimicznych. **VI** (odwodzący) przechodzi przez szczelinę oczodołową górną, nie przez ten otwór.$E$,
   'nerw twarzowy', 'ANATLEK-6'),
(7, 'ANA-TRZ',
   'Znajduje się w odległości około 50 cm od miejsca przejścia jelita cienkiego w jelito grube. Występuje jedynie u części populacji. Objawem stanu zapalnego zlokalizowanego w tej okolicy mogą być krwawienia do przewodu pokarmowego. W razie appendektomii usuwa się tę strukturę wraz z wyrostkiem robaczkowym. O czym mowa?',
   '[{"id": "a", "text": "Pęcherzyk żółciowy"}, {"id": "b", "text": "Uchyłek jelita cienkiego"}, {"id": "c", "text": "Przewód Stensena"}, {"id": "d", "text": "Fałd kątniczy"}, {"id": "e", "text": "Zagięcie wątrobowe"}]'::jsonb,
   'b',
   $E$Opis odpowiada **uchyłkowi Meckela** — pozostałości przewodu żółtkowego, leżącej na **brzegu przeciwkrezkowym** jelita krętego ok. **40–60 cm** od zastawki krętniczo-kątniczej. Reguła "**dwójek**": ~2% populacji, długość ~2 cale, ~2 stopy od zastawki, częściej u chłopców <2 r.ż., może zawierać 2 typy ektopowej błony (żołądkowa/trzustkowa) — błona żołądkowa powoduje owrzodzenia i krwawienia. **Przewód Stensena** to przewód ślinianki przyusznej.$E$,
   'jelito cienkie', 'ANATLEK-7'),
(8, 'ANA-NAC',
   'Szpara głośni składa się z części:',
   '[{"id": "a", "text": "Górnej i dolnej"}, {"id": "b", "text": "Przedniej i tylnej"}, {"id": "c", "text": "Międzybłoniastej i międzychrząstkowej"}, {"id": "d", "text": "Międzymięśniowej i międzybłoniastej"}, {"id": "e", "text": "Międzynalewkowej i międzyrożkowej"}]'::jsonb,
   'c',
   $E$Szpara głośni (rima glottidis) dzieli się na **część międzybłoniastą** (przednia ~3/5, między fałdami głosowymi/wyrostkami głosowymi) i **międzychrząstkową** (tylna ~2/5, między chrząstkami nalewkowatymi). Część międzybłoniasta odpowiada za fonację, międzychrząstkowa głównie za oddychanie. Jest to najwęższe miejsce krtani u dorosłego (u dziecka — okolica podgłośniowa). Szerokość zmienia mm. wewnętrzne krtani unerwione przez n. krtaniowy wsteczny.$E$,
   'krtań', 'ANATLEK-8'),
(9, 'ANA-NAC',
   'W szczelinie przedniej mięśni pochyłych znajduje/znajdują się:',
   '[{"id": "a", "text": "Tętnica podobojczykowa"}, {"id": "b", "text": "Tętnica podobojczykowa i żyła podobojczykowa"}, {"id": "c", "text": "Splot ramienny"}, {"id": "d", "text": "Tętnica podobojczykowa i splot ramienny"}, {"id": "e", "text": "Żyła podobojczykowa"}]'::jsonb,
   'e',
   $E$Szczelina przednia (między m. pochyłym przednim a m. mostkowo-obojczykowo-sutkowym/od przodu) zawiera **żyłę podobojczykową**. W **szczelinie tylnej** (między m. pochyłym przednim i środkowym) biegną **t. podobojczykowa i pnie splotu ramiennego**. Klucz do zespołu górnego otworu klatki piersiowej: ucisk struktur w tych przestrzeniach. Mnemonik: żyła "przed" pochyłym przednim, tętnica i nerwy "za" nim.$E$,
   'mięśnie pochyłe', 'ANATLEK-9'),
(10, 'ANA-TRZ',
   'Więzadło żołądkowo-okrężnicze jest częścią:',
   '[{"id": "a", "text": "Sieci większej"}, {"id": "b", "text": "Krezki brzusznej"}, {"id": "c", "text": "Krezki grzbietowej"}, {"id": "d", "text": "Sieci mniejszej"}, {"id": "e", "text": "Więzadła sierpowatego"}]'::jsonb,
   'a',
   $E$Więzadło żołądkowo-okrężnicze (lig. gastrocolicum) to górna część **sieci większej** (omentum majus), łącząca krzywiznę większą żołądka z okrężnicą poprzeczną. Sieć większa rozwija się z **krezki grzbietowej** żołądka, ale pytanie wskazuje bezpośrednią strukturę — sieć większą. **Sieć mniejsza** (lig. wątrobowo-żołądkowe i wątrobowo-dwunastnicze) pochodzi z krezki brzusznej. Przez lig. gastrocolicum prowadzi dostęp do torby sieciowej w chirurgii.$E$,
   'otrzewna', 'ANATLEK-10'),
(11, 'ANA-CZA',
   'Płynotok z ucha i zaburzenia równowagi mogą być wynikiem uszkodzenia kości:',
   '[{"id": "a", "text": "Skroniowej"}, {"id": "b", "text": "Klinowej"}, {"id": "c", "text": "Czołowej"}, {"id": "d", "text": "Potylicznej"}, {"id": "e", "text": "Ciemieniowej"}]'::jsonb,
   'a',
   $E$**Kość skroniowa** mieści ucho środkowe i wewnętrzne (błędnik z narządem przedsionkowym). Złamanie **części skalistej** uszkadza błędnik (zaburzenia równowagi) i może rozerwać oponę z wyciekiem płynu mózgowo-rdzeniowego przez trąbkę słuchową/przewód słuchowy (**otorrhea**, otoliquorrhea). Złamania podłużne piramidy częściej uszkadzają ucho środkowe, poprzeczne — wewnętrzne i n. VII/VIII. Objaw Battle'a (krwiak nad wyrostkiem sutkowatym) towarzyszy złamaniom tej okolicy.$E$,
   'kość skroniowa', 'ANATLEK-11'),
(12, 'ANA-OBW',
   'Gałąź udowa nerwu płciowo-udowego przechodzi na udo przez:',
   '[{"id": "a", "text": "Rozstęp naczyń"}, {"id": "b", "text": "Rozstęp mięśni"}, {"id": "c", "text": "Kanał pachwinowy"}, {"id": "d", "text": "Płaszczyznę wychodu"}, {"id": "e", "text": "Kanał zasłonowy"}]'::jsonb,
   'a',
   $E$Gałąź udowa (r. femoralis) n. płciowo-udowego (L1–L2) wchodzi na udo przez **rozstęp naczyń** (lacuna vasorum), bocznie od t. udowej, i unerwia czuciowo skórę trójkąta udowego pod więzadłem pachwinowym. Gałąź płciowa (r. genitalis) biegnie w **kanale pachwinowym** (z powrózkiem nasiennym), unerwia m. dźwigacz jądra (odruch nosidłowy) i skórę moszny/warg sromowych. **Rozstęp mięśni** zawiera m. biodrowo-lędźwiowy i n. udowy.$E$,
   'nerw płciowo-udowy', 'ANATLEK-13'),
(13, 'ANA-TRZ',
   'Część dolną odcinka brzusznego moczowodu krzyżuje od przodu nerw:',
   '[{"id": "a", "text": "Skórny uda boczny"}, {"id": "b", "text": "Kulszowy"}, {"id": "c", "text": "Płciowo-udowy"}, {"id": "d", "text": "Brzuszny trzewny"}, {"id": "e", "text": "Sromowy"}]'::jsonb,
   'c',
   $E$W odcinku brzusznym moczowód biegnie zaotrzewnowo po m. lędźwiowym większym, a **n. płciowo-udowy** (L1–L2) leży na powierzchni tego mięśnia i krzyżuje moczowód od przodu. Moczowód następnie krzyżuje naczynia biodrowe (zwykle t. biodrową zewnętrzną przy rozwidleniu) — to jedno z trzech fizjologicznych zwężeń. Topografia istotna w chirurgii zaotrzewnowej, gdzie chroni się oba przebiegające równolegle struktury.$E$,
   'moczowód', 'ANATLEK-14'),
(14, 'ANA-KON',
   'Przyczep końcowy ścięgna mięśnia strzałkowego długiego znajduje się na:',
   '[{"id": "a", "text": "Kości sześciennej i kości śródstopia IV"}, {"id": "b", "text": "Kości łódkowatej i kości klinowatej bocznej"}, {"id": "c", "text": "Kości skokowej i kości łódkowatej"}, {"id": "d", "text": "Kości piętowej"}, {"id": "e", "text": "Kości klinowatej przyśrodkowej i kości śródstopia I"}]'::jsonb,
   'e',
   $E$M. strzałkowy długi (peroneus longus) biegnie za kostką boczną, pod kością sześcienną przechodzi skośnie przez podeszwę i przyczepia się do **podstawy I kości śródstopia i kości klinowatej przyśrodkowej** — lustrzanie do m. piszczelowego przedniego. Razem tworzą "strzemię" podtrzymujące sklepienie poprzeczne stopy. Mięsień nawraca i zgina podeszwowo stopę; unerwia go n. strzałkowy powierzchowny.$E$,
   'mięśnie podudzia', 'ANATLEK-15'),
(15, 'ANA-OBW',
   'Nerw strzałkowy głęboki:',
   '[{"id": "a", "text": "jest gałęzią nerwu podkolanowego"}, {"id": "b", "text": "unerwia mm. prostowniki na podudziu i grzbiecie stopy i skórę powierzchni międzypalcowej I i II palca"}, {"id": "c", "text": "unerwia wyłącznie mm. prostowniki na podudziu i grzbiecie stopy"}, {"id": "d", "text": "jest bezpośrednią gałęzią n. kulszowego"}, {"id": "e", "text": "unerwia mięśnie strzałkowe"}]'::jsonb,
   'b',
   $E$N. strzałkowy głęboki (gałąź n. strzałkowego wspólnego z n. kulszowego) unerwia **mm. prostowniki przedziału przedniego podudzia** (piszczelowy przedni, prostowniki palców) oraz mm. krótkie grzbietu stopy, a czuciowo **skórę pierwszej przestrzeni międzypalcowej** (między I a II palcem). Mm. strzałkowe zaopatruje n. strzałkowy **powierzchowny**. Porażenie daje stopę opadającą i chód brodzący. Odpowiedź C błędna — nerw daje też zakres czuciowy.$E$,
   'nerw strzałkowy', 'ANATLEK-16'),
(16, 'ANA-TUL',
   'Naczyniem zaopatrującym powłoki brzuszne, ale pochodzącym od tętnic górnej części ciała, jest:',
   '[{"id": "a", "text": "Tętnica okalająca biodro powierzchowna"}, {"id": "b", "text": "Tętnica okalająca biodro głęboka"}, {"id": "c", "text": "Tętnica nabrzuszna górna"}, {"id": "d", "text": "Tętnica nabrzuszna dolna"}, {"id": "e", "text": "Tętnica nabrzuszna powierzchowna"}]'::jsonb,
   'c',
   $E$**T. nabrzuszna górna** to gałąź końcowa **t. piersiowej wewnętrznej** (od t. podobojczykowej — układ górnej części ciała). Biegnie w pochewce m. prostego brzucha i zespala się z **t. nabrzuszną dolną** (od t. biodrowej zewnętrznej), tworząc krążenie oboczne na przedniej ścianie brzucha (anastomoza nadbrzuszna). Pozostałe wymienione naczynia pochodzą z układu tętnicy biodrowej zewnętrznej/udowej (dolna część ciała).$E$,
   'unaczynienie powłok brzucha', 'ANATLEK-17'),
(17, 'ANA-KON',
   'Mięśnie bliźniacze biegną:',
   '[{"id": "a", "text": "Od kresy pośladkowej dolnej do krętarza mniejszego kości udowej"}, {"id": "b", "text": "Od obwodu wcięcia kulszowego mniejszego do dołu krętarzowego kości udowej"}, {"id": "c", "text": "Od kości krzyżowej do krętarza większego kości udowej"}, {"id": "d", "text": "Od obustronnych wyrostków żebrowych kręgów lędźwiowych do grzebienia biodrowego"}, {"id": "e", "text": "Od kolców biodrowych przednich"}]'::jsonb,
   'b',
   $E$Mm. bliźniacze (górny i dolny) należą do grupy rotatorów zewnętrznych biodra. Przyczepiają się od okolicy **wcięcia kulszowego mniejszego** (bliźniaczy górny — kolec kulszowy, dolny — guz kulszowy) i biegną do **dołu krętarzowego** kości udowej, towarzysząc ścięgnu m. zasłaniacza wewnętrznego. Rotują udo na zewnątrz i stabilizują staw biodrowy. Unerwienie: gałęzie ze splotu krzyżowego.$E$,
   'mięśnie okolicy biodra', 'ANATLEK-19'),
(18, 'ANA-KON',
   'Wyniosłość promieniową nadgarstka tworzy/tworzą:',
   '[{"id": "a", "text": "Guzek kości łódeczkowatej i guzek kości czworobocznej większej"}, {"id": "b", "text": "Haczyk kości haczykowatej i guzek kości czworobocznej większej"}, {"id": "c", "text": "Kość grochowata i haczyk kości haczykowatej"}, {"id": "d", "text": "Haczyk kości haczykowatej i guzek kości łódeczkowatej"}, {"id": "e", "text": "Wyrostek rylcowaty kości promieniowej"}]'::jsonb,
   'a',
   $E$Wyniosłość promieniowa nadgarstka (eminentia carpi radialis) tworzą **guzek kości łódeczkowatej i guzek kości czworobocznej większej**. Wyniosłość łokciowa — **kość grochowata i haczyk kości haczykowatej**. Między wyniosłościami rozpięta jest **troczek zginaczy** (lig. carpi transversum), zamykający kanał nadgarstka. To kostne punkty orientacyjne przyczepu troczka i granicy kanału, w którym przebiega n. pośrodkowy i ścięgna zginaczy.$E$,
   'kości nadgarstka', 'ANATLEK-20'),
(19, 'ANA-CZA',
   'Zagłębienie błony bębenkowej zwane pępkiem sąsiaduje od strony wewnętrznej z:',
   '[{"id": "a", "text": "Podstawą strzemiączka"}, {"id": "b", "text": "Końcem rękojeści młoteczka"}, {"id": "c", "text": "Odnogą długą kowadełka"}, {"id": "d", "text": "Odnogą krótką kowadełka"}, {"id": "e", "text": "Głową młoteczka"}]'::jsonb,
   'b',
   $E$Pępek błony bębenkowej (umbo membranae tympani) to najgłębiej wciągnięty punkt błony, odpowiadający przyczepowi **końca rękojeści młoteczka** na jej wewnętrznej powierzchni. Od pępka ku przodowi i dołowi biegnie stożek świetlny (refleks w otoskopii). Rękojeść młoteczka jest wrośnięta w warstwę środkową błony. **Strzemiączko** podstawą tkwi w okienku przedsionka, łącząc się z kowadełkiem — nie kontaktuje z błoną bezpośrednio.$E$,
   'ucho środkowe', 'ANATLEK-21'),
(20, 'ANA-TRZ',
   'W przestrzeni pomiędzy głową trzustki a częścią zstępującą dwunastnicy przebiega:',
   '[{"id": "a", "text": "Przewód pęcherzykowy"}, {"id": "b", "text": "Więzadło głowy trzustki"}, {"id": "c", "text": "Sieć mniejsza"}, {"id": "d", "text": "Przewód żółciowy wspólny"}, {"id": "e", "text": "Więzadło wątrobowo-dwunastnicze"}]'::jsonb,
   'd',
   $E$**Przewód żółciowy wspólny** (ductus choledochus) w końcowym odcinku biegnie w bruździe/przez miąższ **głowy trzustki**, do tyłu od części górnej i zstępującej dwunastnicy, by wraz z przewodem trzustkowym uchodzić na **brodawce większej (Vatera)**. Stąd guzy głowy trzustki dają żółtaczkę mechaniczną przez ucisk choledochusa. **Przewód pęcherzykowy** łączy pęcherzyk z przewodem wątrobowym wspólnym wyżej, w wnęce wątroby.$E$,
   'drogi żółciowe', 'ANATLEK-22'),
(21, 'ANA-TRZ',
   'Opłucna ścienna składa się z wszystkich wymienionych części, z wyjątkiem:',
   '[{"id": "a", "text": "Opłucnej piersiowej"}, {"id": "b", "text": "Opłucnej śródpiersiowej"}, {"id": "c", "text": "Opłucnej żebrowej"}, {"id": "d", "text": "Osklepka opłucnej"}, {"id": "e", "text": "Opłucnej przeponowej"}]'::jsonb,
   'a',
   $E$Opłucna ścienna dzieli się topograficznie na: **żebrową**, **śródpiersiową**, **przeponową** oraz **osklepek** (kopuła nad I żebrem). Określenie "opłucna piersiowa" nie jest częścią klasyfikacji — to dystraktor. Opłucna trzewna (płucna) pokrywa płuco i przechodzi we wnęce w opłucną ścienną. Między blaszkami jama opłucnej z płynem surowiczym. Zachyłki (żebrowo-przeponowy, śródpiersiowo-przeponowy) to rezerwa oddechowa.$E$,
   'opłucna', 'ANATLEK-23'),
(22, 'ANA-OUN',
   'Wstęga rdzeniowa dochodzi do jądra:',
   '[{"id": "a", "text": "brzusznego pośrednio-bocznego wzgórza"}, {"id": "b", "text": "smukłego"}, {"id": "c", "text": "brzusznego tylno-bocznego wzgórza"}, {"id": "d", "text": "brzusznego przednio-bocznego wzgórza"}, {"id": "e", "text": "klinowatego"}]'::jsonb,
   'c',
   $E$Wstęga rdzeniowa (lemniscus spinalis), niosąca drogi rdzeniowo-wzgórzowe (ból, temperatura, czucie grube), kończy się w **jądrze brzusznym tylno-bocznym wzgórza** (VPL). Tam też dochodzi wstęga przyśrodkowa (czucie głębokie z kończyn). Czucie z głowy (n. V) projektuje do jądra **VPM**. **Jądra smukłe i klinowate** to jądra rdzenia przedłużonego (przekaźnik dla sznurów tylnych), nie wzgórza. Z VPL informacja biegnie do kory czuciowej (zakręt zaśrodkowy).$E$,
   'drogi czuciowe', 'ANATLEK-24'),
(23, 'ANA-OUN',
   'Z podanych odpowiedzi wybierz tę, która zawiera jedynie elementy wchodzące w skład śródmózgowia (1 – półkule mózgu, 2 – podwzgórze, 3 – pokrywa, 4 – rdzeń przedłużony, 5 – spoidło sklepienia, 6 – konary mózgu, 7 – wzgórzomózgowie, 8 – spoidło przednie, 9 – ciało modzelowate, 10 – niskowzgórze, 11 – móżdżek, 12 – most):',
   '[{"id": "a", "text": "11, 12"}, {"id": "b", "text": "1, 5, 8, 9"}, {"id": "c", "text": "3, 6"}, {"id": "d", "text": "2, 7, 10"}, {"id": "e", "text": "4, 12"}]'::jsonb,
   'c',
   $E$Śródmózgowie (mesencephalon) tworzą: **pokrywa** (tectum z blaszką czworaczą) oraz **konary mózgu** (pedunculi cerebri = nakrywka + odnogi z istotą czarną). Stąd poprawne 3 i 6. Elementy 2, 7, 10 (podwzgórze, wzgórzomózgowie, niskowzgórze) należą do **międzymózgowia**; 4 i 12 (rdzeń przedłużony, most) do tyłomózgowia; 1, 5, 8, 9 do kresomózgowia. W śródmózgowiu biegnie też wodociąg mózgu łączący komorę III z IV.$E$,
   'śródmózgowie', 'ANATLEK-25'),
(24, 'ANA-OUN',
   'Zwoje pnia współczulnego są zwojami:',
   '[{"id": "a", "text": "Przykręgowymi"}, {"id": "b", "text": "Śródściennymi"}, {"id": "c", "text": "Czaszkowymi"}, {"id": "d", "text": "Trzewnymi"}, {"id": "e", "text": "Przedkręgowymi"}]'::jsonb,
   'a',
   $E$Pień współczulny tworzą **zwoje przykręgowe** (paravertebralne) połączone gałęziami międzyzwojowymi, leżące po bokach kręgosłupa. Włókna przedzwojowe z rogów bocznych C8–L2/3 dochodzą gałęziami łączącymi białymi; po synapsie włókna pozazwojowe wracają gałęziami szarymi. **Zwoje przedkręgowe** (trzewne: trzewny, krezkowe) leżą przy aorcie i obsługują narządy jamy brzusznej. **Śródścienne** to zwoje przywspółczulne w ścianie narządów.$E$,
   'układ autonomiczny', 'ANATLEK-27'),
(25, 'ANA-NAC',
   'Jedyną gałęzią tętnicy szyjnej wewnętrznej mającą istotny udział w unaczynieniu części głowy innych niż mózgowie jest:',
   '[{"id": "a", "text": "Tętnica szyjna wewnętrzna unaczynia tylko część mózgową głowy"}, {"id": "b", "text": "Tętnica oczna"}, {"id": "c", "text": "Tętnica twarzowa"}, {"id": "d", "text": "Tętnica łącząca przednia"}, {"id": "e", "text": "Tętnica językowa"}]'::jsonb,
   'b',
   $E$**T. oczna** (a. ophthalmica) — pierwsza większa gałąź **t. szyjnej wewnętrznej** po wyjściu z zatoki jamistej — zaopatruje oczodół, gałkę oczną i przez gałęzie (nadoczodołowa, grzbietowa nosa, nadbloczkowa) skórę okolicy czołowej i nosa. Tworzy istotne zespolenia z układem **t. szyjnej zewnętrznej** (t. twarzowa, skroniowa powierzchowna). Pozostałe odgałęzienia ICA (mózgowa przednia, środkowa, łącząca tylna) zaopatrują mózgowie.$E$,
   'tętnica szyjna wewnętrzna', 'ANATLEK-28'),
(26, 'ANA-TRZ',
   'Gałęziami aorty wstępującej są:',
   '[{"id": "a", "text": "Tętnica podobojczykowa prawa, tętnica szyjna wspólna prawa"}, {"id": "b", "text": "Pień ramienno-głowowy, tętnica szyjna wspólna lewa, tętnica podobojczykowa lewa"}, {"id": "c", "text": "Gałęzie międzyżebrowe, gałęzie oskrzelowe, gałęzie przełykowe"}, {"id": "d", "text": "Gałęzie śródpiersiowe, gałęzie przeponowe"}, {"id": "e", "text": "Tętnice wieńcowe"}]'::jsonb,
   'e',
   $E$Jedynymi gałęziami **aorty wstępującej** są **tt. wieńcowe** (prawa i lewa), odchodzące z zatok aortalnych tuż nad zastawką aortalną. Z **łuku aorty** odchodzą pień ramienno-głowowy, lewa t. szyjna wspólna i lewa t. podobojczykowa (odp. B). Gałęzie międzyżebrowe, oskrzelowe i przełykowe pochodzą z **aorty piersiowej** (zstępującej) — odp. C. Wieńcowe napełniają się głównie w **rozkurczu**.$E$,
   'aorta i jej gałęzie', 'ANATLEK-29'),
(27, 'ANA-OBW',
   'Ile par nerwów szyjnych łączy się obustronnie z rdzeniem kręgowym?',
   '[{"id": "a", "text": "10 par"}, {"id": "b", "text": "14 par"}, {"id": "c", "text": "6 par"}, {"id": "d", "text": "8 par"}, {"id": "e", "text": "12 par"}]'::jsonb,
   'd',
   $E$Istnieje **8 par nerwów rdzeniowych szyjnych** (C1–C8), mimo że kręgów szyjnych jest 7. Pierwsze 7 par wychodzi **nad** odpowiednim kręgiem, nerw C8 — **między** C7 a Th1 (poniżej C7). Od Th1 w dół każdy nerw wychodzi pod kręgiem o tym samym numerze. Łącznie 31 par nerwów rdzeniowych: 8 szyjnych, 12 piersiowych, 5 lędźwiowych, 5 krzyżowych, 1 guziczny.$E$,
   'nerwy rdzeniowe', 'ANATLEK-30'),
(28, 'ANA-TRZ',
   'Jakie części żołądka są miejscem przyczepu sieci otrzewnej?',
   '[{"id": "a", "text": "Wpust i odźwiernik"}, {"id": "b", "text": "Powierzchnia wątrobowa i powierzchnia przeponowa"}, {"id": "c", "text": "Kolano i wcięcie wpustowe"}, {"id": "d", "text": "Krzywizny"}, {"id": "e", "text": "Fałdy i pólka żołądkowe"}]'::jsonb,
   'd',
   $E$Fałdy otrzewnej (sieci i więzadła) przyczepiają się do żołądka wzdłuż jego **krzywizn**. Do **krzywizny mniejszej** — sieć mniejsza (lig. wątrobowo-żołądkowe); do **krzywizny większej** — sieć większa (lig. żołądkowo-okrężnicze), lig. żołądkowo-śledzionowe i żołądkowo-przeponowe. Między blaszkami sieci biegną naczynia żołądkowe (krzywizny mniejszej i większej). Powierzchnie przednia i tylna pokryte są otrzewną trzewną gładko.$E$,
   'żołądek i otrzewna', 'ANATLEK-31'),
(29, 'ANA-KON',
   'Na przedramieniu mięśnie prostowniki znajdują się w komorze/komorach:',
   '[{"id": "a", "text": "Tylnej"}, {"id": "b", "text": "Przedniej i bocznej"}, {"id": "c", "text": "Przedniej"}, {"id": "d", "text": "Tylnej i bocznej"}, {"id": "e", "text": "Bocznej"}]'::jsonb,
   'd',
   $E$Mięśnie prostowniki (grupa tylna i boczna) leżą w **przedziale tylnym i bocznym** przedramienia, unerwione przez n. promieniowy (gałąź głęboka / n. międzykostny tylny). Grupa boczna to m.in. ramienno-promieniowy i prostowniki promieniowe nadgarstka. Przedział przedni mieści zginacze i nawracacze (n. pośrodkowy i łokciowy). Podział na komory wyznaczają przegrody międzymięśniowe i błona międzykostna.$E$,
   'przedramię — przedziały', 'ANATLEK-32'),
(30, 'ANA-NAC',
   'Wspólnym przyczepem końcowym mięśni zwieraczy gardła jest:',
   '[{"id": "a", "text": "Zwężenie gardłowo-przełykowe"}, {"id": "b", "text": "Guzek gardłowy"}, {"id": "c", "text": "Wejście do krtani"}, {"id": "d", "text": "Szew gardłowy"}, {"id": "e", "text": "Fałd gardłowy"}]'::jsonb,
   'd',
   $E$Trzy mięśnie zwieracze gardła (górny, środkowy, dolny) zbiegają się na tylnej ścianie w pośrodkowym **szwie gardłowym** (raphe pharyngis), który u góry przyczepia się do **guzka gardłowego** kości potylicznej. Mięśnie układają się dachówkowato (dolny pokrywa środkowy, środkowy górny). Unerwienie: splot gardłowy (IX, X). Skurcz przesuwa kęs podczas połykania. Między częścią poprzeczną i skośną m. dolnego — trójkąt Killiana (uchyłek Zenkera).$E$,
   'gardło', 'ANATLEK-34'),
(31, 'ANA-JAM',
   'Przestrzeń przygardłowa jest ograniczona przyśrodkowo przez:',
   '[{"id": "a", "text": "Mięsień rylcowo-gardłowy"}, {"id": "b", "text": "Mięsień skrzydłowy przyśrodkowy i gałąź żuchwy"}, {"id": "c", "text": "Boczną ścianę gardła"}, {"id": "d", "text": "Blaszkę przedkręgową powięzi szyjnej"}, {"id": "e", "text": "Skrzydło większe kości klinowej"}]'::jsonb,
   'c',
   $E$Przestrzeń przygardłowa (spatium parapharyngeum) od **strony przyśrodkowej** ograniczona jest **boczną ścianą gardła** (powięź gardłowo-podstawna, m. zwieracz górny). **Bocznie** leży m. skrzydłowy przyśrodkowy i gałąź żuchwy oraz ślinianka przyuszna, **z tyłu** blaszka przedkręgowa. Przestrzeń ma kształt odwróconej piramidy, dzieli się wyrostkiem rylcowatym na część przednią i tylną (z ICA, IX–XII). Droga szerzenia ropni okołomigdałkowych.$E$,
   'przestrzeń przygardłowa', 'ANATLEK-35'),
(32, 'ANA-TRZ',
   'Najgłębszym zachyłkiem jamy opłucnej jest zachyłek:',
   '[{"id": "a", "text": "Śródpiersiowo-przeponowy"}, {"id": "b", "text": "Żebrowo-przeponowy"}, {"id": "c", "text": "Żebrowo-śródpiersiowy tylny"}, {"id": "d", "text": "Żebrowo-sercowy"}, {"id": "e", "text": "Żebrowo-śródpiersiowy przedni"}]'::jsonb,
   'b',
   $E$**Zachyłek żebrowo-przeponowy** (recessus costodiaphragmaticus) jest najgłębszy i klinicznie najważniejszy — to najniżej położona część jamy opłucnej, gdzie gromadzi się płyn wysiękowy/przesiękowy. Szczyt płuca nie wypełnia go nawet przy głębokim wdechu (rezerwa oddechowa). Miejsce nakłucia opłucnej (torakocenteza) — zwykle w linii pachowej tylnej, nad górnym brzegiem żebra (ochrona pęczka międzyżebrowego pod żebrem).$E$,
   'opłucna — zachyłki', 'ANATLEK-36'),
(33, 'ANA-OUN',
   'Do części robaka móżdżku nie należy:',
   '[{"id": "a", "text": "Liść"}, {"id": "b", "text": "Piramida"}, {"id": "c", "text": "Czopek"}, {"id": "d", "text": "Kłaczek"}, {"id": "e", "text": "Grudka"}]'::jsonb,
   'd',
   $E$**Kłaczek** (flocculus) należy do półkuli móżdżku i wraz z **grudką** robaka tworzy płat **kłaczkowo-grudkowy** (archicerebellum, ośrodek równowagi). Do samego **robaka** należą m.in.: języczek, płacik środkowy, szczyt, **liść**, guzek, **piramida**, **czopek** i grudka. Kłaczek jest parzystym wypustem półkuli, nie elementem robaka. Płat kłaczkowo-grudkowy łączy się z układem przedsionkowym (vestibulocerebellum).$E$,
   'móżdżek', 'ANATLEK-37'),
(34, 'ANA-TRZ',
   'Zatoka wieńcowa uchodzi do:',
   '[{"id": "a", "text": "lewej komory"}, {"id": "b", "text": "prawej komory"}, {"id": "c", "text": "lewego przedsionka"}, {"id": "d", "text": "żyły głównej dolnej"}, {"id": "e", "text": "prawego przedsionka"}]'::jsonb,
   'e',
   $E$**Zatoka wieńcowa** (sinus coronarius), zbierająca większość krwi żylnej serca, uchodzi do **prawego przedsionka** między ujściem ż. głównej dolnej a otworem przedsionkowo-komorowym prawym, częściowo przysłonięta **zastawką Tebezjusza**. Leży w bruździe wieńcowej na tylnej ścianie serca. Do niej spływają ż. sercowa wielka, średnia, mała i tylna lewej komory. Punkt orientacyjny w elektrofizjologii (cewnikowanie zatoki).$E$,
   'serce — żyły', 'ANATLEK-38'),
(35, 'ANA-TRZ',
   'Gałąź zaopatrująca jajnik od tętnicy macicznej biegnie w:',
   '[{"id": "a", "text": "Więzadle szerokim macicy"}, {"id": "b", "text": "Więzadle właściwym jajnika"}, {"id": "c", "text": "Krezce jajowodu"}, {"id": "d", "text": "Więzadle wieszadłowym jajnika"}, {"id": "e", "text": "Więzadle obłym macicy"}]'::jsonb,
   'b',
   $E$Gałąź jajnikowa (r. ovaricus) **t. macicznej** biegnie do jajnika w **więzadle właściwym jajnika** (lig. ovarii proprium), łączącym jajnik z trzonem macicy, i zespala się tam z t. jajnikową.$E$,
   'narządy płciowe żeńskie', 'ANATLEK-39'),
(36, 'ANA-TRZ',
   'Serce z zewnątrz pokryte jest:',
   '[{"id": "a", "text": "Dwiema blaszkami: blaszką ścienną i surowiczą"}, {"id": "b", "text": "Trzema blaszkami: surowiczą, trzewną osierdzia włóknistego i ścienną osierdzia włóknistego"}, {"id": "c", "text": "Dwiema blaszkami: osierdziem włóknistym i ściennym"}, {"id": "d", "text": "Dwiema blaszkami: blaszką trzewną i ścienną"}, {"id": "e", "text": "Trzema blaszkami: włóknistą, trzewną osierdzia surowiczego i ścienną osierdzia surowiczego"}]'::jsonb,
   'e',
   $E$Serce otacza osierdzie złożone z **osierdzia włóknistego** (worek z tkanki łącznej) oraz **osierdzia surowiczego** z dwiema blaszkami: **ścienną** (wyściela worek włóknisty od wewnątrz) i **trzewną** = nasierdzie (pokrywa serce). Między blaszkami surowiczymi jama osierdzia z płynem (~20–50 ml), umożliwiająca ślizganie. Zatoki osierdzia: poprzeczna i skośna. Nadmiar płynu → tamponada. Zatem trzy warstwy: włóknista + dwie surowicze.$E$,
   'osierdzie', 'ANATLEK-40'),
(37, 'ANA-KON',
   'Przyczep dystalny mięśnia trójgłowego ramienia znajduje się:',
   '[{"id": "a", "text": "Na wyrostku dziobiastym"}, {"id": "b", "text": "Na bloczku kości ramiennej"}, {"id": "c", "text": "Na wyrostku łokciowym"}, {"id": "d", "text": "Na wyrostku promieniowym"}, {"id": "e", "text": "Na błonie międzykostnej przedramienia"}]'::jsonb,
   'c',
   $E$M. trójgłowy ramienia (głowa długa, boczna, przyśrodkowa) wspólnym ścięgnem przyczepia się dystalnie do **wyrostka łokciowego** (olecranon) kości łokciowej — jest głównym prostownikiem stawu łokciowego. Głowa długa dodatkowo prostuje i przywodzi ramię. Unerwienie: n. promieniowy. **Wyrostek dziobiasty** to przyczep m. ramiennego/zginaczy; wyrostka "promieniowego" w anatomii nie ma (dystraktor). Odruch z m. trójgłowego: poziom C7.$E$,
   'mięsień trójgłowy ramienia', 'ANATLEK-43'),
(38, 'ANA-TRZ',
   'Która z wymienionych struktur anatomicznych nie znajduje się w śródpiersiu tylnym?',
   '[{"id": "a", "text": "grasica lub ciało tłuszczowe grasicze u dorosłych"}, {"id": "b", "text": "nerwy błędne"}, {"id": "c", "text": "aorta piersiowa"}, {"id": "d", "text": "żyła nieparzysta"}, {"id": "e", "text": "Przełyk"}]'::jsonb,
   'a',
   $E$**Grasica** (a u dorosłych ciało tłuszczowe grasicze) leży w **śródpiersiu przednim** (górnym), za mostkiem — nie w tylnym. Śródpiersie tylne zawiera: **przełyk**, **aortę piersiową zstępującą**, **ż. nieparzystą i nieparzystą krótką**, **n. błędne**, przewód piersiowy i pień współczulny. Granica: osierdzie/serce z przodu, kręgosłup z tyłu. Podział śródpiersia klinicznie ważny dla różnicowania guzów (np. grasiczak — przednie).$E$,
   'śródpiersie', 'ANATLEK-44'),
(39, 'ANA-OBW',
   'Nerw przeponowy, poza przeponą, unerwia:',
   '[{"id": "a", "text": "Otrzewną"}, {"id": "b", "text": "Osierdzie"}, {"id": "c", "text": "Opłucną, osierdzie, otrzewną"}, {"id": "d", "text": "Opłucną, osierdzie"}, {"id": "e", "text": "Opłucną"}]'::jsonb,
   'c',
   $E$**N. przeponowy** (C3–C5, "C3,4,5 keep the diaphragm alive") jest ruchowy dla przepony, ale niesie też **włókna czuciowe** dla: **opłucnej** śródpiersiowej i przeponowej, **osierdzia** (worek osierdziowy) oraz **otrzewnej** pokrywającej przeponę (oraz częściowo wątroby/pęcherzyka). Stąd ból przepony promieniuje do barku (dermatom C4 — objaw Kehra przy podrażnieniu podprzeponowym). Biegnie po m. pochyłym przednim, przez śródpiersie po osierdziu.$E$,
   'nerw przeponowy', 'ANATLEK-45'),
(40, 'ANA-KON',
   'Mięsień dźwigacz łopatki pociąga łopatkę do góry oraz:',
   '[{"id": "a", "text": "Przyśrodkowo"}, {"id": "b", "text": "Do tyłu"}, {"id": "c", "text": "Pociąga jedynie do góry"}, {"id": "d", "text": "Do boku"}, {"id": "e", "text": "Do przodu"}]'::jsonb,
   'a',
   $E$M. dźwigacz łopatki biegnie od wyrostków poprzecznych C1–C4 do **kąta górnego łopatki**, więc unosi łopatkę i pociąga jej kąt **przyśrodkowo** (oraz obraca panewkę ku dołowi). Współpracuje z m. czworobocznym (część górna) i mm. równoległobocznymi. Unerwienie: n. grzbietowy łopatki (C5) oraz gałęzie C3–C4. Przy ustalonej łopatce zgina szyję bocznie. Częste źródło bólu mięśniowo-powięziowego okolicy karku.$E$,
   'mięśnie obręczy barkowej', 'ANATLEK-46'),
(41, 'ANA-TRZ',
   'Tętnica mięśnia dźwigacza jądra, nasieniowód z tętnicą nasieniowodu, splot wiciowaty oraz tętnica jądrowa biegną:',
   '[{"id": "a", "text": "W powrózku nasiennym"}, {"id": "b", "text": "W przydance aorty brzusznej"}, {"id": "c", "text": "Wzdłuż moczowodu"}, {"id": "d", "text": "W ciele jamistym prącia"}, {"id": "e", "text": "W ciele gąbczastym prącia"}]'::jsonb,
   'a',
   $E$**Powrózek nasienny** (funiculus spermaticus) zawiera: **nasieniowód** z t. nasieniowodu, **t. jądrową** (od aorty), **t. m. dźwigacza jądra** (od t. nabrzusznej dolnej), **splot wiciowaty** (pampiniformis — chłodzi krew tętniczą, jego poszerzenie to żylaki powrózka), naczynia chłonne i gałąź płciową n. płciowo-udowego. Otoczony osłonkami pochodzącymi z warstw ściany brzucha. Biegnie przez kanał pachwinowy.$E$,
   'powrózek nasienny', 'ANATLEK-47'),
(42, 'ANA-NAC',
   'W skład pęczka naczyniowo-nerwowego szyi wchodzą:',
   '[{"id": "a", "text": "tętnica szyjna wspólna, żyła szyjna wewnętrzna, nerw błędny, korzeń górny pętli szyjnej"}, {"id": "b", "text": "tętnica i żyła szyjna wspólne, nerw błędny, korzeń górny pętli szyjnej"}, {"id": "c", "text": "tętnica szyjna wspólna, żyła szyjna zewnętrzna, nerw błędny, korzeń dolny pętli szyjnej"}, {"id": "d", "text": "tętnica szyjna zewnętrzna, żyła szyjna wewnętrzna, nerw błędny, korzeń górny pętli szyjnej"}, {"id": "e", "text": "tętnica szyjna wewnętrzna, żyła szyjna zewnętrzna, nerw przeponowy, korzeń górny pętli szyjnej"}]'::jsonb,
   'a',
   $E$Pęczek naczyniowo-nerwowy szyi, otoczony **pochewką naczyń szyjnych** (vagina carotica), zawiera: **t. szyjną wspólną** (przyśrodkowo), **ż. szyjną wewnętrzną** (bocznie), **n. błędny X** (w tylnym zachyłku między nimi) oraz **korzeń górny pętli szyjnej** na powierzchni przedniej. "Ż. szyjna wspólna" nie istnieje (dystraktor B). Zawartość biegnie od podstawy czaszki do otworu górnego klatki — kluczowa topografia chirurgii szyi.$E$,
   'pęczek naczyniowo-nerwowy szyi', 'ANATLEK-48'),
(43, 'ANA-CZA',
   'Zatoka czołowa uchodzi do:',
   '[{"id": "a", "text": "części nosowej gardła"}, {"id": "b", "text": "przewodu nosowego dolnego"}, {"id": "c", "text": "przewodu nosowego górnego"}, {"id": "d", "text": "przewodu nosowego środkowego"}, {"id": "e", "text": "przedsionka jamy nosowej"}]'::jsonb,
   'd',
   $E$**Zatoka czołowa** uchodzi do **przewodu nosowego środkowego** przez lejek sitowy (infundibulum ethmoidale)/przewód nosowo-czołowy. Do przewodu środkowego otwierają się też: zatoka szczękowa (rozwór półksiężycowaty), komórki sitowe przednie i środkowe. Do **przewodu górnego** — komórki sitowe tylne; zatoka **klinowa** — do zachyłka klinowo-sitowego. Do **przewodu dolnego** — przewód nosowo-łzowy (jedyny niezwiązany z zatokami).$E$,
   'zatoki przynosowe', 'ANATLEK-49'),
(44, 'ANA-NAC',
   'Jedynym rozwieraczem szpary głośni jest:',
   '[{"id": "a", "text": "Mięsień przedsionkowy"}, {"id": "b", "text": "Mięsień głosowy"}, {"id": "c", "text": "Mięsień tarczowo-nalewkowy"}, {"id": "d", "text": "Mięsień pierścienno-nalewkowy tylny"}, {"id": "e", "text": "Mięsień pierścienno-tarczowy"}]'::jsonb,
   'd',
   $E$**M. pierścienno-nalewkowy tylny** (posticus) jest **jedynym** mięśniem rozwierającym (abdukcja) szparę głośni — odwraca wyrostki głosowe nalewek na zewnątrz. Jego porażenie (obustronne uszkodzenie n. krtaniowego wstecznego) grozi **dusznością** (struny w pozycji przyśrodkowej). Pozostałe mm. wewnętrzne zwierają głośnię lub napinają struny (m. pierścienno-tarczowy — jedyny unerwiony przez n. krtaniowy górny, napina). Mnemonik: "Posticus — please open!".$E$,
   'krtań — mięśnie', 'ANATLEK-50'),
(45, 'ANA-TRZ',
   'Z jakich części składa się przegroda międzykomorowa?',
   '[{"id": "a", "text": "Błoniasta i mięśniowa"}, {"id": "b", "text": "Prawa i lewa"}, {"id": "c", "text": "Mięśniowa gładka i mięśniowa poprzecznie prążkowana"}, {"id": "d", "text": "Trzewna i ścienna"}, {"id": "e", "text": "Surowicza i włóknista"}]'::jsonb,
   'a',
   $E$Przegroda międzykomorowa ma część **błoniastą** (niewielka, górna, przy płatku przegrodowym zastawki trójdzielnej) i **mięśniową** (większość). Część błoniasta to najczęstsze miejsce **ubytków przegrody komorowej (VSD)**. Przez część błoniastą/szczyt mięśniowej biegnie pęczek Hisa — uszkodzenie grozi blokiem. Cała przegroda zbudowana z mięśnia sercowego (kardiomiocyty), część błoniasta z tkanki włóknistej szkieletu serca.$E$,
   'serce — przegrody', 'ANATLEK-51'),
(46, 'ANA-MIE',
   'Cofanie żuchwy w stawie skroniowo-żuchwowym wywołują:',
   '[{"id": "a", "text": "Mm. skrzydłowe przyśrodkowe"}, {"id": "b", "text": "Mm. podgnykowe"}, {"id": "c", "text": "Poziome włókna mm. skroniowych"}, {"id": "d", "text": "Mm. żwacze"}, {"id": "e", "text": "Mm. skrzydłowe boczne"}]'::jsonb,
   'c',
   $E$Cofanie (retrakcję) żuchwy wywołują głównie **tylne, poziomo przebiegające włókna m. skroniowego**, wspomagane przez m. dwubrzuścowy i mm. nadgnykowe. **M. skrzydłowy boczny** (E) działa odwrotnie — wysuwa żuchwę (protrakcja) i opuszcza, ciągnąc krążek i głowę żuchwy do przodu. Mm. żwacz i skrzydłowy przyśrodkowy unoszą żuchwę (zwarcie). Unerwienie mięśni żucia: n. żuchwowy V3.$E$,
   'staw skroniowo-żuchwowy', 'ANATLEK-52'),
(47, 'ANA-CZA',
   'Której ściany nie posiada jama nosowa?',
   '[{"id": "a", "text": "Przyśrodkowej"}, {"id": "b", "text": "Bocznej"}, {"id": "c", "text": "Tylnej"}, {"id": "d", "text": "Dolnej"}, {"id": "e", "text": "Górnej"}]'::jsonb,
   'c',
   $E$Jama nosowa nie ma zamkniętej **ściany tylnej** — ku tyłowi otwiera się **nozdrzami tylnymi (choanae)** do części nosowej gardła. Posiada: ścianę **górną** (kości nosowe, blaszka sitowa, trzon klinowej), **dolną** (podniebienie twarde), **przyśrodkową** (przegroda nosa) i **boczną** (z małżowinami i przewodami nosowymi, ujścia zatok). Brak ściany tylnej zapewnia ciągłość drogi oddechowej z gardłem.$E$,
   'jama nosowa', 'ANATLEK-54'),
(48, 'ANA-OUN',
   'Włókna drogi korowo-jądrowej przechodzą przez:',
   '[{"id": "a", "text": "odnogę przednią torebki wewnętrznej"}, {"id": "b", "text": "płat ciała modzelowatego"}, {"id": "c", "text": "promienistość wzgórza"}, {"id": "d", "text": "odnogę tylną torebki wewnętrznej"}, {"id": "e", "text": "kolano torebki wewnętrznej"}]'::jsonb,
   'e',
   $E$Droga korowo-jądrowa (korowo-opuszkowa), unerwiająca jądra ruchowe nerwów czaszkowych, biegnie przez **kolano torebki wewnętrznej** (genu capsulae internae). Droga **korowo-rdzeniowa** zajmuje **odnogę tylną** (z somatotopowym ułożeniem). Odnogę przednią tworzą drogi czołowo-mostowe i wypustki promieniste przednie. Zawał w okolicy kolana/odnogi tylnej daje niedowład połowiczy. Torebka leży między jądrem soczewkowatym a wzgórzem/jądrem ogoniastym.$E$,
   'torebka wewnętrzna', 'ANATLEK-55'),
(49, 'ANA-TRZ',
   'Tętnicy międzykomorowej przedniej towarzyszy:',
   '[{"id": "a", "text": "Żyła sercowa wielka"}, {"id": "b", "text": "Żyła sercowa średnia"}, {"id": "c", "text": "Żyła tylna komory lewej"}, {"id": "d", "text": "Żyły i tętnice serca nie mają wspólnego przebiegu"}, {"id": "e", "text": "Żyła skośna przedsionka lewego"}]'::jsonb,
   'a',
   $E$**T. międzykomorowa przednia** (gałąź zstępująca przednia, LAD — od t. wieńcowej lewej) biegnie w bruździe międzykomorowej przedniej wraz z **ż. sercową wielką**. **Ż. sercowa średnia** towarzyszy t. międzykomorowej tylnej w bruździe tylnej. Wielka żyła uchodzi do zatoki wieńcowej. LAD zaopatruje przednią ścianę lewej komory i przegrodę — jej zamknięcie ("widow-maker") daje rozległy zawał ściany przedniej.$E$,
   'serce — naczynia', 'ANATLEK-56'),
(50, 'ANA-OUN',
   'Podłużne bruzdy rdzenia kręgowego zaznaczają podział powierzchni rdzenia kręgowego na:',
   '[{"id": "a", "text": "6 sznurów"}, {"id": "b", "text": "3 sznury"}, {"id": "c", "text": "4 sznury"}, {"id": "d", "text": "5 sznurów"}, {"id": "e", "text": "7 sznurów"}]'::jsonb,
   'a',
   $E$Bruzdy podłużne dzielą powierzchnię rdzenia na **6 sznurów** (parzyście, po 3 z każdej strony): **przedni**, **boczny** i **tylny**. Wyznaczają je: szczelina pośrodkowa przednia, bruzda pośrodkowa tylna oraz bruzdy boczne przednia i tylna (miejsca wejścia/wyjścia korzeni). Sznury zawierają drogi nerwowe: tylny — czucie głębokie (smukły, klinowaty), boczny i przedni — drogi ruchowe i czuciowe (np. korowo-rdzeniowa, rdzeniowo-wzgórzowa).$E$,
   'rdzeń kręgowy', 'ANATLEK-57'),
(51, 'ANA-KON',
   'Wspólną głowę początkową ze wspólnym przyczepem początkowym posiadają:',
   '[{"id": "a", "text": "Głowy mięśnia dwugłowego ramienia"}, {"id": "b", "text": "Mięsień półbłoniasty i mięsień półścięgnisty"}, {"id": "c", "text": "Mięśnie kłębu"}, {"id": "d", "text": "Mięśnie składowe mięśnia trójgłowego łydki"}, {"id": "e", "text": "Mięśnie grupy I (powierzchownej) zginaczy przedramienia"}]'::jsonb,
   'e',
   $E$Powierzchowna warstwa zginaczy przedramienia (nawrotny obły, zginacz promieniowy nadgarstka, dłoniowy długi, zginacz łokciowy nadgarstka — głowa ramienna) odchodzi wspólnym ścięgnem (**caput commune**) od **nadkłykcia przyśrodkowego** kości ramiennej. Przeciążenie tego przyczepu to "łokieć golfisty" (epicondylitis medialis). Analogicznie prostowniki mają wspólny przyczep na nadkłykciu bocznym ("łokieć tenisisty"). Unerwienie zginaczy: głównie n. pośrodkowy (FCU — łokciowy).$E$,
   'zginacze przedramienia', 'ANATLEK-59'),
(52, 'ANA-KON',
   'Gałęziami końcowymi tętnicy ramiennej są tętnice:',
   '[{"id": "a", "text": "Piersiowa górna i piersiowa boczna"}, {"id": "b", "text": "Wszystkie odpowiedzi prawidłowe"}, {"id": "c", "text": "Okalająca ramię przednia i okalająca ramię tylna"}, {"id": "d", "text": "Promieniowa i łokciowa"}, {"id": "e", "text": "Okalająca łopatki i piersiowo-grzbietowa"}]'::jsonb,
   'd',
   $E$**T. ramienna** w dole łokciowym (na wysokości szyjki kości promieniowej) dzieli się na gałęzie końcowe: **t. promieniową i t. łokciową**. Po drodze oddaje t. głęboką ramienia (biegnie z n. promieniowym w bruździe nerwu promieniowego) oraz tt. poboczne łokciowe. Miejsce pomiaru ciśnienia (osłuchiwanie w dole łokciowym, przyśrodkowo od ścięgna m. dwugłowego). Tt. okalające ramię odchodzą od t. pachowej, nie ramiennej.$E$,
   'tętnica ramienna', 'ANATLEK-60'),
(53, 'ANA-TUL',
   'Do dróg odpływu chłonki z sutka zaliczamy:',
   '[{"id": "a", "text": "drogę pachową oraz drogę międzyżebrową przednią i tylną"}, {"id": "b", "text": "drogę międzyżebrową przednią i tylną"}, {"id": "c", "text": "wszystkie odpowiedzi prawidłowe"}, {"id": "d", "text": "drogę międzymięśniową"}, {"id": "e", "text": "drogę pachową"}]'::jsonb,
   'c',
   $E$Chłonka z sutka odpływa kilkoma drogami: **pachową** (główna, ~75% — do węzłów pachowych), **piersiową wewnętrzną/przymostkową** (przez przestrzenie międzyżebrowe do węzłów wzdłuż t. piersiowej wewnętrznej), oraz **międzymięśniową** (Rottera, między mm. piersiowymi). Istnieją też połączenia do strony przeciwnej i ku dołowi (do węzłów podprzeponowych). Znajomość dróg kluczowa w onkologii sutka (przerzuty, węzeł wartowniczy).$E$,
   'sutek — chłonka', 'ANATLEK-61'),
(54, 'ANA-CZA',
   'Zjawisko akomodacji zachodzi głównie dzięki:',
   '[{"id": "a", "text": "Tęczówce"}, {"id": "b", "text": "Soczewce"}, {"id": "c", "text": "Ciału szklistemu"}, {"id": "d", "text": "Twardówce"}, {"id": "e", "text": "Rogówce"}]'::jsonb,
   'b',
   $E$Akomodacja (nastawność oka do widzenia z bliska) zachodzi dzięki zmianie kształtu **soczewki**. Skurcz **m. rzęskowego** (przywspółczulny, n. III) rozluźnia obwódkę rzęskową (więzadełka Zinna), soczewka uwypukla się i zwiększa moc łamiącą. Z wiekiem traci elastyczność → **prezbiopia** (starczowzroczność). **Rogówka** ma stałą, największą moc łamiącą oka, ale nie zmienia jej. Triada akomodacyjna: zwężenie źrenicy, zbieżność, uwypuklenie soczewki.$E$,
   'gałka oczna', 'ANATLEK-62'),
(55, 'ANA-OBW',
   'Splot ramienny powstaje zwykle z gałęzi następujących nerwów:',
   '[{"id": "a", "text": "Th3 – Th12"}, {"id": "b", "text": "C8 – Th3"}, {"id": "c", "text": "C6 – Th7"}, {"id": "d", "text": "C4 – C8"}, {"id": "e", "text": "C5 – Th1"}]'::jsonb,
   'e',
   $E$Splot ramienny tworzą gałęzie brzuszne nerwów rdzeniowych **C5–Th1**. Korzenie łączą się w pnie: górny (C5–C6), środkowy (C7), dolny (C8–Th1); każdy dzieli się na część przednią i tylną, tworząc pęczki (boczny, przyśrodkowy, tylny) wokół t. pachowej. Uszkodzenie górnego pnia — porażenie Erba ("kelnerska ręka"), dolnego — porażenie Klumpkego (ręka szponiasta). Z pęczków odchodzą nerwy: pośrodkowy, łokciowy, promieniowy, mięśniowo-skórny, pachowy.$E$,
   'splot ramienny', 'ANATLEK-63'),
(56, 'ANA-TRZ',
   'Do gałęzi ściennych tętnicy biodrowej wewnętrznej nie należy:',
   '[{"id": "a", "text": "Tętnica pośladkowa górna"}, {"id": "b", "text": "Tętnica biodrowo-lędźwiowa"}, {"id": "c", "text": "Tętnica zasłonowa"}, {"id": "d", "text": "Tętnica udowa powierzchowna"}, {"id": "e", "text": "Tętnica pośladkowa dolna"}]'::jsonb,
   'd',
   $E$**T. udowa powierzchowna** w ogóle nie odchodzi od t. biodrowej wewnętrznej — jest częścią układu t. udowej (od biodrowej zewnętrznej), a "powierzchowna/głęboka" to nazewnictwo kliniczne (anatomicznie t. udowa i głęboka uda). Gałęzie **ścienne** t. biodrowej wewnętrznej: biodrowo-lędźwiowa, krzyżowe boczne, zasłonowa, pośladkowa górna i dolna. Gałęzie **trzewne**: pęcherzowe, maciczna, odbytnicza środkowa, sromowa wewnętrzna.$E$,
   'tętnica biodrowa wewnętrzna', 'ANATLEK-65'),
(57, 'ANA-NER',
   'Mięsień rylcowo-gardłowy unerwia:',
   '[{"id": "a", "text": "Nerw XII"}, {"id": "b", "text": "Nerw szczękowy"}, {"id": "c", "text": "Nerw IX"}, {"id": "d", "text": "Nerw żuchwowy"}, {"id": "e", "text": "Nerw twarzowy"}]'::jsonb,
   'c',
   $E$**M. rylcowo-gardłowy** (stylopharyngeus) jest jedynym mięśniem unerwianym ruchowo przez **n. językowo-gardłowy (IX)**. Unosi gardło i krtań podczas połykania i mowy. Pozostałe mięśnie gardła (zwieracze, podniebienno-gardłowy) zaopatruje splot gardłowy z **n. błędnego (X)**. Mm. rylcowo-językowy unerwia XII, rylcowo-gnykowy — VII. N. IX odpowiada też za czucie/smak tylnej 1/3 języka i część odruchu gardłowego (ramię aferentne).$E$,
   'nerw językowo-gardłowy', 'ANATLEK-66'),
(58, 'ANA-TRZ',
   'Strukturami ograniczającymi krążenie czynnościowe płuc w rozwoju płodowym są:',
   '[{"id": "a", "text": "Przewód tętniczy i przewód żylny"}, {"id": "b", "text": "Przewód tętniczy i otwór owalny"}, {"id": "c", "text": "Przewód żylny"}, {"id": "d", "text": "Przewód tętniczy"}, {"id": "e", "text": "Otwór owalny"}]'::jsonb,
   'b',
   $E$W życiu płodowym płuca są nieczynne oddechowo (duży opór naczyń płucnych), więc krew omija krążenie płucne dwoma drogami: **otworem owalnym** (z prawego do lewego przedsionka) i **przewodem tętniczym** Botalla (z pnia płucnego do aorty). Po urodzeniu rozprężenie płuc obniża opór, otwór owalny zamyka się czynnościowo (→ dół owalny), a przewód tętniczy → więzadło tętnicze. **Przewód żylny** (Arancjusza) omija wątrobę, nie płuca.$E$,
   'krążenie płodowe', 'ANATLEK-67'),
(59, 'ANA-OUN',
   'Drugi neuron drogi czucia interoceptywnego tworzą komórki znajdujące się w:',
   '[{"id": "a", "text": "Głowie rogu tylnego rdzenia kręgowego"}, {"id": "b", "text": "Oliwkach rdzenia przedłużonego"}, {"id": "c", "text": "Piramidach rdzenia przedłużonego"}, {"id": "d", "text": "Istocie szarej wokół kanału środkowego rdzenia kręgowego"}, {"id": "e", "text": "Jądrze smukłym bądź jądrze klinowatym"}]'::jsonb,
   'd',
   $E$W drodze czucia **interoceptywnego** (z trzewi) drugi neuron leży w **istocie szarej wokół kanału środkowego** rdzenia (okolica blaszki X / jądra pośrednio-przyśrodkowego). Pierwszy neuron — w zwoju rdzeniowym. Drogi trzewno-czuciowe biegną rozproszone, częściowo ze sznurami tylnymi i drogą rdzeniowo-wzgórzową. **Jądra smukłe/klinowate** to drugi neuron czucia **eksteroceptywnego/proprioceptywnego** sznurów tylnych, nie trzewnego.$E$,
   'drogi czuciowe', 'ANATLEK-68'),
(60, 'ANA-TRZ',
   'W topografii płuc i opłucnej różnica w lokalizacji obu struktur (granic dolnych), jeśli chodzi o odległość między nimi, wynosi zwykle:',
   '[{"id": "a", "text": "1 mm"}, {"id": "b", "text": "10 cm"}, {"id": "c", "text": "Jedno międzyżebrze (ok. dwa żebra)"}, {"id": "d", "text": "Szerokość mostka"}, {"id": "e", "text": "0,5 cm"}]'::jsonb,
   'c',
   $E$Dolna granica **opłucnej** leży zwykle o **ok. dwa żebra (jedno–dwa międzyżebrza) niżej** niż dolna granica **płuca**, tworząc zachyłek żebrowo-przeponowy (rezerwa oddechowa). Orientacyjnie: w linii środkowo-obojczykowej granica płuca na VI żebrze, opłucnej na VIII; w linii pachowej środkowej — VIII i X; w linii łopatkowej — X i XII. Ta różnica to przestrzeń, w którą rozpręża się płuco przy wdechu.$E$,
   'topografia płuc i opłucnej', 'ANATLEK-69'),
(61, 'ANA-TUL',
   'Pęczek naczyniowo-nerwowy przestrzeni międzyżebrowej zawiera, w kolejności od żebra (od góry):',
   '[{"id": "a", "text": "tętnicę, żyłę i nerw międzyżebrowe"}, {"id": "b", "text": "żyłę, nerw i tętnicę międzyżebrowe"}, {"id": "c", "text": "nerw, żyłę i tętnicę międzyżebrowe"}, {"id": "d", "text": "żyłę, tętnicę i nerw międzyżebrowe"}, {"id": "e", "text": "tętnicę międzyżebrową, żyły towarzyszące i nerw międzyżebrowy"}]'::jsonb,
   'd',
   $E$W bruździe żebra (pod dolnym brzegiem żebra wyższego) pęczek układa się od góry: **żyła, tętnica, nerw** (mnemonik **VAN** — Vein, Artery, Nerve). Stąd nakłucia opłucnej wykonuje się **nad górnym brzegiem żebra niższego**, by ominąć pęczek biegnący pod żebrem. Tętnice międzyżebrowe tylne odchodzą od aorty piersiowej, przednie — od t. piersiowej wewnętrznej. Nerw to gałąź przednia nerwu rdzeniowego piersiowego.$E$,
   'przestrzeń międzyżebrowa', 'ANATLEK-70'),
(62, 'ANA-KON',
   'Ruchy możliwe do wykonania w stawie kolanowym to:',
   '[{"id": "a", "text": "Zginanie i prostowanie"}, {"id": "b", "text": "Przywodzenie i odwodzenie"}, {"id": "c", "text": "Zginanie i prostowanie oraz obrót do wewnątrz i na zewnątrz"}, {"id": "d", "text": "Obrót do wewnątrz i na zewnątrz"}, {"id": "e", "text": "Zginanie i prostowanie oraz przywodzenie i odwodzenie"}]'::jsonb,
   'c',
   $E$Staw kolanowy (zawiasowo-obrotowy, kłykciowy) umożliwia **zginanie i prostowanie** oraz — przy zgiętym kolanie — **rotację (obrót do wewnątrz i na zewnątrz)**. W pełnym wyproście rotacja jest zablokowana ("zaryglowanie" stawu, terminal rotation — niewielka rotacja zewnętrzna piszczeli). Stabilizują go więzadła krzyżowe (przednie/tylne) i poboczne (piszczelowe/strzałkowe) oraz łąkotki. Przywodzenie/odwodzenie w prawidłowym kolanie nie występuje (patologiczne — uszkodzenie więzadeł pobocznych).$E$,
   'staw kolanowy', 'ANATLEK-71'),
(63, 'ANA-OUN',
   'Rdzeń kręgowy u człowieka kończy się zwykle na wysokości:',
   '[{"id": "a", "text": "L5"}, {"id": "b", "text": "L1/2"}, {"id": "c", "text": "Co1"}, {"id": "d", "text": "S1"}, {"id": "e", "text": "Th12"}]'::jsonb,
   'b',
   $E$Rdzeń kręgowy u dorosłego kończy się stożkiem rdzeniowym na wysokości **L1/L2** (u noworodka niżej, ~L3, z powodu szybszego wzrostu kręgosłupa). Poniżej biegną korzenie nerwowe tworzące **ogon koński** (cauda equina). Dlatego **punkcję lędźwiową** wykonuje się bezpiecznie poniżej L2 (zwykle L3–L4 lub L4–L5, na linii Tuffiera między grzebieniami biodrowymi). Stożek przedłuża się w nić końcową kotwiczącą rdzeń.$E$,
   'rdzeń kręgowy', 'ANATLEK-72'),
(64, 'ANA-TRZ',
   'W której części tchawicy występuje głównie błona, bez części chrzęstnych?',
   '[{"id": "a", "text": "Przedniej"}, {"id": "b", "text": "Górnej"}, {"id": "c", "text": "Tylnej"}, {"id": "d", "text": "Dolnej"}, {"id": "e", "text": "Bocznych"}]'::jsonb,
   'c',
   $E$Chrząstki tchawicze mają kształt **podkowy otwartej ku tyłowi** — **ściana tylna** jest błoniasta (paries membranaceus), zbudowana z tkanki łącznej i **mięśnia tchawiczego** (gładkiego). Ta budowa pozwala na rozszerzanie się sąsiadującego od tyłu **przełyku** przy połykaniu oraz na zwężanie światła tchawicy (np. przy kaszlu). Przednia i boczne ściany są wzmocnione chrząstkami szklistymi zapobiegającymi zapadaniu dróg oddechowych.$E$,
   'tchawica', 'ANATLEK-74'),
(65, 'ANA-TRZ',
   'Miejscem zejścia się bruzd międzykomorowych jest:',
   '[{"id": "a", "text": "Wcięcie koniuszka serca"}, {"id": "b", "text": "Bruzda graniczna"}, {"id": "c", "text": "Uszko lewe"}, {"id": "d", "text": "Bruzda wieńcowa"}, {"id": "e", "text": "Korzeń aorty"}]'::jsonb,
   'a',
   $E$Bruzdy międzykomorowe przednia i tylna spotykają się w okolicy koniuszka serca, w **wcięciu koniuszka serca** (incisura apicis cordis), na prawo od samego koniuszka. Koniuszek tworzy niemal w całości **lewa komora**. Bruzdy międzykomorowe odpowiadają położeniu przegrody międzykomorowej i biegnącym w nich naczyniom (LAD + ż. sercowa wielka z przodu; t. międzykomorowa tylna + ż. średnia z tyłu). Bruzda wieńcowa oddziela przedsionki od komór.$E$,
   'serce — powierzchnia', 'ANATLEK-76'),
(66, 'ANA-MIE',
   'Jedynym mięśniem żucia zlokalizowanym zewnętrznie od żuchwy jest:',
   '[{"id": "a", "text": "M. żwacz"}, {"id": "b", "text": "M. skrzydłowy przyśrodkowy"}, {"id": "c", "text": "M. skroniowy"}, {"id": "d", "text": "Wszystkie mięśnie żucia są zlokalizowane zewnętrznie od żuchwy"}, {"id": "e", "text": "M. skrzydłowy boczny"}]'::jsonb,
   'a',
   $E$**M. żwacz** (masseter) leży **bocznie/zewnętrznie** od gałęzi żuchwy (od łuku jarzmowego do kąta i gałęzi żuchwy) — jest jedynym z czterech mięśni żucia położonym na zewnątrz. **Mm. skrzydłowe** (przyśrodkowy, boczny) leżą **przyśrodkowo** w dole podskroniowym; **m. skroniowy** przyczepia się do wyrostka dziobiastego od strony przyśrodkowej. Wszystkie unerwia n. żuchwowy (V3). Żwacz to najsilniejszy mięsień unoszący żuchwę.$E$,
   'mięśnie żucia', 'ANATLEK-78'),
(67, 'ANA-NER',
   'Nerw krtaniowy wsteczny prawy w klatce piersiowej przebiega:',
   '[{"id": "a", "text": "nie przebiega przez śródpiersie"}, {"id": "b", "text": "wzdłuż pnia współczulnego"}, {"id": "c", "text": "na przedniej ścianie tchawicy"}, {"id": "d", "text": "w śródpiersiu tylnym, wzdłuż więzadła podłużnego przedniego"}, {"id": "e", "text": "w bruździe pomiędzy przełykiem i tchawicą"}]'::jsonb,
   'e',
   $E$N. krtaniowy wsteczny **prawy** odchodzi od n. błędnego, owija się wokół **t. podobojczykowej prawej** (lewy — wokół łuku aorty) i wraca ku górze w **bruździe tchawiczo-przełykowej**, by unerwić mięśnie wewnętrzne krtani (poza pierścienno-tarczowym). Ze względu na asymetrię przebiegu prawy sięga niżej szyi, lewy wchodzi głębiej do klatki. Uszkodzenie (np. tarczyca, guzy śródpiersia) → chrypka, porażenie struny głosowej.$E$,
   'nerw krtaniowy wsteczny', 'ANATLEK-81'),
(68, 'ANA-KON',
   'Do pierścienia (stożka) rotatorów nie należy:',
   '[{"id": "a", "text": "Mięsień podgrzebieniowy"}, {"id": "b", "text": "Mięsień obły większy"}, {"id": "c", "text": "Mięsień podłopatkowy"}, {"id": "d", "text": "Mięsień obły mniejszy"}, {"id": "e", "text": "Mięsień nadgrzebieniowy"}]'::jsonb,
   'b',
   $E$Stożek rotatorów tworzą cztery mięśnie (mnemonik **SITS**): **S**upraspinatus (nadgrzebieniowy), **I**nfraspinatus (podgrzebieniowy), **T**eres minor (obły mniejszy), **S**ubscapularis (podłopatkowy). **M. obły większy** NIE należy do stożka — przyczepia się do grzebienia guzka mniejszego i jest przywodzicielem/rotatorem wewnętrznym (unerwiony przez n. podłopatkowy dolny). Najczęściej uszkadzany element stożka to ścięgno m. nadgrzebieniowego (zespół ciasnoty podbarkowej).$E$,
   'stożek rotatorów', 'ANATLEK-82'),
(69, 'ANA-NAC',
   'Tętnica podstawna biegnie w:',
   '[{"id": "a", "text": "Bruździe mostu"}, {"id": "b", "text": "Bruździe środkowej mózgu"}, {"id": "c", "text": "Szczelinie pierwszej móżdżku"}, {"id": "d", "text": "Skrzyżowaniu piramid rdzenia przedłużonego"}, {"id": "e", "text": "Skrzyżowaniu wzrokowym"}]'::jsonb,
   'a',
   $E$**T. podstawna** (a. basilaris) powstaje z połączenia dwóch **tt. kręgowych** na granicy mostu i rdzenia przedłużonego, biegnie w **bruździe podstawnej (bruździe mostu)** po jego brzusznej powierzchni, ku górze. Dzieli się na **tt. mózgu tylne** zasilające koło tętnicze Willisa. Oddaje gałęzie do mostu, móżdżku (AICA, t. móżdżku górna) i ucha wewnętrznego. Zakrzep → zespół zamknięcia (locked-in syndrome) przy rozległym uszkodzeniu mostu.$E$,
   'unaczynienie mózgowia', 'ANATLEK-83'),
(70, 'ANA-TRZ',
   'Do głównych dopływów tworzących żyłę wrotną należy:',
   '[{"id": "a", "text": "Żyła krezkowa dolna"}, {"id": "b", "text": "Żyła śledzionowa"}, {"id": "c", "text": "Żyła krezkowa dolna i żyła śledzionowa"}, {"id": "d", "text": "Wszystkie odpowiedzi prawidłowe"}, {"id": "e", "text": "Żyła krezkowa górna"}]'::jsonb,
   'd',
   $E$**Żyła wrotna** (v. portae) powstaje za szyją trzustki z połączenia **ż. śledzionowej i ż. krezkowej górnej**; **ż. krezkowa dolna** zwykle uchodzi do śledzionowej (lub do kąta zlania). Zbiera krew z całego przewodu pokarmowego (od dolnej dwunastnicy), śledziony, trzustki — prowadzi ją do wątroby. Nadciśnienie wrotne → krążenie oboczne (żylaki przełyku, "głowa Meduzy", hemoroidy) przez zespolenia wrotno-układowe.$E$,
   'żyła wrotna', 'ANATLEK-84'),
(71, 'ANA-TRZ',
   'Dwa główne spływy żył ciała to:',
   '[{"id": "a", "text": "Żyła brzuszna i żyła piersiowa"}, {"id": "b", "text": "Żyła ścienna i żyła trzewna"}, {"id": "c", "text": "Żyła sercowa i żyła obwodowa"}, {"id": "d", "text": "Żyła główna górna i żyła główna dolna"}, {"id": "e", "text": "Żyła główna prawa i żyła główna lewa"}]'::jsonb,
   'd',
   $E$Krew żylna z całego ciała spływa dwiema dużymi żyłami do **prawego przedsionka**: **ż. główna górna** (z głowy, szyi, kończyn górnych, klatki piersiowej — powstaje z połączenia żył ramienno-głowowych) i **ż. główna dolna** (z tułowia poniżej przepony i kończyn dolnych — powstaje z połączenia żył biodrowych wspólnych na ~L4/L5). Trzeci, mniejszy spływ to zatoka wieńcowa (z serca). Krew z układu wrotnego przechodzi najpierw przez wątrobę.$E$,
   'żyły główne', 'ANATLEK-85'),
(72, 'ANA-CZA',
   'Do przewodu nosowego górnego uchodzi/uchodzą:',
   '[{"id": "a", "text": "Komórki sitowe przednie"}, {"id": "b", "text": "Zatoka czołowa"}, {"id": "c", "text": "Przewód nosowo-łzowy"}, {"id": "d", "text": "Komórki sitowe tylne"}, {"id": "e", "text": "Zatoka szczękowa"}]'::jsonb,
   'd',
   $E$Do **przewodu nosowego górnego** uchodzą **komórki sitowe tylne**. Do **przewodu środkowego**: zatoka czołowa, szczękowa oraz komórki sitowe przednie i środkowe. Do **przewodu dolnego** — przewód nosowo-łzowy (jedyny niezwiązany z zatokami). Zatoka **klinowa** otwiera się do zachyłka klinowo-sitowego (powyżej małżowiny górnej). Reguła: im wyżej ujście, tym bardziej z tyłu położona zatoka/komórka.$E$,
   'jama nosowa — przewody', 'ANATLEK-88'),
(73, 'ANA-KON',
   'Która z części mięśnia naramiennego odpowiada za odwodzenie kończyny górnej w początkowym zakresie ruchu?',
   '[{"id": "a", "text": "Obojczykowa i grzebieniowa"}, {"id": "b", "text": "Obojczykowa"}, {"id": "c", "text": "Grzebieniowa"}, {"id": "d", "text": "Barkowa (akromialna/środkowa)"}, {"id": "e", "text": "Obojczykowa, barkowa i grzebieniowa"}]'::jsonb,
   'd',
   $E$**Część barkowa (środkowa, akromialna)** m. naramiennego jest głównym **odwodzicielem** ramienia (zakres ~15–90°). Pierwsze ~15° odwodzenia inicjuje m. nadgrzebieniowy. Część **obojczykowa (przednia)** zgina i rotuje do wewnątrz, część **grzebieniowa (tylna)** prostuje i rotuje na zewnątrz. M. naramienny unerwia **n. pachowy (C5–C6)** — uszkodzenie (np. zwichnięcie barku, złamanie szyjki k. ramiennej) upośledza odwodzenie i daje znieczulenie skóry nad mięśniem.$E$,
   'mięsień naramienny', 'ANATLEK-89'),
(74, 'ANA-KON',
   'Prawidłowy rozkład przybliżonego udziału kości w tworzeniu panewki stawu biodrowego przedstawia odpowiedź:',
   '[{"id": "a", "text": "2/5 k. ogonowa, 1/5 k. biodrowa, 1/5 k. łonowa, 1/5 k. kulszowa"}, {"id": "b", "text": "2/5 k. biodrowa, 2/5 k. kulszowa, 1/5 k. łonowa"}, {"id": "c", "text": "1/5 k. łonowa, 3/5 k. kulszowa, 1/5 k. biodrowa"}, {"id": "d", "text": "3/5 k. biodrowa, 1/5 k. kulszowa, 1/5 k. łonowa"}, {"id": "e", "text": "1/5 k. udowa, 1/5 k. łonowa, 1/5 k. kulszowa, 1/5 k. biodrowa, 1/5 k. krzyżowa"}]'::jsonb,
   'b',
   $E$Panewkę (acetabulum) tworzą trzy kości miednicze schodzące się w **chrząstce w kształcie litery Y**: w przybliżeniu **2/5 kość biodrowa, 2/5 kość kulszowa, 1/5 kość łonowa**. Kość kulszowa i biodrowa tworzą większą, obciążaną część stropu, łonowa — przyśrodkowo-przednią. Chrząstka Y kostnieje ~15.–16. r.ż. Kość udowa (głowa) nie buduje panewki — jest elementem stawowym wchodzącym do niej. Powierzchnię stawową stanowi powierzchnia księżycowata.$E$,
   'panewka stawu biodrowego', 'ANATLEK-90'),
(75, 'ANA-NER',
   'Pierwszy neuron nerwu węchowego znajduje się w:',
   '[{"id": "a", "text": "Blaszce sitowej kości sitowej"}, {"id": "b", "text": "Błonie śluzowej jamy nosowej"}, {"id": "c", "text": "Opuszce węchowej"}, {"id": "d", "text": "Hipokampie"}, {"id": "e", "text": "Korze gruszkowatej"}]'::jsonb,
   'b',
   $E$Pierwszy neuron drogi węchowej to **komórki węchowe dwubiegunowe** w **błonie śluzowej (nabłonku węchowym)** górnej części jamy nosowej — są jednocześnie receptorem i neuronem. Ich aksony (nici węchowe) przechodzą przez **blaszkę sitową** kości sitowej i tworzą synapsy w **opuszce węchowej** (drugi neuron — komórki mitralne). Złamanie blaszki sitowej → anosmia i ryzyko płynotoku nosowego. Węch to jedyny zmysł omijający wzgórze w drodze do kory.$E$,
   'nerw węchowy', 'ANATLEK-91'),
(76, 'ANA-OUN',
   'Sznur tylny rdzenia kręgowego składa się z:',
   '[{"id": "a", "text": "Rogów przednich i tylnych"}, {"id": "b", "text": "Oliwek"}, {"id": "c", "text": "Pęczka smukłego i klinowatego"}, {"id": "d", "text": "Rogów górnych i dolnych"}, {"id": "e", "text": "Pęczka tylnego i bocznego"}]'::jsonb,
   'c',
   $E$Sznur tylny tworzą dwa pęczki przewodzące **czucie głębokie (proprioceptywne), wibrację i dotyk różnicujący**: **pęczek smukły** (Golla, przyśrodkowy — z kończyny dolnej i dolnej części tułowia) i **pęczek klinowaty** (Burdacha, boczny — z kończyny górnej, powyżej Th6). Pojawiają się dopiero powyżej Th6 (klinowaty). Aksony kończą się w jądrach smukłym i klinowatym rdzenia przedłużonego. Uszkodzenie → utrata czucia głębokiego, ataksja czuciowa (objaw Romberga).$E$,
   'rdzeń kręgowy — sznury', 'ANATLEK-92'),
(77, 'ANA-OUN',
   'Drogi rdzeniowo-wzgórzowe przebiegają w:',
   '[{"id": "a", "text": "Przednim i bocznym sznurze rdzenia kręgowego"}, {"id": "b", "text": "Przednim i tylnym sznurze rdzenia kręgowego"}, {"id": "c", "text": "Tylnym sznurze rdzenia kręgowego"}, {"id": "d", "text": "Przednim, bocznym i tylnym sznurze rdzenia kręgowego"}, {"id": "e", "text": "Bocznym i tylnym sznurze rdzenia kręgowego"}]'::jsonb,
   'a',
   $E$Drogi rdzeniowo-wzgórzowe biegną w sznurze **przednim** (czucie dotyku i ucisku — droga przednia) i **bocznym** (ból i temperatura — droga boczna). Aksony drugiego neuronu **krzyżują się** w spoidle przednim rdzenia (1–2 segmenty wyżej) przed wstąpieniem. To tłumaczy rozszczepienne zaburzenia czucia (np. w jamistości rdzenia, zespole Browna-Séquarda — utrata bólu/temperatury po stronie przeciwnej poniżej uszkodzenia). Kończą się w jądrze VPL wzgórza.$E$,
   'drogi rdzeniowo-wzgórzowe', 'ANATLEK-93'),
(78, 'ANA-JAM',
   'Zwój nerwowy w trójkącie podżuchwowym tworzony jest przez nerw:',
   '[{"id": "a", "text": "Podjęzykowy"}, {"id": "b", "text": "Krtaniowy górny"}, {"id": "c", "text": "Krtaniowy dolny"}, {"id": "d", "text": "Językowy"}, {"id": "e", "text": "Żuchwowo-gnykowy"}]'::jsonb,
   'd',
   $E$W trójkącie podżuchwowym leży **zwój podżuchwowy** (ganglion submandibulare), zawieszony na **n. językowym** (V3). Włókna przywspółczulne przedzwojowe pochodzą jednak z **n. twarzowego (VII)** — przez strunę bębenkową dołączają do n. językowego i docierają do zwoju, gdzie przełączają się; włókna pozazwojowe unerwiają wydzielniczo ślinianki **podżuchwową i podjęzykową**. N. językowy jest więc "wieszadłem" zwoju i drogą dla włókien VII. Sam niesie czucie przednich 2/3 języka.$E$,
   'zwoje przywspółczulne głowy', 'ANATLEK-94'),
(79, 'ANA-TRZ',
   'Struktury mocujące płatki zastawek przedsionkowo-komorowych:',
   '[{"id": "a", "text": "Struny ścięgniste i obłączki"}, {"id": "b", "text": "Mięśnie brodawkowate"}, {"id": "c", "text": "Struny ścięgniste"}, {"id": "d", "text": "Obłączki"}, {"id": "e", "text": "Struny ścięgniste i mięśnie brodawkowate"}]'::jsonb,
   'e',
   $E$Płatki zastawek przedsionkowo-komorowych (trójdzielnej i dwudzielnej/mitralnej) mocują **struny ścięgniste** (chordae tendineae) przyczepione do **mięśni brodawkowatych** wystających ze ściany komór. Aparat ten zapobiega cofaniu (wynicowaniu) płatków do przedsionków w skurczu komory. Uszkodzenie (zawał m. brodawkowatego, zerwanie struny) → niedomykalność zastawki. Komora lewa ma 2 mm. brodawkowate, prawa zwykle 3.$E$,
   'zastawki serca', 'ANATLEK-95'),
(80, 'ANA-KON',
   'Rozcięgno mięśnia dwugłowego ramienia wzmacnia:',
   '[{"id": "a", "text": "Przegrodę międzymięśniową przyśrodkową ramienia"}, {"id": "b", "text": "Przegrodę międzymięśniową boczną ramienia"}, {"id": "c", "text": "Powięź łokciową (powięź przedramienia w dole łokciowym)"}, {"id": "d", "text": "Powrózek naczyniowo-nerwowy ramienia"}, {"id": "e", "text": "Torebkę stawu ramiennego"}]'::jsonb,
   'c',
   $E$**Rozcięgno m. dwugłowego ramienia** (aponeurosis bicipitalis, lacertus fibrosus) odchodzi od ścięgna mięśnia przyśrodkowo i wplata się w **powięź przedramienia (powięź łokciową)** po stronie zginaczy, wzmacniając ją. Chroni leżące pod nim t. ramienną i n. pośrodkowy w dole łokciowym (np. przy pobieraniu krwi/pomiarze ciśnienia). Ścięgno główne m. dwugłowego przyczepia się do guzowatości kości promieniowej (supinacja i zgięcie łokcia).$E$,
   'dół łokciowy', 'ANATLEK-96'),
(81, 'ANA-TRZ',
   'Najcieńszym elementem przegrody międzyprzedsionkowej jest:',
   '[{"id": "a", "text": "Cała przegroda międzyprzedsionkowa ma jednakową grubość"}, {"id": "b", "text": "Guzek międzyżylny"}, {"id": "c", "text": "Rąbek dołu owalnego"}, {"id": "d", "text": "Grzebień graniczny"}, {"id": "e", "text": "Zastawka dołu owalnego (dno dołu owalnego)"}]'::jsonb,
   'e',
   $E$Najcieńszym miejscem przegrody międzyprzedsionkowej jest **dno (zastawka) dołu owalnego** (fossa ovalis) — pozostałość po pierwotnej przegrodzie i otworze owalnym życia płodowego. Otacza je grubszy **rąbek dołu owalnego** (limbus). Przez tę okolicę wykonuje się **nakłucie przezprzegrodowe** w kardiologii inwazyjnej. U ~25% osób utrzymuje się **przetrwały otwór owalny (PFO)** — ryzyko zatorowości skrzyżowanej. Guzek międzyżylny i grzebień graniczny to inne struktury prawego przedsionka.$E$,
   'przegroda międzyprzedsionkowa', 'ANATLEK-97'),
(82, 'ANA-TRZ',
   'Która z odpowiedzi prawidłowo wymienia elementy składowe szkieletu włóknistego serca?',
   '[{"id": "a", "text": "3 pierścienie włókniste, 2 trójkąty wieńcowe, węzeł Aschoffa-Tawary"}, {"id": "b", "text": "2 trójkąty włókniste, 4 pierścienie włókniste, część błoniasta przegrody międzykomorowej"}, {"id": "c", "text": "1 trójkąt włóknisty, 2 pierścienie włókniste, przegroda międzykomorowa"}, {"id": "d", "text": "1 trójkąt wieńcowy, nici ścięgniste, przegroda międzyprzedsionkowa"}, {"id": "e", "text": "Przegroda międzyprzedsionkowa, przegroda międzykomorowa, pierścienie włókniste"}]'::jsonb,
   'b',
   $E$Szkielet włóknisty serca tworzą: **4 pierścienie włókniste** (wokół ujść: aortalnego, pnia płucnego, przedsionkowo-komorowych prawego i lewego), **2 trójkąty włókniste** (prawy i lewy) oraz **błoniasta część przegrody międzykomorowej**. Stanowi rusztowanie dla zastawek i przyczep mięśniówki, **elektrycznie izoluje** przedsionki od komór (jedyne połączenie — pęczek Hisa przez trójkąt prawy). Zbudowany z tkanki łącznej zbitej, czasem zwapniały u starszych.$E$,
   'szkielet serca', 'ANATLEK-98'),
(83, 'ANA-JAM',
   'W skład splotu zębowego górnego wchodzą:',
   '[{"id": "a", "text": "Gałęzie zębodołowe"}, {"id": "b", "text": "Gałęzie zębodołowe splotowe"}, {"id": "c", "text": "Gałęzie zębodołowe górne tylne, przednie i środkowe"}, {"id": "d", "text": "Brak poprawnej odpowiedzi"}, {"id": "e", "text": "Gałęzie zębodołowe górne"}]'::jsonb,
   'c',
   $E$Splot zębowy górny tworzą **gałęzie zębodołowe górne tylne, środkowe i przednie** — odgałęzienia **n. szczękowego (V2)**. Gałęzie tylne odchodzą w dole skrzydłowo-podniebiennym, środkowa i przednie w kanale podoczodołowym. Splot zaopatruje czuciowo zęby górne, dziąsła i część zatoki szczękowej. Analogicznie zęby dolne unerwia n. zębodołowy dolny (V3) przez splot zębowy dolny. Znajomość kluczowa w znieczuleniu stomatologicznym.$E$,
   'unerwienie zębów', 'ANATLEK-101'),
(84, 'ANA-CZA',
   'Do przewodu nosowego dolnego uchodzi:',
   '[{"id": "a", "text": "Przednia grupa komórek sitowych"}, {"id": "b", "text": "Tylna grupa komórek sitowych"}, {"id": "c", "text": "Przewód nosowo-łzowy"}, {"id": "d", "text": "Zatoka czołowa"}, {"id": "e", "text": "Zatoka szczękowa"}]'::jsonb,
   'c',
   $E$Do **przewodu nosowego dolnego** uchodzi **przewód nosowo-łzowy** (canalis nasolacrimalis) — odprowadza łzy z worka łzowego do jamy nosowej, dlatego przy płaczu pojawia się katar. Ujście jest częściowo przysłonięte fałdem (zastawka Hasnera). Pozostałe struktury (zatoka czołowa, szczękowa, komórki sitowe przednie/środkowe) uchodzą do przewodu środkowego, komórki sitowe tylne do górnego. Niedrożność przewodu u noworodków → zapalenie woreczka łzowego.$E$,
   'jama nosowa — przewody', 'ANATLEK-102'),
(85, 'ANA-TRZ',
   'Rzut koniuszka serca znajduje się:',
   '[{"id": "a", "text": "w czwartej przestrzeni międzyżebrowej lewej w linii przymostkowej"}, {"id": "b", "text": "w piątej przestrzeni międzyżebrowej lewej, pomiędzy linią przymostkową a środkowo-obojczykową"}, {"id": "c", "text": "w czwartej przestrzeni międzyżebrowej lewej w linii środkowo-obojczykowej"}, {"id": "d", "text": "w piątej przestrzeni międzyżebrowej lewej w linii przymostkowej"}, {"id": "e", "text": "w trzeciej przestrzeni międzyżebrowej lewej w linii przymostkowej"}]'::jsonb,
   'b',
   $E$Koniuszek serca rzutuje się na **V lewą przestrzeń międzyżebrową**, nieco przyśrodkowo od linii środkowo-obojczykowej (pomiędzy nią a przymostkową), ~7–9 cm od linii pośrodkowej. Tu bada się **uderzenie koniuszkowe** (ictus cordis) i osłuchuje zastawkę **dwudzielną (mitralną)**. Przesunięcie uderzenia w lewo i ku dołowi sugeruje powiększenie lewej komory. Koniuszek tworzy głównie lewa komora.$E$,
   'serce — topografia', 'ANATLEK-103'),
(86, 'ANA-NER',
   'Zwój uszny:',
   '[{"id": "a", "text": "Jest zwojem współczulnym"}, {"id": "b", "text": "Posiada korzeń współczulny prowadzony przez nerw skalisty większy"}, {"id": "c", "text": "Posiada korzeń przywspółczulny prowadzony przez nerw skalisty mniejszy"}, {"id": "d", "text": "Leży w dole skrzydłowo-podniebiennym"}, {"id": "e", "text": "Posiada korzeń czuciowy prowadzony przez strunę bębenkową"}]'::jsonb,
   'c',
   $E$**Zwój uszny** (ganglion oticum) to zwój **przywspółczulny** leżący pod otworem owalnym, przy n. żuchwowym (V3). Korzeń przywspółczulny stanowi **n. skalisty mniejszy** — włókna z jądra ślinowego dolnego (**n. IX**). Po synapsie włókna pozazwojowe biegną z **n. uszno-skroniowym** (V3) do **ślinianki przyusznej** (wydzielanie śliny). **N. skalisty większy** (VII) prowadzi włókna do zwoju skrzydłowo-podniebiennego, nie usznego.$E$,
   'zwoje przywspółczulne głowy', 'ANATLEK-104'),
(87, 'ANA-KON',
   'Staw Lisfranca to:',
   '[{"id": "a", "text": "Staw skokowo-goleniowy"}, {"id": "b", "text": "Staw stępowo-śródstopny"}, {"id": "c", "text": "Staw skokowo-piętowo-łódkowy"}, {"id": "d", "text": "Staw poprzeczny stępu"}, {"id": "e", "text": "Staw skokowo-piętowy"}]'::jsonb,
   'b',
   $E$**Staw Lisfranca** to **staw stępowo-śródstopny** (articulationes tarsometatarsales) — między kośćmi klinowatymi i sześcienną a podstawami kości śródstopia. Linia stawu jest miejscem **amputacji Lisfranca** i typowych złamań-zwichnięć (uraz Lisfranca). **Staw poprzeczny stępu (Choparta)** = skokowo-łódkowy + piętowo-sześcienny (linia amputacji Choparta). Rozróżnienie obu linii istotne w chirurgii stopy i urazach sportowych (np. upadek na zgiętą podeszwowo stopę).$E$,
   'stawy stopy', 'ANATLEK-105'),
(88, 'ANA-NER',
   'Nerw szczękowy:',
   '[{"id": "a", "text": "Zaopatruje górną powiekę czuciowo"}, {"id": "b", "text": "Prowadzi włókna czuciowe do zatoki czołowej"}, {"id": "c", "text": "Oddaje nerwy skrzydłowo-podniebienne"}, {"id": "d", "text": "Prowadzi włókna ruchowe do mięśni podniebienia"}, {"id": "e", "text": "Wychodzi z czaszki przez otwór owalny"}]'::jsonb,
   'c',
   $E$**N. szczękowy (V2)** wychodzi z czaszki przez **otwór okrągły** (nie owalny — tym wychodzi V3), wnika do dołu skrzydłowo-podniebiennego i oddaje **nerwy skrzydłowo-podniebienne** (łączące go ze zwojem skrzydłowo-podniebiennym). Jest **wyłącznie czuciowy**: zaopatruje środkowe piętro twarzy — **dolną powiekę**, policzek, wargę górną, zatokę szczękową, podniebienie, zęby górne. Górną powiekę i zatokę czołową unerwia V1 (oczny). Mięśnie podniebienia — głównie n. błędny (X), nie V2.$E$,
   'nerw szczękowy V2', 'ANATLEK-106'),
(89, 'ANA-TRZ',
   'Zatoka poprzeczna osierdzia:',
   '[{"id": "a", "text": "znajduje się pomiędzy żyłami płucnymi lewymi a żyłą główną dolną i żyłami płucnymi prawymi"}, {"id": "b", "text": "znajduje się pomiędzy dużymi tętnicami (aortą i pniem płucnym) a przednią ścianą przedsionków"}, {"id": "c", "text": "jest to miejsce, gdzie wpadają żyły serca"}, {"id": "d", "text": "jest nadrzędnym stymulatorem układu bodźcowo-przewodzącego"}, {"id": "e", "text": "znajduje się w śródpiersiu tylnym"}]'::jsonb,
   'b',
   $E$**Zatoka poprzeczna osierdzia** (sinus transversus) to przestrzeń w jamie osierdzia **za dużymi tętnicami** (aorta, pień płucny) a **przed przedsionkami** i żyłami (główną górną, płucnymi). Powstaje z zagięcia osierdzia surowiczego między odprowadzeniem tętniczym a żylnym. W kardiochirurgii umożliwia założenie podwiązki/zacisku wokół naczyń tętniczych. **Zatoka skośna** leży za lewym przedsionkiem (między żyłami płucnymi a ż. główną dolną) — odp. A opisuje skośną.$E$,
   'osierdzie — zatoki', 'ANATLEK-107'),
(90, 'ANA-TUL',
   'Najpóźniej zrastająca się nasada kości długiej występuje w:',
   '[{"id": "a", "text": "Kości piszczelowej"}, {"id": "b", "text": "Kości łokciowej"}, {"id": "c", "text": "Kości ramiennej"}, {"id": "d", "text": "Kości udowej"}, {"id": "e", "text": "Obojczyku"}]'::jsonb,
   'e',
   $E$**Obojczyk** kostnieje najwcześniej (pierwsza kość rozpoczynająca kostnienie w życiu płodowym, ~5.–6. tydzień), ale jego **przymostkowa nasada zrasta się najpóźniej** — nawet do ~25. roku życia. Dlatego u młodych dorosłych nasada mostkowa obojczyka bywa wykorzystywana w **ocenie wieku kostnego**. Obojczyk jest też jedyną długą kością powstającą głównie na drodze kostnienia **śródbłoniastego** (część przynasadowa — chrzęstnego).$E$,
   'kostnienie', 'ANATLEK-108'),
(91, 'ANA-KON',
   'Staw promieniowo-nadgarstkowy jest stawem:',
   '[{"id": "a", "text": "bloczkowym"}, {"id": "b", "text": "eliptycznym (kłykciowym)"}, {"id": "c", "text": "nieregularnym"}, {"id": "d", "text": "kulistym"}, {"id": "e", "text": "obrotowym"}]'::jsonb,
   'b',
   $E$**Staw promieniowo-nadgarstkowy** (radiocarpalis) jest stawem **eliptycznym (kłykciowym)** — między powierzchnią stawową kości promieniowej i krążkiem stawowym a pierwszym szeregiem kości nadgarstka (łódeczkowata, księżycowata, trójgraniasta; grochowata leży poza nim). Umożliwia ruchy w **dwóch osiach**: zginanie/prostowanie oraz odwodzenie/przywodzenie (ruch okrężny). Kość łokciowa nie wchodzi bezpośrednio w skład stawu (oddziela ją krążek stawowy).$E$,
   'staw nadgarstkowy', 'ANATLEK-109'),
(92, 'ANA-TRZ',
   'Śródpiersie tylne zlokalizowane jest pomiędzy:',
   '[{"id": "a", "text": "Osierdziem a odcinkiem piersiowym kręgosłupa"}, {"id": "b", "text": "Mostkiem a osierdziem"}, {"id": "c", "text": "Powierzchnią przednią a tylną osierdzia"}, {"id": "d", "text": "Otworem górnym klatki piersiowej a tchawicą"}, {"id": "e", "text": "Otworem dolnym klatki piersiowej a koniuszkiem serca"}]'::jsonb,
   'a',
   $E$**Śródpiersie tylne** leży między tylną ścianą **osierdzia** (z przodu) a **piersiowym odcinkiem kręgosłupa** (z tyłu), poniżej płaszczyzny przez kąt mostka. Zawiera: przełyk, aortę piersiową zstępującą, ż. nieparzystą i nieparzystą krótką, przewód piersiowy, n. błędne, pień współczulny. **Śródpiersie przednie** to wąska przestrzeń mostek–osierdzie (odp. B). Podział: górne i dolne (przednie, środkowe z sercem, tylne).$E$,
   'śródpiersie', 'ANATLEK-110'),
(93, 'ANA-NAC',
   'Do przodu od małżowiny usznej nie przebiega/nie przebiegają:',
   '[{"id": "a", "text": "Nerw potyliczny trzeci"}, {"id": "b", "text": "Nerw jarzmowo-twarzowy"}, {"id": "c", "text": "Gałęzie nerwu VII"}, {"id": "d", "text": "Nerw uszno-skroniowy"}, {"id": "e", "text": "Gałęzie tętnicy skroniowej powierzchownej"}]'::jsonb,
   'a',
   $E$**N. potyliczny trzeci** (z gałęzi grzbietowej C3) unerwia skórę **karku/potylicy** — biegnie z tyłu, nie do przodu od małżowiny. Do przodu od ucha przebiegają: **n. uszno-skroniowy** (V3, czucie + włókna do ślinianki), **gałęzie n. twarzowego (VII)** do mm. mimicznych, **t. skroniowa powierzchowna** (tętno przed skrawkiem) oraz n. jarzmowo-twarzowy (V2). Okolica zauszna i potyliczna należy do n. usznego wielkiego (splot szyjny) i potylicznych.$E$,
   'okolica ucha', 'ANATLEK-112'),
(94, 'ANA-TRZ',
   'W płucu lewym szczelina skośna oddziela od siebie płaty:',
   '[{"id": "a", "text": "Górny i dolny"}, {"id": "b", "text": "Dolny i środkowy"}, {"id": "c", "text": "Górny i najwyższy"}, {"id": "d", "text": "Górny i środkowy"}, {"id": "e", "text": "W płucu lewym brak szczeliny skośnej"}]'::jsonb,
   'a',
   $E$Płuco **lewe** ma tylko **dwa płaty** (górny i dolny) oddzielone jedną **szczeliną skośną** — brak płata środkowego (jego odpowiednikiem jest **języczek** płata górnego). Płuco **prawe** ma trzy płaty: szczelina skośna oddziela dolny, a szczelina pozioma wydziela płat środkowy. Asymetria wynika z położenia serca (wcięcie sercowe po lewej). Liczba płatów: lewe 2, prawe 3; segmenty oskrzelowo-płucne ~10 (lewe 8–10).$E$,
   'płuca — płaty', 'ANATLEK-113'),
(95, 'ANA-OUN',
   'Włókna przedzwojowe układu współczulnego odchodzą od następujących segmentów rdzenia kręgowego:',
   '[{"id": "a", "text": "C5 – Th1"}, {"id": "b", "text": "C8 – L2"}, {"id": "c", "text": "Th12 – L5"}, {"id": "d", "text": "C1 – Co"}, {"id": "e", "text": "C1 – C4"}]'::jsonb,
   'b',
   $E$Włókna przedzwojowe współczulne wychodzą z **jądra pośrednio-bocznego** (rogi boczne) rdzenia w segmentach **C8/Th1 – L2/L3** (część piersiowo-lędźwiowa układu autonomicznego). Opuszczają rdzeń korzeniami brzusznymi i **gałęziami łączącymi białymi** docierają do pnia współczulnego. Przywspółczulna część jest **czaszkowo-krzyżowa** (jądra nn. III, VII, IX, X oraz S2–S4). Stąd "współczulny = piersiowo-lędźwiowy, przywspółczulny = czaszkowo-krzyżowy".$E$,
   'układ współczulny', 'ANATLEK-114'),
(96, 'ANA-KON',
   'Na guzie piętowym znajduje się przyczep końcowy mięśnia:',
   '[{"id": "a", "text": "Trójgłowego łydki"}, {"id": "b", "text": "Strzałkowego trzeciego"}, {"id": "c", "text": "Piszczelowego tylnego"}, {"id": "d", "text": "Zginacza długiego palców"}, {"id": "e", "text": "Zginacza długiego palucha"}]'::jsonb,
   'a',
   $E$**M. trójgłowy łydki** (brzuchaty + płaszczkowaty) przyczepia się ścięgnem **piętowym (Achillesa)** do **guza piętowego** — to najsilniejsze ścięgno ciała. Mięsień zgina podeszwowo stopę (odbicie przy chodzie, bieg, wspięcie na palce); unerwia n. piszczelowy (S1–S2). Zerwanie ścięgna Achillesa → niemożność wspięcia na palce, objaw Thompsona. Pozostałe wymienione mięśnie przyczepiają się do kości stępu/śródstopia i paliczków, nie do guza piętowego.$E$,
   'mięśnie podudzia', 'ANATLEK-115'),
(97, 'ANA-TRZ',
   'W śródpiersiu górnym tchawica i przełyk od strony prawej krzyżowane są przez:',
   '[{"id": "a", "text": "Żyłę główną górną"}, {"id": "b", "text": "Nerw przeponowy"}, {"id": "c", "text": "Żyłę nieparzystą"}, {"id": "d", "text": "Łuk aorty"}, {"id": "e", "text": "Nerw błędny"}]'::jsonb,
   'c',
   $E$**Ż. nieparzysta** (v. azygos) w śródpiersiu górnym łukowato wygina się od strony **prawej** ponad prawym oskrzelem głównym i uchodzi do ż. głównej górnej, krzyżując po prawej tchawicę/przełyk. Po stronie **lewej** analogiczne krzyżowanie tworzy **łuk aorty**. Ż. nieparzysta zbiera krew z żył międzyżebrowych i jest ważnym połączeniem obocznym między układem ż. głównej górnej i dolnej (przy niedrożności ż. głównej).$E$,
   'śródpiersie górne', 'ANATLEK-116'),
(98, 'ANA-NAC',
   'Kora powierzchni przyśrodkowej kresomózgowia jest unaczyniana przez tętnice mózgu:',
   '[{"id": "a", "text": "środkową i tylną"}, {"id": "b", "text": "wyłącznie środkową"}, {"id": "c", "text": "przednią i tylną"}, {"id": "d", "text": "wyłącznie przednią"}, {"id": "e", "text": "przednią i środkową"}]'::jsonb,
   'c',
   $E$Powierzchnię **przyśrodkową** półkuli zaopatrują **t. mózgu przednia** (część przednia — płat czołowy i ciemieniowy przyśrodkowo, w tym płacik okołośrodkowy) i **t. mózgu tylna** (część tylna — płat potyliczny z korą wzrokową wokół bruzdy ostrogowej). Powierzchnię **boczną** (w tym pole Broki, Wernickego, większość ruchowej i czuciowej) zaopatruje **t. mózgu środkowa**. Stąd zawał ACA → niedowład kończyny dolnej, ACP → niedowidzenie połowicze.$E$,
   'unaczynienie mózgowia', 'ANATLEK-117'),
(99, 'ANA-TUL',
   'Podstawowym kierunkiem odpływu chłonki z sutka jest kierunek:',
   '[{"id": "a", "text": "Śródpiersiowy"}, {"id": "b", "text": "Oskrzelowo-wnękowy"}, {"id": "c", "text": "Mostkowy"}, {"id": "d", "text": "Grasiczy"}, {"id": "e", "text": "Pachowy"}]'::jsonb,
   'e',
   $E$Główną (~75%) drogą odpływu chłonki z sutka jest kierunek **pachowy** — do węzłów chłonnych pachowych (piersiowych/Sorgiusa, następnie centralnych i szczytowych). Pozostała chłonka spływa drogą **przymostkową** (do węzłów piersiowych wewnętrznych) i międzymięśniową. Dominacja drogi pachowej ma kluczowe znaczenie w **raku piersi** (ocena węzła wartowniczego, limfadenektomia pachowa, ryzyko obrzęku chłonnego kończyny po zabiegu).$E$,
   'sutek — chłonka', 'ANATLEK-118'),
(100, 'ANA-NAC',
   'Tętnica piersiowa wewnętrzna najczęściej odchodzi od:',
   '[{"id": "a", "text": "Tętnicy szyjnej wspólnej"}, {"id": "b", "text": "Aorty"}, {"id": "c", "text": "Tętnicy międzyżebrowej najwyższej"}, {"id": "d", "text": "Tętnicy kręgowej"}, {"id": "e", "text": "Tętnicy podobojczykowej"}]'::jsonb,
   'e',
   $E$**T. piersiowa wewnętrzna** (a. thoracica interna/mammaria) odchodzi od dolnej powierzchni **t. podobojczykowej**, biegnie pionowo za chrząstkami żebrowymi ~1 cm od brzegu mostka, oddając gałęzie międzyżebrowe przednie i przeszywające. Dzieli się na t. nabrzuszną górną i mięśniowo-przeponową. Jest złotym standardem **pomostowania aortalno-wieńcowego (LIMA-LAD)** dzięki trwałości przeszczepu. Inne gałęzie t. podobojczykowej: kręgowa, pień tarczowo-szyjny, żebrowo-szyjny.$E$,
   'tętnica podobojczykowa', 'ANATLEK-119'),
(101, 'ANA-TRZ',
   'Nozdrza przednie są ograniczone przez:',
   '[{"id": "a", "text": "chrząstki nosa boczne"}, {"id": "b", "text": "groblę nosa i bruzdę węchową"}, {"id": "c", "text": "skrzydła nosa i część błoniastą przegrody"}, {"id": "d", "text": "uwypuklenie ściany bocznej, zwane progiem nosa"}, {"id": "e", "text": "wszystkie chrząstki nosa"}]'::jsonb,
   'c',
   $E$**Nozdrza przednie** (nares) to parzyste otwory wejściowe do jamy nosowej, ograniczone od boku przez **skrzydła nosa** (zawierające chrząstki skrzydłowe większe), a przyśrodkowo przez **część błoniastą przegrody nosa** (ruchoma, łącząca koniuszek z wargą górną). Próg nosa (limen nasi) to uwypuklenie na granicy przedsionka i jamy właściwej — nie ogranicza nozdrzy. Grobla i bruzda węchowa leżą głęboko w jamie nosowej.$E$,
   'jama nosowa', 'ANATLEK-121'),
(102, 'ANA-NER',
   'Który z poniższych nerwów nie należy do części ruchowej nerwu trójdzielnego (V)?',
   '[{"id": "a", "text": "Nerw skrzydłowy boczny"}, {"id": "b", "text": "Nerw żwaczowy"}, {"id": "c", "text": "Nerw skrzydłowy przyśrodkowy"}, {"id": "d", "text": "Nerwy skroniowe głębokie"}, {"id": "e", "text": "Nerw policzkowy"}]'::jsonb,
   'e',
   $E$Część ruchowa **V** biegnie z gałęzią żuchwową (V3) i unerwia mięśnie żucia: **żwacz** (n. żwaczowy), **skroniowy** (nn. skroniowe głębokie), oba **skrzydłowe** (boczny i przyśrodkowy), a także żuchwowo-gnykowy, przedni brzusiec dwubrzuścowego, napinacz podniebienia i bębenka. **Nerw policzkowy** (V3) jest wyłącznie **czuciowy** — zaopatruje skórę i błonę śluzową policzka, nie unerwia ruchowo mięśnia policzkowego (ten od VII).$E$,
   'nerw trójdzielny', 'ANATLEK-122'),
(103, 'ANA-TUL',
   'W rozwoju płodowym zastawka żyły głównej dolnej kieruje krew na:',
   '[{"id": "a", "text": "Ścianę tylną przedsionka"}, {"id": "b", "text": "Ujście przedsionkowo-komorowe prawe"}, {"id": "c", "text": "Ujście żyły głównej górnej"}, {"id": "d", "text": "Otwór owalny"}, {"id": "e", "text": "Ujście zatoki wieńcowej"}]'::jsonb,
   'd',
   $E$**Zastawka żyły głównej dolnej** (zastawka Eustachiusza) w życiu płodowym kieruje natlenowaną krew z łożyska przez **otwór owalny** wprost do przedsionka lewego, omijając krążenie płucne. To kluczowy element przecieku prawo-lewego płodu. Po urodzeniu zanika lub pozostaje jako szczątkowy fałd. U dorosłego otwór owalny zarasta, tworząc **dół owalny** w przegrodzie międzyprzedsionkowej.$E$,
   'krążenie płodowe', 'ANATLEK-123'),
(104, 'ANA-KON',
   'Ścięgno końcowe mięśnia piersiowego mniejszego przyczepia się do:',
   '[{"id": "a", "text": "Grzebienia guzka większego"}, {"id": "b", "text": "Wyrostka barkowego"}, {"id": "c", "text": "Grzebienia guzka mniejszego"}, {"id": "d", "text": "Guzowatości naramiennej"}, {"id": "e", "text": "Wyrostka kruczego"}]'::jsonb,
   'e',
   $E$**Mięsień piersiowy mniejszy** biegnie od żeber III–V do **wyrostka kruczego** łopatki (processus coracoideus). Obniża i przesuwa łopatkę do przodu i w dół, a przy ustalonej łopatce jest mięśniem wdechowym pomocniczym. Wyrostek kruczy jest też przyczepem m. kruczo-ramiennego i głowy krótkiej dwugłowego ramienia. Grzebienie guzków i guzowatość naramienna leżą na kości ramiennej — to przyczepy innych mięśni.$E$,
   'mięśnie obręczy barkowej', 'ANATLEK-124'),
(105, 'ANA-TUL',
   'Zastawka mitralna składa się z płatków:',
   '[{"id": "a", "text": "Lewego, prawego i przedniego"}, {"id": "b", "text": "Przedniego, przegrodowego i tylnego"}, {"id": "c", "text": "Górnego, środkowego i dolnego"}, {"id": "d", "text": "Lewego, prawego i tylnego"}, {"id": "e", "text": "Przedniego i tylnego"}]'::jsonb,
   'e',
   $E$**Zastawka mitralna** (dwudzielna), między przedsionkiem a komorą lewą, ma **dwa płatki**: **przedni** (aortalny, większy) i **tylny**. Stąd nazwa „mitralna" — przypomina mitrę biskupią. Płatki łączą się ze strunami ścięgnistymi i mięśniami brodawkowatymi. Trójpłatkowa jest zastawka trójdzielna (prawa: przedni, tylny, przegrodowy — opcja B). Zapamiętaj: **M**itralna = **M**niej płatków (2), bo „2 litery i" w słowie.$E$,
   'zastawki serca', 'ANATLEK-126'),
(106, 'ANA-TRZ',
   'Pozostałością po płodowym przewodzie Arancjusza (przewód żylny) jest u dorosłego:',
   '[{"id": "a", "text": "Więzadło żylne"}, {"id": "b", "text": "Więzadło tętnicze"}, {"id": "c", "text": "Więzadło obłe wątroby"}, {"id": "d", "text": "Struny tętnicze"}, {"id": "e", "text": "Dół owalny"}]'::jsonb,
   'a',
   $E$**Przewód żylny** (Arancjusza) płodu omijał wątrobę, prowadząc krew z żyły pępkowej wprost do żyły głównej dolnej; po urodzeniu zarasta w **więzadło żylne** (ligamentum venosum). Inne pozostałości: żyła pępkowa → **więzadło obłe wątroby** (C), przewód tętniczy Botalla → **więzadło tętnicze** (B), otwór owalny → **dół owalny** (E). Nie mylić obłego (po żyle pępkowej) z żylnym (po przewodzie żylnym).$E$,
   'pozostałości krążenia płodowego', 'ANATLEK-127'),
(107, 'ANA-KON',
   'Która odpowiedź prawidłowo łączy część mięśnia naramiennego z jej przyczepem początkowym?',
   '[{"id": "a", "text": "Część przednia – grzebień łopatki"}, {"id": "b", "text": "Część tylna – wyrostek barkowy"}, {"id": "c", "text": "Część środkowa – grzebień łopatki"}, {"id": "d", "text": "Część środkowa – obojczyk"}, {"id": "e", "text": "Część przednia – obojczyk"}]'::jsonb,
   'e',
   $E$**Mięsień naramienny** ma trzy części wg przyczepu początkowego: **przednia (obojczykowa)** — boczna część **obojczyka**; **środkowa (barkowa)** — **wyrostek barkowy**; **tylna (grzebieniowa)** — **grzebień łopatki**. Wszystkie zbiegają się na **guzowatości naramiennej** kości ramiennej. Część środkowa odwodzi ramię, przednia zgina i przywodzi przyśrodkowo, tylna prostuje. Poprawne łączenie daje tylko opcja E (przednia–obojczyk).$E$,
   'mięsień naramienny', 'ANATLEK-128'),
(108, 'ANA-OUN',
   'Korowy ośrodek czucia dla zębów i dziąseł znajduje się w:',
   '[{"id": "a", "text": "tylnej części płacika okołośrodkowego"}, {"id": "b", "text": "przedniej części płacika okołośrodkowego"}, {"id": "c", "text": "dolnej części zakrętu zaśrodkowego"}, {"id": "d", "text": "dolnej części zakrętu przedśrodkowego"}, {"id": "e", "text": "hipokampie"}]'::jsonb,
   'c',
   $E$Pierwszorzędowa **kora czuciowa** leży w **zakręcie zaśrodkowym** (płat ciemieniowy, pole 3,1,2). Zgodnie z **homunkulusem czuciowym** twarz, jama ustna, zęby i dziąsła rzutują na **dolną część** zakrętu (blisko bruzdy bocznej), a kończyna dolna na płacik okołośrodkowy. Zakręt przedśrodkowy (D) to kora ruchowa. Płacik okołośrodkowy reprezentuje krocze i stopę — nie zęby.$E$,
   'ośrodki korowe', 'ANATLEK-129'),
(109, 'ANA-OBW',
   'Splot podbrzuszny dolny:',
   '[{"id": "a", "text": "powstaje z gałęzi brzusznych nn. rdzeniowych krzyżowych"}, {"id": "b", "text": "leży w obrębie dołu kulszowo-odbytniczego"}, {"id": "c", "text": "leży w obrębie płyty naczyniowo-nerwowej miednicy"}, {"id": "d", "text": "otacza t. krezkową dolną"}, {"id": "e", "text": "powstaje z gałęzi łączących nn. rdzeniowych krzyżowych"}]'::jsonb,
   'c',
   $E$**Splot podbrzuszny dolny** (miedniczy) to splot autonomiczny leżący po bokach narządów miednicy, w obrębie **płyty (blaszki) naczyniowo-nerwowej miednicy** przylegającej do odbytnicy, pęcherza i (u kobiet) pochwy. Tworzą go włókna współczulne z nerwów podbrzusznych oraz przywspółczulne z **nerwów trzewnych miednicznych** (S2–S4). Splot wokół t. krezkowej dolnej to splot krezkowy dolny (D), nie podbrzuszny dolny.$E$,
   'splot podbrzuszny dolny', 'ANATLEK-133'),
(110, 'ANA-NAC',
   'Głównym naczyniem tętniczym zaopatrującym mózgowie jest:',
   '[{"id": "a", "text": "Tętnica kręgowa"}, {"id": "b", "text": "Tętnica oponowa środkowa"}, {"id": "c", "text": "Tętnica szyjna wewnętrzna"}, {"id": "d", "text": "Tętnica podstawna mózgu"}, {"id": "e", "text": "Tętnica szyjna zewnętrzna"}]'::jsonb,
   'c',
   $E$**Tętnica szyjna wewnętrzna** dostarcza około **2/3–4/5 krwi** do mózgowia, zaopatrując przez tt. przednią i środkową mózgu większość półkul (krążenie przednie). Pozostałą część (krążenie tylne) zapewnia układ kręgowo-podstawny. T. kręgowa i podstawna to elementy tego układu tylnego, ale głównym, dominującym naczyniem mózgowia pozostaje **t. szyjna wewnętrzna**. Oponowa środkowa zaopatruje oponę twardą, nie mózg.$E$,
   'unaczynienie mózgowia', 'ANATLEK-134'),
(111, 'ANA-KON',
   'Mięśnie mające przyczep początkowy na guzie kulszowym, a końcowy na kłykciu przyśrodkowym kości piszczelowej i głowie strzałki to:',
   '[{"id": "a", "text": "mm. półścięgnisty, półbłoniasty i dwugłowy uda"}, {"id": "b", "text": "mm. grzebieniowy, smukły i przywodziciel krótki"}, {"id": "c", "text": "m. przywodziciel długi"}, {"id": "d", "text": "m. krawiecki"}, {"id": "e", "text": "m. czworogłowy uda"}]'::jsonb,
   'a',
   $E$**Grupa tylna uda** (kulszowo-goleniowe) rozpoczyna się na **guzie kulszowym**: **półścięgnisty** i **półbłoniasty** kończą się przyśrodkowo (okolica kłykcia przyśrodkowego piszczeli, m.in. „gęsia stopka"), a **dwugłowy uda** bocznie na **głowie strzałki**. Prostują udo w stawie biodrowym i zginają w kolanowym. Głowa krótka dwugłowego odchodzi od kresy chropawej, nie od guza — ale grupa jako całość pasuje do opisu.$E$,
   'mięśnie tylne uda', 'ANATLEK-136'),
(112, 'ANA-MIE',
   'Przyczep końcowy mięśnia rylcowo-gnykowego jest zwykle przeszywany lub krzyżowany przez ścięgno innego mięśnia związanego z kością gnykową. Którego?',
   '[{"id": "a", "text": "Żuchwowo-gnykowego"}, {"id": "b", "text": "Mostkowo-tarczowego"}, {"id": "c", "text": "Łopatkowo-gnykowego"}, {"id": "d", "text": "Językowo-gnykowego"}, {"id": "e", "text": "Dwubrzuścowego"}]'::jsonb,
   'e',
   $E$**Mięsień rylcowo-gnykowy** biegnie od wyrostka rylcowatego do trzonu kości gnykowej; tuż przed przyczepem jego ścięgno **rozdwaja się** i obejmuje (jest przeszyte przez) **ścięgno pośrednie mięśnia dwubrzuścowego**. Oba rozwijają się z drugiego łuku skrzelowego i są unerwione przez **nerw twarzowy (VII)**. Pozostałe mięśnie nie mają tej relacji ze ścięgnem rylcowo-gnykowego.$E$,
   'mięśnie nadgnykowe', 'ANATLEK-137'),
(113, 'ANA-NAC',
   'Żyła głęboka twarzy to bezpośrednie połączenie żyły twarzowej z:',
   '[{"id": "a", "text": "Żyłą szyjną zewnętrzną"}, {"id": "b", "text": "Żyłą szczękową"}, {"id": "c", "text": "Splotem zażuchwowym"}, {"id": "d", "text": "Żyłą zażuchwową"}, {"id": "e", "text": "Splotem skrzydłowym"}]'::jsonb,
   'e',
   $E$**Żyła głęboka twarzy** łączy żyłę twarzową ze **splotem skrzydłowym** (splotem żylnym leżącym wokół mięśni skrzydłowych). To połączenie ma znaczenie kliniczne: zakażenia twarzy (tzw. „trójkąt śmierci") mogą tą drogą oraz przez żyłę oczną szerzyć się do **zatoki jamistej**, grożąc zakrzepicą. Splot skrzydłowy uchodzi dalej do żyły szczękowej i zażuchwowej, ale bezpośrednim połączeniem żyły głębokiej twarzy jest splot skrzydłowy.$E$,
   'żyły twarzy', 'ANATLEK-138'),
(114, 'ANA-TUL',
   'Pozostałością po płodowym otworze owalnym jest u dorosłego:',
   '[{"id": "a", "text": "Więzadło tętnicze"}, {"id": "b", "text": "Struny tętnicze"}, {"id": "c", "text": "Więzadło obłe wątroby"}, {"id": "d", "text": "Dół owalny"}, {"id": "e", "text": "Więzadło żylne"}]'::jsonb,
   'd',
   $E$**Otwór owalny** w przegrodzie międzyprzedsionkowej płodu umożliwiał przeciek krwi z przedsionka prawego do lewego (omijając płuca). Po urodzeniu wzrost ciśnienia w lewym przedsionku dociska zastawkę otworu, który zarasta, pozostawiając zagłębienie — **dół owalny** (fossa ovalis). Niezarośnięcie daje przetrwały otwór owalny (PFO). Pozostałe opcje to ślady po: przewodzie tętniczym (A), żyle pępkowej (C), przewodzie żylnym (E).$E$,
   'pozostałości krążenia płodowego', 'ANATLEK-139'),
(115, 'ANA-TRZ',
   'Do ucha środkowego nie należy:',
   '[{"id": "a", "text": "Błędnik błoniasty"}, {"id": "b", "text": "Jama bębenkowa"}, {"id": "c", "text": "Jama sutkowa"}, {"id": "d", "text": "Kosteczki słuchowe"}, {"id": "e", "text": "Trąbka słuchowa"}]'::jsonb,
   'a',
   $E$**Ucho środkowe** obejmuje **jamę bębenkową** z **kosteczkami słuchowymi** (młoteczek, kowadełko, strzemiączko), **jamę sutkową** z komórkami wyrostka oraz **trąbkę słuchową** (Eustachiusza). **Błędnik błoniasty** wraz z błędnikiem kostnym należy do **ucha wewnętrznego** — zawiera ślimak i narząd przedsionkowy. Ślad: ucho środkowe = przestrzenie powietrzne i kosteczki; ucho wewnętrzne = błędniki z płynami (perylimfa, endolimfa).$E$,
   'ucho środkowe', 'ANATLEK-140'),
(116, 'ANA-MIE',
   'Mięsień rylcowo-gnykowy unerwia:',
   '[{"id": "a", "text": "Nerw żuchwowy (V3)"}, {"id": "b", "text": "Nerw twarzowy (VII)"}, {"id": "c", "text": "Nerw podjęzykowy (XII)"}, {"id": "d", "text": "Nerw szczękowy (V2)"}, {"id": "e", "text": "Nerw językowo-gardłowy (IX)"}]'::jsonb,
   'b',
   $E$**Mięsień rylcowo-gnykowy** rozwija się z **drugiego łuku skrzelowego**, dlatego — jak wszystkie pochodne tego łuku (mięśnie mimiczne, tylny brzusiec dwubrzuścowego, strzemiączkowy) — jest unerwiony przez **nerw twarzowy (VII)**.$E$,
   'unerwienie mięśni nadgnykowych', 'ANATLEK-141'),
(117, 'ANA-TUL',
   'Znajduje się w jednej trzeciej odległości pomiędzy pępkiem a prawym kolcem biodrowym przednim górnym. Opis ten odnosi się do:',
   '[{"id": "a", "text": "Punktu Verresa"}, {"id": "b", "text": "Punktu Lanza"}, {"id": "c", "text": "Punktu McBurneya"}, {"id": "d", "text": "Punktu G"}, {"id": "e", "text": "Punktu Basyego"}]'::jsonb,
   'c',
   $E$**Punkt McBurneya** leży na granicy **bocznej 1/3 i przyśrodkowych 2/3** linii łączącej **pępek z prawym kolcem biodrowym przednim górnym** (ASIS) — odpowiada rzutowi podstawy wyrostka robaczkowego. Bolesność uciskowa w tym miejscu jest klasycznym objawem ostrego zapalenia wyrostka. **Punkt Lanza** leży na linii międzykolcowej (prawa 1/3). Punkt Verresa odnosi się do laparoskopii, nie do wyrostka.$E$,
   'punkty topograficzne brzucha', 'ANATLEK-142'),
(118, 'ANA-TRZ',
   'W stosunku do jamy otrzewnej dwunastnica jest położona:',
   '[{"id": "a", "text": "Wtórnie zaotrzewnowo"}, {"id": "b", "text": "Pierwotnie zaotrzewnowo"}, {"id": "c", "text": "Częściowo wewnątrzotrzewnowo i częściowo wtórnie zaotrzewnowo"}, {"id": "d", "text": "Częściowo wewnątrzotrzewnowo i częściowo pierwotnie zewnątrzotrzewnowo"}, {"id": "e", "text": "Wewnątrzotrzewnowo"}]'::jsonb,
   'c',
   $E$**Opuszka dwunastnicy** (początkowy odcinek części górnej) leży **wewnątrzotrzewnowo** — jest ruchoma, połączona z więzadłem wątrobowo-dwunastniczym. Pozostała część dwunastnicy w trakcie rozwoju przylega do tylnej ściany i staje się **wtórnie zaotrzewnowa**. Dlatego dwunastnica jest „częściowo wewnątrz-, częściowo wtórnie zaotrzewnowa". Pierwotnie zaotrzewnowe są np. nerki — dwunastnica taka nie jest.$E$,
   'dwunastnica — położenie', 'ANATLEK-145'),
(119, 'ANA-CZA',
   'Ile jest głównych chrząstek nosa zewnętrznego?',
   '[{"id": "a", "text": "3"}, {"id": "b", "text": "4"}, {"id": "c", "text": "1"}, {"id": "d", "text": "2"}, {"id": "e", "text": "5"}]'::jsonb,
   'e',
   $E$Do głównych chrząstek nosa zewnętrznego zalicza się **pięć**: nieparzystą **chrząstkę przegrody nosa** oraz parzyste — **chrząstki boczne nosa** (2) i **chrząstki skrzydłowe większe** (2). Dodatkowo występują drobne chrząstki skrzydłowe mniejsze i nosowe dodatkowe, ale głównych jest 5. Wraz z kośćmi nosowymi i wyrostkami szczęki tworzą rusztowanie nosa, nadające kształt i drożność nozdrzy.$E$,
   'chrząstki nosa zewnętrznego', 'ANATLEK-146'),
(120, 'ANA-KON',
   'Mięsień napinacz powięzi szerokiej:',
   '[{"id": "a", "text": "Obraca udo na zewnątrz"}, {"id": "b", "text": "Przywodzi udo"}, {"id": "c", "text": "Odwodzi udo"}, {"id": "d", "text": "Prostuje udo w stawie biodrowym"}, {"id": "e", "text": "Prostuje udo w stawie kolanowym"}]'::jsonb,
   'c',
   $E$**Mięsień napinacz powięzi szerokiej** biegnie od kolca biodrowego przedniego górnego do **pasma biodrowo-piszczelowego**. Działając na staw biodrowy: **odwodzi**, zgina i **obraca udo do wewnątrz** (nie na zewnątrz). Przez pasmo biodrowo-piszczelowe stabilizuje też wyprostowane kolano, ale jego główną funkcją w biodrze jest **odwodzenie**. Unerwiany przez nerw pośladkowy górny (L4–S1), jak pośladkowe średni i mały.$E$,
   'mięśnie obręczy biodrowej', 'ANATLEK-148'),
(121, 'ANA-NAC',
   'Do węzłów chłonnych pachowych zaliczamy:',
   '[{"id": "a", "text": "szczytowe"}, {"id": "b", "text": "podłopatkowe"}, {"id": "c", "text": "boczne"}, {"id": "d", "text": "wszystkie wymienione"}, {"id": "e", "text": "piersiowe"}]'::jsonb,
   'd',
   $E$**Węzły chłonne pachowe** dzieli się klasycznie na **pięć grup**: **piersiowe** (przednie), **podłopatkowe** (tylne), **boczne** (ramienne), **środkowe (centralne)** oraz **szczytowe (wierzchołkowe)**, które zbierają chłonkę z pozostałych i odprowadzają do pnia podobojczykowego. Wszystkie wymienione w opcjach (szczytowe, podłopatkowe, boczne, piersiowe) należą do pachowych — stąd poprawna „wszystkie wymienione". Mają kluczowe znaczenie w drenażu chłonki sutka i kończyny górnej.$E$,
   'węzły chłonne pachowe', 'ANATLEK-151'),
(122, 'ANA-TUL',
   'Z podanych wybierz odpowiedź zawierającą jedynie gałęzie aorty wstępującej (I – t. wieńcowa prawa, II – t. wieńcowa lewa, III – gałęzie oskrzelowe, IV – pień ramienno-głowowy, V – tt. przeponowe górne, VI – t. szyjna wspólna lewa, VII – gałęzie przełykowe, VIII – tt. międzyżebrowe tylne, IX – t. podobojczykowa lewa, X – gałęzie śródpiersiowe, XI – tt. międzyżebrowe przednie, XII – gałęzie osierdziowe):',
   '[{"id": "a", "text": "V, VIII"}, {"id": "b", "text": "III, VII, X, XII"}, {"id": "c", "text": "VIII, XI"}, {"id": "d", "text": "IV, VI, IX"}, {"id": "e", "text": "I, II"}]'::jsonb,
   'e',
   $E$**Aorta wstępująca** oddaje wyłącznie **tętnice wieńcowe — prawą i lewą** (I, II), odchodzące z zatok aorty tuż nad zastawką. Gałęzie IV, VI, IX (pień ramienno-głowowy, t. szyjna wspólna lewa, t. podobojczykowa lewa) pochodzą z **łuku aorty**. Gałęzie oskrzelowe, przełykowe, śródpiersiowe, międzyżebrowe tylne, przeponowe górne i osierdziowe to gałęzie **aorty piersiowej (zstępującej)**.$E$,
   'gałęzie aorty', 'ANATLEK-152'),
(123, 'ANA-TUL',
   'Ujścia których żył nie znajdują się u zdrowego człowieka w przedsionku prawym?',
   '[{"id": "a", "text": "Zatoki wieńcowej"}, {"id": "b", "text": "Żył najmniejszych"}, {"id": "c", "text": "Żył płucnych"}, {"id": "d", "text": "Żyły Eustachiusza"}, {"id": "e", "text": "Żyły głównej górnej"}]'::jsonb,
   'c',
   $E$Do **przedsionka prawego** uchodzą: **żyła główna górna i dolna**, **zatoka wieńcowa** (zbiera krew z serca) oraz drobne **żyły najmniejsze serca** (Tebezjusza). **Żyły płucne** (cztery) prowadzą krew utlenowaną i uchodzą do **przedsionka lewego** — dlatego nie należą do prawego. „Żyła Eustachiusza" to mylące określenie zastawki ż. głównej dolnej; sama żyła główna dolna uchodzi po prawej. Poprawna: żyły płucne (C).$E$,
   'przedsionek prawy serca', 'ANATLEK-153'),
(124, 'ANA-NER',
   'Który z nerwów odpowiada za poruszanie językiem?',
   '[{"id": "a", "text": "V (V3) – nerw żuchwowy"}, {"id": "b", "text": "XI – nerw dodatkowy"}, {"id": "c", "text": "IX – nerw językowo-gardłowy"}, {"id": "d", "text": "XII – nerw podjęzykowy"}, {"id": "e", "text": "VII – nerw twarzowy"}]'::jsonb,
   'd',
   $E$**Nerw podjęzykowy (XII)** to nerw **ruchowy** języka — unerwia wszystkie mięśnie wewnętrzne i większość zewnętrznych (z wyjątkiem podniebienno-językowego, od X). Jego uszkodzenie powoduje zbaczanie wysuniętego języka **w stronę uszkodzenia**. V3 prowadzi czucie ogólne przedniej 2/3 (n. językowy), VII smak przedniej 2/3 (struna bębenkowa), IX czucie i smak tylnej 1/3 — ale ruch to wyłącznie XII.$E$,
   'nerw podjęzykowy', 'ANATLEK-154'),
(125, 'ANA-OUN',
   'Drogi rdzeniowo-mózgowe:',
   '[{"id": "a", "text": "Pośredniczą w przekazywaniu impulsów z mózgowia do efektorów"}, {"id": "b", "text": "Są drogami ruchowymi"}, {"id": "c", "text": "Dzielą się na 2 grupy: rdzeniowo-wzgórzowe i rdzeniowo-opuszkowe"}, {"id": "d", "text": "Są drogami czuciowymi"}, {"id": "e", "text": "Utworzone są z włókien zstępujących"}]'::jsonb,
   'd',
   $E$**Drogi rdzeniowo-mózgowe** prowadzą impulsy **od rdzenia kręgowego ku mózgowiu**, czyli są drogami **czuciowymi (wstępującymi)** — niosą informacje czuciowe do wyższych pięter OUN. Drogi ruchowe to drogi **mózgowo-rdzeniowe** (zstępujące), np. korowo-rdzeniowa. Należą tu m.in. drogi rdzeniowo-wzgórzowe (ból, temperatura) i rdzeniowo-móżdżkowe (czucie głębokie) — nie „rdzeniowo-opuszkowe", co wyklucza C.$E$,
   'drogi rdzeniowo-mózgowe', 'ANATLEK-155'),
(126, 'ANA-TRZ',
   'Które stwierdzenie dotyczące pęcherza moczowego jest nieprawdziwe?',
   '[{"id": "a", "text": "leży wewnątrzotrzewnowo"}, {"id": "b", "text": "m. zwieracz pęcherza jest zbudowany z mięśni gładkich i nie podlega naszej woli"}, {"id": "c", "text": "dno jest najmniej ruchomą częścią pęcherza"}, {"id": "d", "text": "posiada szczyt, dno, trzon oraz szyję"}, {"id": "e", "text": "krew ze splotu pęcherzowego odpływa do żyły biodrowej wewnętrznej"}]'::jsonb,
   'a',
   $E$Pęcherz moczowy leży **podotrzewnowo (zewnątrzotrzewnowo)** — otrzewna pokrywa jedynie jego górną powierzchnię i szczyt; nie leży wewnątrzotrzewnowo, więc A jest nieprawdziwe. Pozostałe są prawdziwe: zwieracz **wewnętrzny** to mięsień gładki, niezależny od woli; **dno** (najniższa, tylno-dolna część) jest najmniej ruchome; pęcherz dzieli się na szczyt, trzon, dno i szyję; krew odpływa splotem pęcherzowym do **żyły biodrowej wewnętrznej**.$E$,
   'pęcherz moczowy', 'ANATLEK-156'),
(127, 'ANA-OBW',
   'W przebiegu nerwu sromowego znajdują się włókna:',
   '[{"id": "a", "text": "Autonomiczne"}, {"id": "b", "text": "Czuciowe, ruchowe, autonomiczne"}, {"id": "c", "text": "Czuciowe"}, {"id": "d", "text": "Czuciowe, ruchowe"}, {"id": "e", "text": "Ruchowe"}]'::jsonb,
   'b',
   $E$**Nerw sromowy** (S2–S4, ze splotu krzyżowego) zawiera włókna **czuciowe** (skóra krocza, narządów płciowych zewnętrznych), **ruchowe** (mięśnie dna miednicy, zwieracz zewnętrzny odbytu i cewki) oraz **autonomiczne** — współczulne włókna naczynioruchowe biegnące z nerwem oraz przywspółczulne uczestniczące w odruchu erekcji. Stąd ma charakter **mieszany** z komponentą wegetatywną — poprawna B.$E$,
   'nerw sromowy', 'ANATLEK-157'),
(128, 'ANA-TUL',
   'Wymiar międzygrzebieniowy miednicy u kobiet wynosi około:',
   '[{"id": "a", "text": "31-32 cm"}, {"id": "b", "text": "28-29 cm"}, {"id": "c", "text": "11.5 cm"}, {"id": "d", "text": "7 cm"}, {"id": "e", "text": "25-26 cm"}]'::jsonb,
   'b',
   $E$**Wymiar międzygrzebieniowy** (distantia cristarum) — odległość między najdalszymi punktami grzebieni biodrowych — wynosi prawidłowo ok. **28–29 cm**. Pozostałe wymiary zewnętrzne: **międzykolcowy** (spinarum) ~25–26 cm, **międzykrętarzowy** (trochanterica) ~31–32 cm, **sprzężna zewnętrzna** ~20 cm. Wartość 11 cm dotyczy sprzężnej prawdziwej (wewnętrznej). Ślad rosnący: spinarum < cristarum < trochanterica (25 < 28 < 31).$E$,
   'wymiary miednicy', 'ANATLEK-158'),
(129, 'ANA-TRZ',
   'Odgałęzieniami pnia trzewnego są:',
   '[{"id": "a", "text": "Tętnica wątrobowa właściwa"}, {"id": "b", "text": "Tętnica śledzionowa"}, {"id": "c", "text": "Tętnica śledzionowa i tętnica żołądkowa lewa"}, {"id": "d", "text": "Wszystkie prawidłowe"}, {"id": "e", "text": "Tętnica żołądkowa lewa"}]'::jsonb,
   'c',
   $E$**Pień trzewny** odchodzi od aorty na wysokości Th12 i dzieli się na **trzy** gałęzie: **t. żołądkową lewą**, **t. śledzionową** i **t. wątrobową wspólną**. Wśród opcji bezpośrednimi gałęziami pnia są śledzionowa i żołądkowa lewa (C). **T. wątrobowa właściwa** (A) to gałąź t. wątrobowej **wspólnej**, więc nie odchodzi wprost od pnia. Mnemonik: **Left gastric, Splenic, Common hepatic** — „pień ma 3 gałęzie".$E$,
   'pień trzewny', 'ANATLEK-159'),
(130, 'ANA-NER',
   'Prawidłowe zestawienie gałęzi nerwu trójdzielnego z otworami, przez które opuszczają czaszkę, to:',
   '[{"id": "a", "text": "V1 – szczelina oczodołowa górna, V2 – otwór owalny, V3 – otwór okrągły"}, {"id": "b", "text": "V1 – szczelina oczodołowa dolna, V2 – otwór okrągły, V3 – otwór owalny"}, {"id": "c", "text": "V1 – szczelina oczodołowa górna, V2 – otwór okrągły, V3 – otwór owalny"}, {"id": "d", "text": "V1 – kanał wzrokowy, V2 – otwór owalny, V3 – otwór okrągły"}, {"id": "e", "text": "V1 – szczelina oczodołowa dolna, V2 – otwór owalny, V3 – otwór okrągły"}]'::jsonb,
   'c',
   $E$Gałęzie nerwu trójdzielnego (V) opuszczają czaszkę: **V1 (oczny)** przez **szczelinę oczodołową górną**, **V2 (szczękowy)** przez **otwór okrągły**, **V3 (żuchwowy)** przez **otwór owalny**. Pytanie błędnie mówi „nerwu twarzowego", ale opcje dotyczą V — odpowiada C. Mnemonik **Standing Room Only**: Superior orbital fissure (V1), Rotundum (V2), Ovale (V3).$E$,
   'nerw trójdzielny — wyjścia z czaszki', 'ANATLEK-163'),
(131, 'ANA-TRZ',
   'Najniżej położone miejsce zachyłka żebrowo-przeponowego leży w linii:',
   '[{"id": "a", "text": "przykręgowej"}, {"id": "b", "text": "pachowej tylnej"}, {"id": "c", "text": "pachowej przedniej"}, {"id": "d", "text": "środkowo-obojczykowej"}, {"id": "e", "text": "pachowej środkowej"}]'::jsonb,
   'e',
   $E$**Zachyłek żebrowo-przeponowy** (recessus costodiaphragmaticus) to najgłębsza rezerwowa przestrzeń jamy opłucnej, gdzie gromadzi się płyn wysiękowy. Sięga najniżej w **linii pachowej środkowej**, gdzie dolna granica opłucnej osiąga poziom **żebra X**. Dla porównania granica płuca jest tam na poziomie żebra VIII. To miejsce ma znaczenie przy nakłuciu opłucnej (torakocentezie) wykonywanym powyżej dolnej granicy.$E$,
   'opłucna — zachyłki', 'ANATLEK-164'),
(132, 'ANA-MIE',
   'Do okolicy bocznej powierzchownej twarzy nie należy:',
   '[{"id": "a", "text": "Powięź policzkowo-gardłowa"}, {"id": "b", "text": "Dół podskroniowy"}, {"id": "c", "text": "Błona śluzowa"}, {"id": "d", "text": "Mięsień policzkowy"}, {"id": "e", "text": "Skóra"}]'::jsonb,
   'b',
   $E$Okolica **boczna powierzchowna** twarzy (okolica policzkowa) obejmuje warstwy od powierzchni w głąb: **skórę**, tkankę podskórną, **mięsień policzkowy** pokryty **powięzią policzkowo-gardłową** oraz **błonę śluzową** przedsionka jamy ustnej. **Dół podskroniowy** leży **głęboko**, należy do okolicy bocznej **głębokiej** twarzy (zawiera mięśnie skrzydłowe, splot skrzydłowy, t. szczękową) — więc nie należy do powierzchownej.$E$,
   'okolice twarzy', 'ANATLEK-165'),
(133, 'ANA-KON',
   'Które twierdzenie dotyczące trójkąta udowego jest nieprawdziwe?',
   '[{"id": "a", "text": "podstawa trójkąta stanowi wejście do kanału przywodzicieli"}, {"id": "b", "text": "bliższą część trójkąta zajmuje dół biodrowo-łonowy"}, {"id": "c", "text": "przyśrodkowo jest ograniczony przez m. przywodziciel długi"}, {"id": "d", "text": "zawiera tętnicę, żyłę i nerw udowy"}, {"id": "e", "text": "od boku ogranicza go m. krawiecki"}]'::jsonb,
   'a',
   $E$**Trójkąt udowy** (Scarpy) ograniczają: **górą więzadło pachwinowe** (podstawa), **bocznie m. krawiecki**, **przyśrodkowo m. przywodziciel długi**. Zawiera tętnicę, żyłę i nerw udowy oraz węzły chłonne. Nieprawdą jest A: **podstawą trójkąta jest więzadło pachwinowe**, a wejście do **kanału przywodzicieli** stanowi **wierzchołek (szczyt)** trójkąta, nie jego podstawa. Stąd poprawna (fałszywa) odpowiedź to A.$E$,
   'trójkąt udowy', 'ANATLEK-167'),
(134, 'ANA-OUN',
   'Prawdziwe stwierdzenie o rdzeniu kręgowym:',
   '[{"id": "a", "text": "Ma kształt graniastosłupa prawidłowego czworokątnego"}, {"id": "b", "text": "Posiada jedno zgrubienie tj. zgrubienie lędźwiowe"}, {"id": "c", "text": "Jego grubość jest równomierna"}, {"id": "d", "text": "Posiada jedno zgrubienie tj. zgrubienie szyjne"}, {"id": "e", "text": "W dwóch miejscach występują wrzecionowate rozszerzenia"}]'::jsonb,
   'e',
   $E$Rdzeń kręgowy ma **dwa wrzecionowate zgrubienia**: **szyjne** (C4–Th1, dla splotu ramiennego, kończyna górna) i **lędźwiowo-krzyżowe** (L1–S3, dla kończyny dolnej). Odpowiadają one zwiększonej liczbie neuronów ruchowych unerwiających kończyny. Stąd jego grubość **nie jest równomierna** (C błędne), a stwierdzenia o „jednym zgrubieniu" (B, D) są niepełne. Kształt jest spłaszczonego walca, nie graniastosłupa. Poprawna E.$E$,
   'rdzeń kręgowy — morfologia', 'ANATLEK-168'),
(135, 'ANA-TUL',
   'Łącznikiem pomiędzy żyłą główną górną a dolną w klatce piersiowej jest zwykle:',
   '[{"id": "a", "text": "Żyła nieparzysta krótka dodatkowa"}, {"id": "b", "text": "Żyła wrotna"}, {"id": "c", "text": "Kąt żylny"}, {"id": "d", "text": "Żyła nieparzysta"}, {"id": "e", "text": "Żyła nieparzysta krótka"}]'::jsonb,
   'd',
   $E$**Żyła nieparzysta** (v. azygos) biegnie po prawej stronie kręgosłupa, zbiera krew z żył międzyżebrowych tylnych, nieparzystej krótkiej i dodatkowej, a u góry łukiem uchodzi do **żyły głównej górnej**. Ku dołowi łączy się z układem **żyły głównej dolnej** (przez żyłę lędźwiową wstępującą). Stanowi więc naturalny **zespolenie kawalno-kawalne** — krążenie oboczne przy niedrożności którejś z żył głównych. Poprawna: żyła nieparzysta.$E$,
   'układ żyły nieparzystej', 'ANATLEK-169'),
(136, 'ANA-TRZ',
   'W czasie opróżniania pęcherza moczowego moczowód jest zamykany przez:',
   '[{"id": "a", "text": "Nie jest zamykany i mocz częściowo cofa się do moczowodów"}, {"id": "b", "text": "Mięsień wypieracz moczu, zaciskający część śródścienną moczowodu"}, {"id": "c", "text": "Zastawkę moczowodu"}, {"id": "d", "text": "Mięsień zwieracz moczowodu"}, {"id": "e", "text": "Fałd międzymoczowodowy"}]'::jsonb,
   'b',
   $E$Moczowód przebija ścianę pęcherza **skośnie**, a jego odcinek **śródścienny** nie ma własnej zastawki anatomicznej. Podczas mikcji skurcz **mięśnia wypieracza** (detrusor) podnosi ciśnienie i **zaciska śródścienny odcinek moczowodu**, działając jak zastawka czynnościowa zapobiegająca **odpływowi wstecznemu** (refluksowi pęcherzowo-moczowodowemu). Skrócenie tego odcinka u dzieci sprzyja refluksowi. Poprawna B.$E$,
   'pęcherz moczowy — czynność', 'ANATLEK-171'),
(137, 'ANA-OUN',
   'Istota szara rdzenia kręgowego na przekroju poprzecznym ma kształt litery:',
   '[{"id": "a", "text": "C"}, {"id": "b", "text": "B"}, {"id": "c", "text": "H"}, {"id": "d", "text": "T"}, {"id": "e", "text": "D"}]'::jsonb,
   'c',
   $E$Na przekroju poprzecznym **istota szara** rdzenia kręgowego tworzy kształt litery **H** (lub motyla) — dwa rogi przednie (ruchowe), dwa tylne (czuciowe), połączone **spoidłem szarym** z kanałem środkowym; w odcinku piersiowym i górnym lędźwiowym dochodzą rogi boczne (autonomiczne). Otacza ją istota biała ze sznurami przednim, bocznym i tylnym. Mnemonik: szare „H" w środku, biała otoczka dookoła.$E$,
   'rdzeń kręgowy — istota szara', 'ANATLEK-172'),
(138, 'ANA-NER',
   'Jądra ruchowe nerwu trójdzielnego znajdują się w:',
   '[{"id": "a", "text": "Śródmózgowiu"}, {"id": "b", "text": "Moście – jądro ślinowe górne"}, {"id": "c", "text": "Moście – jądro w dnie dołu równoległobocznego"}, {"id": "d", "text": "Rdzeniu przedłużonym"}, {"id": "e", "text": "Moście – jądro żwaczowe"}]'::jsonb,
   'e',
   $E$**Jądro ruchowe nerwu trójdzielnego** (jądro żwaczowe, nucleus motorius/masticatorius) leży w **moście**, przyśrodkowo od jądra czuciowego głównego. Wysyła włókna ruchowe z gałęzią V3 do mięśni żucia. Jądro ślinowe górne (B) należy do nerwu twarzowego (parasympatyczne). Trójdzielny ma też jądra czuciowe: śródmózgowiowe, mostowe (główne) i rdzeniowe — ale jądro **ruchowe** jest mostowe (żwaczowe). Poprawna E.$E$,
   'jądra nerwu trójdzielnego', 'ANATLEK-175'),
(139, 'ANA-OUN',
   'Wybierz odpowiedź zawierającą jedynie elementy wchodzące w skład międzymózgowia (1 – półkule mózgu, 2 – podwzgórze, 3 – pokrywa, 4 – rdzeń przedłużony, 5 – spoidło sklepienia, 6 – konary mózgu, 7 – wzgórzomózgowie, 8 – spoidło przednie, 9 – ciało modzelowate, 10 – niskowzgórze, 11 – móżdżek, 12 – most):',
   '[{"id": "a", "text": "2, 7, 10"}, {"id": "b", "text": "4, 12"}, {"id": "c", "text": "3, 6"}, {"id": "d", "text": "1, 5, 8, 9"}, {"id": "e", "text": "11, 12"}]'::jsonb,
   'a',
   $E$**Międzymózgowie** (diencephalon) obejmuje: **wzgórzomózgowie** (thalamencephalon — wzgórze, zawzgórze, nadwzgórze), **podwzgórze** (hypothalamus) i **niskowzgórze** (subthalamus). Z podanych pasują 2, 7, 10. **Pokrywa i konary mózgu** to śródmózgowie (3, 6), **most i rdzeń przedłużony** — tyłomózgowie (4, 12), a spoidła i ciało modzelowate (5, 8, 9) to struktury kresomózgowia. Poprawna A.$E$,
   'międzymózgowie — podział', 'ANATLEK-177'),
(140, 'ANA-TRZ',
   'Podczas cewnikowania starszego mężczyzny kolega po kilku próbach zmienia cewnik na coraz węższy. W jakim odcinku cewki moczowej zlokalizowany był najpewniej problem utrudniający wprowadzenie cewnika?',
   '[{"id": "a", "text": "Sterczowym"}, {"id": "b", "text": "Błoniastym"}, {"id": "c", "text": "Śródściennym"}, {"id": "d", "text": "Gąbczastym"}, {"id": "e", "text": "Żadnym, kolega może i jest starszy, ale na pewno nie doświadczony"}]'::jsonb,
   'a',
   $E$U **starszego mężczyzny** najczęstszą przyczyną trudności w cewnikowaniu jest **łagodny rozrost stercza (BPH)**, który zwęża **odcinek sterczowy** cewki przebiegający przez gruczoł krokowy. Powiększony stercz uciska i wydłuża ten odcinek, utrudniając przejście cewnika — stąd konieczność użycia węższego. Odcinek błoniasty jest najwęższy anatomicznie, ale to stercz tłumaczy zależny od wieku problem. Poprawna A.$E$,
   'cewka moczowa męska', 'ANATLEK-179'),
(141, 'ANA-CZA',
   'Dół skrzydłowo-podniebienny łączy się:',
   '[{"id": "a", "text": "Poprzez kanał skrzydłowy z dołem przednim czaszki"}, {"id": "b", "text": "Poprzez kanał skrzydłowo-podniebienny z oczodołem"}, {"id": "c", "text": "Poprzez otwór okrągły z dołem środkowym czaszki"}, {"id": "d", "text": "Poprzez kanał podniebienny większy z dołem podskroniowym"}, {"id": "e", "text": "Poprzez szczelinę skrzydłowo-szczękową z jamą nosa"}]'::jsonb,
   'c',
   $E$**Dół skrzydłowo-podniebienny** to węzeł komunikacyjny: z **dołem środkowym czaszki** łączy go **otwór okrągły** (V2), z **jamą nosową** — otwór klinowo-podniebienny, z **oczodołem** — szczelina oczodołowa dolna, z **jamą ustną** — kanał podniebienny większy, z **dołem podskroniowym** — szczelina skrzydłowo-szczękowa, a z podstawą czaszki — kanał skrzydłowy. Poprawnie zestawia połączenie tylko C (otwór okrągły → dół środkowy).$E$,
   'dół skrzydłowo-podniebienny', 'ANATLEK-181'),
(142, 'ANA-OBW',
   'Splot słoneczny to nazwa zwyczajowa:',
   '[{"id": "a", "text": "Splotu szyjnego"}, {"id": "b", "text": "Splotu przyuszniczego"}, {"id": "c", "text": "Splotu trzewnego"}, {"id": "d", "text": "Zwoju szyjno-piersiowego"}, {"id": "e", "text": "Splotu sercowego"}]'::jsonb,
   'c',
   $E$**Splot słoneczny** to potoczna nazwa **splotu trzewnego** (plexus coeliacus) — największego splotu autonomicznego jamy brzusznej, leżącego wokół początku pnia trzewnego i t. krezkowej górnej. Nazwa „słoneczny" odnosi się do promienistego, gwiaździstego rozchodzenia się gałęzi (splotów wtórnych) na okoliczne narządy. Zawiera włókna współczulne i przywspółczulne (z nerwu błędnego). Poprawna C.$E$,
   'splot trzewny', 'ANATLEK-183'),
(143, 'ANA-TUL',
   'Koronę serca stanowią:',
   '[{"id": "a", "text": "Komora lewa, aorta, żyły płucne"}, {"id": "b", "text": "Aorta, pień płucny"}, {"id": "c", "text": "Komora prawa, pień płucny, żyły główne"}, {"id": "d", "text": "Przedsionki"}, {"id": "e", "text": "Aorta, pień płucny, żyły płucne, żyły główne"}]'::jsonb,
   'e',
   $E$**Korona serca** (corona cordis) to zespół **wielkich naczyń** u podstawy serca: **aorta wstępująca**, **pień płucny**, **żyły płucne** oraz **żyły główne** (górna i dolna). Otaczają one podstawę serca niczym korona i wyznaczają granicę między przedsionkami a strukturami naczyniowymi. Nie należą tu komory ani same przedsionki. Najpełniej zestawia te naczynia odpowiedź E.$E$,
   'serce — duże naczynia', 'ANATLEK-184'),
(144, 'ANA-TUL',
   'Zastawka pnia płucnego składa się z płatków:',
   '[{"id": "a", "text": "Lewego, prawego i tylnego"}, {"id": "b", "text": "Lewego, prawego i przedniego"}, {"id": "c", "text": "Przedniego i tylnego"}, {"id": "d", "text": "Przedniego, przegrodowego i tylnego"}, {"id": "e", "text": "Górnego, środkowego i dolnego"}]'::jsonb,
   'b',
   $E$**Zastawka pnia płucnego** to zastawka półksiężycowata o **trzech płatkach**: **lewym, prawym i przednim**. Dla porównania **zastawka aortalna** ma płatki: lewy, prawy i **tylny** (z lewej i prawej odchodzą tętnice wieńcowe). Różnica w nazwie trzeciego płatka (przedni dla płucnej, tylny dla aortalnej) wynika z przestrzennego ułożenia ujść. Poprawna B.$E$,
   'zastawki serca', 'ANATLEK-185'),
(145, 'ANA-KON',
   'Który z poniższych mięśni obraca ramię do wewnątrz?',
   '[{"id": "a", "text": "Mięsień nadgrzebieniowy"}, {"id": "b", "text": "Mięsień obły większy"}, {"id": "c", "text": "Mięsień podgrzebieniowy"}, {"id": "d", "text": "Mięsień obły mniejszy"}, {"id": "e", "text": "Mięsień czworoboczny"}]'::jsonb,
   'b',
   $E$**Mięsień obły większy** biegnie od dolnego kąta łopatki do grzebienia guzka mniejszego kości ramiennej — **przywodzi i obraca ramię do wewnątrz** (rotacja wewnętrzna), wspomagając najszerszy grzbietu. Mięśnie **podgrzebieniowy** i **obły mniejszy** są rotatorami **zewnętrznymi**. Nadgrzebieniowy odwodzi (inicjuje odwiedzenie). Czworoboczny działa na łopatkę. Poprawna B.$E$,
   'mięśnie obręczy barkowej', 'ANATLEK-186'),
(146, 'ANA-OBW',
   'Stawy biodrowy, kolanowy i skokowo-goleniowy unerwiane są przez nerw:',
   '[{"id": "a", "text": "Piszczelowy"}, {"id": "b", "text": "Udowy"}, {"id": "c", "text": "Kulszowy"}, {"id": "d", "text": "Zasłonowy"}, {"id": "e", "text": "Strzałkowy wspólny"}]'::jsonb,
   'b',
   $E$Zgodnie z **prawem Hiltona** staw unerwiają nerwy mięśni nim poruszających. **Nerw udowy** (L2–L4) wysyła gałęzie stawowe do **biodra**, **kolana** (przez n. udowo-goleniowy i gałęzie m. czworogłowego) oraz uczestniczy w unerwieniu okolicy **stawu skokowego** przez nerw udowo-goleniowy (saphenus) zaopatrujący przyśrodkową stronę. To jedyny nerw obecny przy wszystkich trzech stawach. Poprawna B.$E$,
   'unerwienie stawów kończyny dolnej', 'ANATLEK-187'),
(147, 'ANA-OBW',
   'Mięsień piersiowy większy jest unerwiony przez:',
   '[{"id": "a", "text": "Nerw piersiowy długi"}, {"id": "b", "text": "Nerw piersiowy boczny"}, {"id": "c", "text": "Nerw piersiowy długi i nerw piersiowy przyśrodkowy"}, {"id": "d", "text": "Nerw piersiowy przyśrodkowy i nerw piersiowy boczny"}, {"id": "e", "text": "Nerw piersiowy przyśrodkowy"}]'::jsonb,
   'd',
   $E$**Mięsień piersiowy większy** unerwiają oba **nerwy piersiowe — boczny i przyśrodkowy** (z pęczków bocznego i przyśrodkowego splotu ramiennego). Nerw piersiowy boczny zaopatruje głównie głowę obojczykową, przyśrodkowy — mostkowo-żebrową (oraz cały piersiowy mniejszy). **Nerw piersiowy długi** unerwia mięsień zębaty przedni (nie piersiowy większy) — to klasyczna pułapka. Poprawna D.$E$,
   'unerwienie mięśni klatki piersiowej', 'ANATLEK-188'),
(148, 'ANA-OUN',
   'Drugi neuron drogi czucia proprioceptywnego (świadomego) tworzą komórki znajdujące się w:',
   '[{"id": "a", "text": "Istocie szarej wokół kanału środkowego"}, {"id": "b", "text": "Jądrze smukłym bądź jądrze klinowatym"}, {"id": "c", "text": "Oliwkach rdzenia przedłużonego"}, {"id": "d", "text": "Głowie rogu tylnego rdzenia kręgowego"}, {"id": "e", "text": "Piramidach rdzenia przedłużonego"}]'::jsonb,
   'b',
   $E$Świadome czucie głębokie biegnie drogą **sznurów tylnych**: I neuron (zwój rdzeniowy) wstępuje pęczkiem smukłym/klinowatym, **II neuron** leży w **jądrze smukłym (Golla) i klinowatym (Burdacha)** rdzenia przedłużonego, skąd włókna krzyżują się (wstęga przyśrodkowa) i biegną do **wzgórza** (III neuron). Stąd II neuron tej drogi to jądra smukłe/klinowate. Poprawna B.$E$,
   'drogi czucia głębokiego', 'ANATLEK-189'),
(149, 'ANA-NAC',
   'Mięsień mostkowo-gnykowy ogranicza trójkąt tarczowy szyi:',
   '[{"id": "a", "text": "Od tyłu"}, {"id": "b", "text": "Bocznie"}, {"id": "c", "text": "Od góry"}, {"id": "d", "text": "Od przodu"}, {"id": "e", "text": "Przyśrodkowo"}]'::jsonb,
   'd',
   $E$**Trójkąt tarczowy** (mięśniowy) szyi ograniczają: **od przodu (przyśrodkowo)** — linia pośrodkowa szyi i mięśnie podgnykowe (m.in. **mostkowo-gnykowy**), **od góry** — brzusiec górny m. łopatkowo-gnykowego, **od tyłu (boku)** — przedni brzeg m. mostkowo-obojczykowo-sutkowego. Zawiera tarczycę, krtań, tchawicę. Mostkowo-gnykowy biegnie przyśrodkowo, wyznaczając granicę przednią. Poprawna D.$E$,
   'trójkąty szyi', 'ANATLEK-190'),
(150, 'ANA-MIE',
   'Przestrzeń (dół) zażuchwowy jest położona:',
   '[{"id": "a", "text": "Do tyłu od gałęzi żuchwy"}, {"id": "b", "text": "Do tyłu od wyrostka sutkowatego"}, {"id": "c", "text": "Do przodu i powyżej przewodu słuchowego zewnętrznego"}, {"id": "d", "text": "Do boku od wyrostka rylcowatego"}, {"id": "e", "text": "Leży pod mięśniem mostkowo-obojczykowo-sutkowym"}]'::jsonb,
   'a',
   $E$**Dół zażuchwowy** (fossa retromandibularis) leży **do tyłu od gałęzi żuchwy**, przed wyrostkiem sutkowatym i m. mostkowo-obojczykowo-sutkowym, poniżej przewodu słuchowego zewnętrznego. Zawiera **ślinankę przyuszną**, **żyłę zażuchwową**, **t. szyjną zewnętrzną** oraz nerw twarzowy (VII). Stanowi ważną przestrzeń topograficzną boczną okolicy twarzy. Poprawna A.$E$,
   'dół zażuchwowy', 'ANATLEK-191'),
(151, 'ANA-KON',
   'Opuszcza ramię, przywodzi je, zgina i rotuje do wewnątrz z jednoczesnym pociąganiem łopatki w dół. O którym mięśniu wpływającym na ruchy kończyny górnej, ale nietopograficznie do niej nienależącym, mowa?',
   '[{"id": "a", "text": "Mięsień równoległoboczny"}, {"id": "b", "text": "Mięsień zębaty przedni"}, {"id": "c", "text": "Mięsień czworoboczny"}, {"id": "d", "text": "Mięsień piersiowy mniejszy"}, {"id": "e", "text": "Mięsień piersiowy większy"}]'::jsonb,
   'e',
   $E$**Mięsień piersiowy większy** (mięsień kolcowo-ramienny, należący topograficznie do klatki piersiowej, ale działający na ramię) **przywodzi, zgina i rotuje ramię do wewnątrz**, a przy ustalonym ramieniu **obniża obręcz barkową** (pociąga łopatkę w dół i przód). Mięśnie równoległoboczny, czworoboczny i zębaty przedni działają głównie na łopatkę. Piersiowy mniejszy obniża łopatkę, ale nie porusza ramienia. Poprawna E.$E$,
   'mięśnie kolcowo-ramienne', 'ANATLEK-192'),
(152, 'ANA-NAC',
   'Trójkąt tętnicy szyjnej ograniczają:',
   '[{"id": "a", "text": "brzeg m. mostkowo-obojczykowo-sutkowego, brzusiec górny m. łopatkowo-gnykowego, brzusiec tylny m. dwubrzuścowego"}, {"id": "b", "text": "brzeg m. mostkowo-obojczykowo-sutkowego, brzusiec przedni m. dwubrzuścowego, m. mostkowo-gnykowy"}, {"id": "c", "text": "brzuśce mięśnia dwubrzuścowego i brzeg trzonu żuchwy"}, {"id": "d", "text": "brzeg m. mostkowo-obojczykowo-sutkowego, brzusiec tylny m. dwubrzuścowego, m. mostkowo-gnykowy"}, {"id": "e", "text": "brzeg m. mostkowo-obojczykowo-sutkowego, brzusiec dolny m. łopatkowo-gnykowego, obojczyk"}]'::jsonb,
   'a',
   $E$**Trójkąt tętnicy szyjnej** (carotideum) ograniczają: **przedni brzeg m. mostkowo-obojczykowo-sutkowego** (z tyłu/boku), **brzusiec górny m. łopatkowo-gnykowego** (przednio-dolnie) oraz **brzusiec tylny m. dwubrzuścowego** (górnie). Zawiera podział tętnicy szyjnej wspólnej, żyłę szyjną wewnętrzną i nerw błędny.$E$,
   'trójkąty szyi', 'ANATLEK-193'),
(153, 'ANA-TRZ',
   'Na której powierzchni płuca znajduje się wnęka płuca?',
   '[{"id": "a", "text": "Powierzchni przyśrodkowej"}, {"id": "b", "text": "Powierzchni bocznej"}, {"id": "c", "text": "Powierzchni dolnej"}, {"id": "d", "text": "Powierzchni przedniej"}, {"id": "e", "text": "Powierzchni tylnej"}]'::jsonb,
   'a',
   $E$**Wnęka płuca** (hilum pulmonis) znajduje się na **powierzchni przyśrodkowej (śródpiersiowej)** płuca — tędy wchodzą i wychodzą struktury **korzenia płuca**: oskrzele główne, tętnica płucna, żyły płucne, naczynia oskrzelowe, nerwy i naczynia chłonne. Powierzchnia przyśrodkowa zwrócona jest ku śródpiersiu i zawiera też wycisk sercowy. Powierzchnia żebrowa (boczna) przylega do żeber. Poprawna A.$E$,
   'płuca — powierzchnie', 'ANATLEK-195'),
(154, 'ANA-CZA',
   'Z poniżej podanych, przez otwór wielki czaszki przechodzi:',
   '[{"id": "a", "text": "Tętnica kręgowa"}, {"id": "b", "text": "Zatoka skalista dolna"}, {"id": "c", "text": "Nerw okoruchowy"}, {"id": "d", "text": "Nerw żuchwowy"}, {"id": "e", "text": "Tętnica sitowa przednia"}]'::jsonb,
   'a',
   $E$Przez **otwór wielki (potyliczny)** przechodzą: **rdzeń przedłużony** z oponami, **tętnice kręgowe** (wstępują do jamy czaszki), korzenie rdzeniowe **nerwu dodatkowego (XI)**, tętnice rdzeniowe przednia i tylne oraz więzadła. Nerw okoruchowy biegnie przez szczelinę oczodołową górną, żuchwowy przez otwór owalny, zatoka skalista dolna przez otwór szyjny, sitowa przednia przez kanał sitowy. Poprawna A.$E$,
   'otwory podstawy czaszki', 'ANATLEK-196'),
(155, 'ANA-OUN',
   'Dwa największe zbiorniki podpajęczynówkowe to:',
   '[{"id": "a", "text": "Dół czworoboczny i zatoka prosta"}, {"id": "b", "text": "Zatoka strzałkowa górna i zatoka strzałkowa dolna"}, {"id": "c", "text": "Zatoka sitowa i zatoka szczękowa"}, {"id": "d", "text": "Zbiornik móżdżkowo-rdzeniowy i międzykonarowy"}, {"id": "e", "text": "Zbiornik czołowy i potyliczny"}]'::jsonb,
   'd',
   $E$**Zbiorniki podpajęczynówkowe** to poszerzenia przestrzeni podpajęczynówkowej wypełnione płynem mózgowo-rdzeniowym. Największe to **zbiornik móżdżkowo-rdzeniowy (wielki)** — między móżdżkiem a rdzeniem przedłużonym, miejsce nakłucia podpotylicznego — oraz **zbiornik międzykonarowy** (międzykonarowy/podstawny) u podstawy mózgu. Wymienione w innych opcjach to zatoki żylne lub przynosowe, nie zbiorniki PMR. Poprawna D.$E$,
   'opony i przestrzeń podpajęczynówkowa', 'ANATLEK-197'),
(156, 'ANA-TRZ',
   'Szczelina (granica) skośna płuca krzyżuje 4. przestrzeń międzyżebrową w linii:',
   '[{"id": "a", "text": "Przymostkowej"}, {"id": "b", "text": "Pachowej przedniej"}, {"id": "c", "text": "Środkowo-obojczykowej"}, {"id": "d", "text": "Pośrodkowej"}, {"id": "e", "text": "Pachowej środkowej"}]'::jsonb,
   'e',
   $E$**Szczelina skośna** płuca (oddzielająca płat dolny) rozpoczyna się z tyłu na poziomie **wyrostka kolczystego Th3–Th4**, biegnie ku przodowi i dołowi, krzyżując **4. przestrzeń międzyżebrową w linii pachowej środkowej**, a kończy w okolicy chrząstki żebra VI w linii środkowo-obojczykowej. Wyznacza ona przebieg granicy między płatami i jest istotna w osłuchiwaniu. Poprawna E.$E$,
   'opłucna — granice', 'ANATLEK-199'),
(157, 'ANA-OUN',
   'Róg przedni rdzenia kręgowego:',
   '[{"id": "a", "text": "Składa się z szczytu, szyjki i głowy"}, {"id": "b", "text": "Zwany jest ruchowym"}, {"id": "c", "text": "Jest cieńszy od rogu tylnego"}, {"id": "d", "text": "Zwany jest czuciowym"}, {"id": "e", "text": "W szczycie znajduje się substantia gelatinosa"}]'::jsonb,
   'b',
   $E$**Róg przedni** istoty szarej zawiera **motoneurony** (komórki ruchowe alfa i gamma) dające początek korzeniom brzusznym — stąd nazwa **róg ruchowy**. Jest **szerszy i krótszy** od rogu tylnego. **Róg tylny** (czuciowy) jest węższy, ma głowę, szyję i podstawę, a w jego szczycie leży **istota galaretowata** (substantia gelatinosa) — opcje A, C, D, E opisują róg tylny. Poprawna B.$E$,
   'rdzeń kręgowy — rogi istoty szarej', 'ANATLEK-200'),
(158, 'ANA-CZA',
   'Z poniżej podanych, przez szczelinę oczodołową górną przechodzi:',
   '[{"id": "a", "text": "Tętnica sitowa przednia"}, {"id": "b", "text": "Nerw okoruchowy"}, {"id": "c", "text": "Nerw żuchwowy"}, {"id": "d", "text": "Zatoka skalista dolna"}, {"id": "e", "text": "Tętnica kręgowa"}]'::jsonb,
   'b',
   $E$Przez **szczelinę oczodołową górną** przechodzą: **nerw okoruchowy (III)**, **bloczkowy (IV)**, gałąź oczna trójdzielnego (**V1**), **odwodzący (VI)** oraz **żyły oczne**. Mnemonik **„Live Frankly To See Absolutely No Insult"** lub kolejność III-IV-V1-VI. Nerw żuchwowy biegnie przez otwór owalny, sitowa przednia przez kanał sitowy, zatoka skalista dolna przez otwór szyjny. Poprawna B.$E$,
   'otwory podstawy czaszki', 'ANATLEK-201'),
(159, 'ANA-TUL',
   'Wskaż twierdzenie fałszywe:',
   '[{"id": "a", "text": "Nerwy przechodzą przez górny otwór klatki piersiowej bocznie do przodu od przełyku"}, {"id": "b", "text": "W płaszczyźnie pośrodkowej tchawica leży bezpośrednio przed przełykiem"}, {"id": "c", "text": "Duże naczynia krwionośne przechodzą przez górny otwór klatki piersiowej do tyłu od przełyku"}, {"id": "d", "text": "Nerwy przechodzą przez górny otwór klatki piersiowej bocznie od tchawicy"}, {"id": "e", "text": "Górna część jamy opłucnej sięga około 2-3 cm powyżej żebra I"}]'::jsonb,
   'c',
   $E$Fałszywe jest C. W otworze górnym **duże naczynia** (pień ramienno-głowowy, tt. szyjne wspólne, ż. ramienno-głowowe) leżą **do przodu** od tchawicy i przełyku, a nie do tyłu. Przełyk leży najbardziej z tyłu, bezpośrednio przed kręgosłupem; tchawica jest przed przełykiem (B prawdziwe). Nerwy (błędne, przeponowe) biegną bocznie. Szczyt opłucnej rzeczywiście wystaje ponad żebro I. Poprawna (fałszywa) C.$E$,
   'otwór górny klatki piersiowej', 'ANATLEK-202'),
(160, 'ANA-OBW',
   'Główną grupą unerwianą przez pętlę szyjną są mięśnie:',
   '[{"id": "a", "text": "Nadgnykowe"}, {"id": "b", "text": "Głębokie szyi"}, {"id": "c", "text": "Pochyłe szyi"}, {"id": "d", "text": "Krtani"}, {"id": "e", "text": "Podgnykowe"}]'::jsonb,
   'e',
   $E$**Pętla szyjna** (ansa cervicalis, C1–C3) unerwia ruchowo **mięśnie podgnykowe**: mostkowo-gnykowy, mostkowo-tarczowy, tarczowo-gnykowy i łopatkowo-gnykowy. Korzeń górny (C1, biegnący z nerwem podjęzykowym) oddaje też gałąź do tarczowo-gnykowego. Mięśnie nadgnykowe unerwiają nerwy czaszkowe (V3, VII), a mięśnie krtani — nerw błędny (X). Poprawna E.$E$,
   'pętla szyjna', 'ANATLEK-203'),
(161, 'ANA-TRZ',
   'Zachyłek klinowo-sitowy znajduje się:',
   '[{"id": "a", "text": "w przewodzie nosowym środkowym"}, {"id": "b", "text": "w przewodzie nosowym dolnym"}, {"id": "c", "text": "w części nosowej gardła"}, {"id": "d", "text": "w przewodzie nosowym górnym"}, {"id": "e", "text": "w przedsionku jamy nosowej"}]'::jsonb,
   'd',
   $E$**Zachyłek klinowo-sitowy** (recessus sphenoethmoidalis) leży **powyżej i ku tyłowi od małżowiny nosowej górnej**, czyli w obrębie **przewodu nosowego górnego** (najwyższej części jamy nosowej). Uchodzi tu **zatoka klinowa**. Dla porównania: do przewodu górnego uchodzą też komórki sitowe tylne, a do środkowego — zatoki czołowa, szczękowa i przednie/środkowe sitowe. Poprawna D.$E$,
   'jama nosowa — ujścia zatok', 'ANATLEK-204'),
(162, 'ANA-CZA',
   'Szczelina oczodołowa dolna zawiera:',
   '[{"id": "a", "text": "nerw wzrokowy"}, {"id": "b", "text": "nerw oczny"}, {"id": "c", "text": "nerw szczękowy"}, {"id": "d", "text": "nerw żuchwowy"}, {"id": "e", "text": "nerw jarzmowy"}]'::jsonb,
   'e',
   $E$Przez **szczelinę oczodołową dolną** przechodzą: **nerw podoczodołowy** (kontynuacja n. szczękowego V2), **nerw jarzmowy** (gałąź V2), gałąź zwoju skrzydłowo-podniebiennego oraz **żyła oczna dolna** i naczynia podoczodołowe. Z wymienionych opcji właściwy jest **nerw jarzmowy**. Nerw wzrokowy biegnie kanałem wzrokowym, nerw oczny (V1) — szczeliną oczodołową górną, żuchwowy nie wchodzi do oczodołu. Poprawna E.$E$,
   'oczodół — szczeliny', 'ANATLEK-205'),
(163, 'ANA-OBW',
   'Które mięśnie są unerwione przez nerw mięśniowo-skórny?',
   '[{"id": "a", "text": "m. ramienny"}, {"id": "b", "text": "m. kruczo-ramienny"}, {"id": "c", "text": "wszystkie mięśnie grupy przedniej ramienia"}, {"id": "d", "text": "m. dwugłowy ramienia"}, {"id": "e", "text": "tylko głowa długa m. dwugłowego ramienia"}]'::jsonb,
   'c',
   $E$**Nerw mięśniowo-skórny** (z pęczka bocznego splotu ramiennego, C5–C7) unerwia **wszystkie mięśnie grupy przedniej (zginaczy) ramienia**: **kruczo-ramienny**, **dwugłowy ramienia** (obie głowy) i **ramienny**. Następnie przebija powięź i jako nerw skórny boczny przedramienia prowadzi czucie. Opcje A, B, D, E wymieniają tylko pojedyncze mięśnie — pełną grupę obejmuje C. Poprawna C.$E$,
   'nerw mięśniowo-skórny', 'ANATLEK-206'),
(164, 'ANA-OUN',
   'Skorupa (łupina) jest to:',
   '[{"id": "a", "text": "część prążkowia"}, {"id": "b", "text": "powierzchowna część ciała migdałowatego"}, {"id": "c", "text": "grzbietowa część śródmózgowia"}, {"id": "d", "text": "jądro położone pomiędzy torebkami: zewnętrzną i ostatnią"}, {"id": "e", "text": "płat kresomózgowia przykryty wieczkami"}]'::jsonb,
   'a',
   $E$**Skorupa** (putamen) wraz z **jądrem ogoniastym** tworzy **prążkowie** (neostriatum) — należące do jąder podstawnych. Skorupa z **gałką bladą** tworzy z kolei **jądro soczewkowate**. Prążkowie odgrywa kluczową rolę w kontroli ruchów (układ pozapiramidowy). Jądrem leżącym między torebką zewnętrzną a ostatnią jest **przedmurze** (claustrum), nie skorupa — co wyklucza D. Poprawna A.$E$,
   'jądra podstawne', 'ANATLEK-207'),
(165, 'ANA-OUN',
   'Wybierz odpowiedź zawierającą jedynie elementy wchodzące w skład kresomózgowia (1 – półkule mózgu, 2 – podwzgórze, 3 – pokrywa, 4 – rdzeń przedłużony, 5 – spoidło sklepienia, 6 – konary mózgu, 7 – wzgórzomózgowie, 8 – spoidło przednie, 9 – ciało modzelowate, 10 – niskowzgórze, 11 – móżdżek, 12 – most):',
   '[{"id": "a", "text": "4, 12"}, {"id": "b", "text": "11, 12"}, {"id": "c", "text": "1, 5, 8, 9"}, {"id": "d", "text": "2, 7, 10"}, {"id": "e", "text": "3, 6"}]'::jsonb,
   'c',
   $E$**Kresomózgowie** (telencephalon) obejmuje **półkule mózgu** wraz ze spoidłami łączącymi je: **spoidło sklepienia (hipokampa)**, **spoidło przednie** i **ciało modzelowate**. Pasują więc 1, 5, 8, 9. Elementy 2, 7, 10 to międzymózgowie; 3, 6 to śródmózgowie; 4, 12 to tyłomózgowie; 11 (móżdżek) — tyłomózgowie wtórne. Poprawna C.$E$,
   'kresomózgowie — podział', 'ANATLEK-208'),
(166, 'ANA-OUN',
   'Wybierz odpowiedź zawierającą jedynie elementy wchodzące w skład tyłomózgowia wtórnego (1 – półkule mózgu, 2 – podwzgórze, 3 – pokrywa, 4 – rdzeń przedłużony, 5 – spoidło sklepienia, 6 – konary mózgu, 7 – wzgórzomózgowie, 8 – spoidło przednie, 9 – ciało modzelowate, 10 – niskowzgórze, 11 – móżdżek, 12 – most):',
   '[{"id": "a", "text": "3, 6"}, {"id": "b", "text": "11, 12"}, {"id": "c", "text": "2, 7, 10"}, {"id": "d", "text": "1, 5, 8, 9"}, {"id": "e", "text": "4, 12"}]'::jsonb,
   'b',
   $E$**Tyłomózgowie wtórne** (metencephalon) obejmuje **most** (12) i **móżdżek** (11). **Rdzeń przedłużony** (4) należy do **rdzeniomózgowia** (myelencephalon). Razem most, móżdżek i rdzeń przedłużony tworzą tyłomózgowie pierwotne (rhombencephalon). Elementy 3 i 6 to śródmózgowie, 2/7/10 — międzymózgowie, 1/5/8/9 — kresomózgowie. Poprawna B (most + móżdżek).$E$,
   'tyłomózgowie wtórne', 'ANATLEK-209'),
(167, 'ANA-TUL',
   'Poprzez zespolenie przełykowe krew z układu wrotnego trafia do:',
   '[{"id": "a", "text": "Wszystkie odpowiedzi prawidłowe"}, {"id": "b", "text": "Żył nieparzystych lub żyły głównej dolnej"}, {"id": "c", "text": "Żyły udowej lub pachowej"}, {"id": "d", "text": "Żyły biodrowej wewnętrznej"}, {"id": "e", "text": "Żył zaotrzewnowych"}]'::jsonb,
   'b',
   $E$**Zespolenie przełykowe** to anastomoza wrotno-układowa w dolnym przełyku: **żyła żołądkowa lewa** (układ wrotny) łączy się z **żyłami przełykowymi** uchodzącymi do **żyły nieparzystej** (układ żyły głównej górnej). W nadciśnieniu wrotnym to zespolenie poszerza się, tworząc groźne **żylaki przełyku**. Krew omija wątrobę i wraca do układu żył głównych przez żyłę nieparzystą. Poprawna B.$E$,
   'zespolenia wrotno-układowe', 'ANATLEK-210'),
(168, 'ANA-OBW',
   'Pień dolny splotu ramiennego powstaje:',
   '[{"id": "a", "text": "z gałęzi grzbietowych C5–C7"}, {"id": "b", "text": "z gałęzi brzusznych C5–C6"}, {"id": "c", "text": "z gałęzi brzusznych C7"}, {"id": "d", "text": "z gałęzi brzusznych C8–Th1"}, {"id": "e", "text": "z gałęzi grzbietowych C8–Th1"}]'::jsonb,
   'd',
   $E$**Splot ramienny** tworzą **gałęzie brzuszne** nerwów rdzeniowych C5–Th1. Łączą się w trzy pnie: **górny** (C5–C6), **środkowy** (C7) i **dolny** (**C8–Th1**). Pień dolny daje początek m.in. nerwowi łokciowemu i przyśrodkowej części pośrodkowego; jego uszkodzenie powoduje porażenie Klumpkego (ręka szponiasta). Gałęzie grzbietowe unerwiają mięśnie grzbietu, nie tworzą splotu. Poprawna D.$E$,
   'splot ramienny', 'ANATLEK-211'),
(169, 'ANA-NAC',
   'Gałęzie końcowe tętnicy szyjnej zewnętrznej odchodzą w:',
   '[{"id": "a", "text": "Przestrzeni przygardłowej"}, {"id": "b", "text": "Dole skroniowym"}, {"id": "c", "text": "Dole skrzydłowo-podniebiennym"}, {"id": "d", "text": "Dole podskroniowym"}, {"id": "e", "text": "Przestrzeni (dole) zażuchwowej"}]'::jsonb,
   'e',
   $E$**Tętnica szyjna zewnętrzna** wnika do **ślinianki przyusznej** w **przestrzeni (dole) zażuchwowej**, gdzie na wysokości szyjki żuchwy dzieli się na **gałęzie końcowe**: **tętnicę skroniową powierzchowną** i **tętnicę szczękową**. Ta druga wnika dalej do dołu podskroniowego, a jej gałąź (t. klinowo-podniebienna) do dołu skrzydłowo-podniebiennego — ale sam podział końcowy następuje zażuchwowo. Poprawna E.$E$,
   'tętnica szyjna zewnętrzna', 'ANATLEK-212'),
(170, 'ANA-NAC',
   'Najsilniejszą gałęzią tętnicy podobojczykowej jest:',
   '[{"id": "a", "text": "T. tarczowa dolna"}, {"id": "b", "text": "T. kręgowa"}, {"id": "c", "text": "T. nadłopatkowa"}, {"id": "d", "text": "T. szyjna głęboka"}, {"id": "e", "text": "Pień tarczowo-szyjny"}]'::jsonb,
   'b',
   $E$**Tętnica kręgowa** to najsilniejsza (najgrubsza) gałąź tętnicy podobojczykowej. Odchodzi jako pierwsza, wstępuje przez otwory wyrostków poprzecznych kręgów szyjnych C6–C1, wchodzi przez otwór wielki i wraz z drugostronną tworzy **tętnicę podstawną**, zaopatrując tylną część mózgowia. Pień tarczowo-szyjny i pozostałe gałęzie są cieńsze. Poprawna B.$E$,
   'tętnica podobojczykowa', 'ANATLEK-213'),
(171, 'ANA-OUN',
   'Skrzyżowanie włókien dróg korowo-rdzeniowych następuje w:',
   '[{"id": "a", "text": "Skrzyżowaniu wstęg"}, {"id": "b", "text": "Głowie rogu tylnego rdzenia"}, {"id": "c", "text": "Skrzyżowaniu piramid"}, {"id": "d", "text": "Brak prawidłowej odpowiedzi"}, {"id": "e", "text": "Spoidle szarym przednim"}]'::jsonb,
   'c',
   $E$Około **80–90%** włókien **drogi korowo-rdzeniowej** krzyżuje się na granicy rdzenia przedłużonego i kręgowego w **skrzyżowaniu piramid** (decussatio pyramidum), tworząc drogę korowo-rdzeniową **boczną**. Pozostałe włókna (droga przednia) krzyżują się dopiero na poziomie segmentu rdzenia. **Skrzyżowanie wstęg** dotyczy drogi czuciowej (sznurów tylnych), nie ruchowej. Poprawna C.$E$,
   'drogi ruchowe', 'ANATLEK-214'),
(172, 'ANA-KON',
   'Unaczynienie kończyn jest zwykle realizowane w postaci schematu:',
   '[{"id": "a", "text": "Sieci tętniczo-żylnych i wrotnych"}, {"id": "b", "text": "Jedna tętnica, jedna żyła"}, {"id": "c", "text": "Dwie żyły, dwie tętnice"}, {"id": "d", "text": "Jedna tętnica, dwie żyły"}, {"id": "e", "text": "Dwie tętnice, jedna żyła"}]'::jsonb,
   'd',
   $E$W kończynach typowym schematem jest **jedna tętnica głęboka** z towarzyszącymi **dwiema żyłami głębokimi** (venae comitantes) biegnącymi po obu jej stronach. Dodatkowo występuje niezależny układ **żył powierzchownych** (np. odpiszczelowa, odłokciowa). Parzyste żyły towarzyszące wspomagają powrót żylny dzięki pulsacji tętnicy. Poprawna D (jedna tętnica, dwie żyły).$E$,
   'schemat naczyniowy kończyn', 'ANATLEK-216'),
(173, 'ANA-TUL',
   'Miejsca osłuchiwania zastawek serca (przy fizjologicznym położeniu) prawidłowo przedstawia odpowiedź:',
   '[{"id": "a", "text": "trójdzielna – mostkowy przyczep lewego żebra III; dwudzielna – mostkowy przyczep lewego żebra IV; pnia płucnego – mostkowy przyczep lewego żebra III; aortalna – linia pośrodkowa przednia na przecięciu z bruzdą wieńcową"}, {"id": "b", "text": "trójdzielna – IV/VI pmż przy linii mostkowej prawej; dwudzielna – V pmż w pobliżu linii środkowo-obojczykowej lewej; pnia płucnego – II pmż przy linii mostkowej lewej; aortalna – II pmż przy linii mostkowej prawej"}, {"id": "c", "text": "trójdzielna – linia środkowo-obojczykowa prawa; dwudzielna – mostkowy przyczep prawego żebra XI; pnia płucnego – mostkowy przyczep lewego żebra I; aortalna – V pmż przy linii środkowo-obojczykowej lewej"}, {"id": "d", "text": "trójdzielna – linia pośrodkowa przednia na bruździe wieńcowej; dwudzielna – mostkowy przyczep lewego żebra IV; pnia płucnego – mostkowy przyczep lewego żebra III; aortalna – linia mostkowa lewa na wysokości III pmż"}, {"id": "e", "text": "trójdzielna – V pmż linia środkowo-obojczykowa lewa; dwudzielna – IV/VI pmż linia mostkowa prawa; pnia płucnego – II pmż linia mostkowa prawa; aortalna – linia mostkowa lewa III pmż"}]'::jsonb,
   'b',
   $E$Klasyczne **miejsca osłuchiwania** (rzut akustyczny, nie anatomiczny): **aortalna** — II pmż przy **prawym** brzegu mostka; **pnia płucnego** — II pmż przy **lewym** brzegu mostka; **trójdzielna** — dół mostka / IV–V pmż przy prawym brzegu; **dwudzielna (mitralna)** — koniuszek serca, V pmż w linii środkowo-obojczykowej lewej. Wszystkie cztery prawidłowo zestawia tylko B. Mnemonik **APTM**: All Patients Take Medicine.$E$,
   'osłuchiwanie zastawek serca', 'ANATLEK-217'),
(174, 'ANA-NER',
   'Unerwienie języka:',
   '[{"id": "a", "text": "Włókna smakowe pochodzą z n. V"}, {"id": "b", "text": "Włókna smakowe pochodzą z n. VII"}, {"id": "c", "text": "Włókna ruchowe prowadzi n. IX"}, {"id": "d", "text": "Włókna czuciowe prowadzi n. szczękowy"}, {"id": "e", "text": "Włókna czuciowe pochodzą z n. podjęzykowego"}]'::jsonb,
   'b',
   $E$**Smak** przedniej 2/3 języka prowadzą włókna **nerwu twarzowego (VII)** drogą **struny bębenkowej** (ciała komórek w zwoju kolanka). Czucie ogólne przedniej 2/3 — n. językowy (V3), tylnej 1/3 (smak i czucie) — n. językowo-gardłowy (IX). **Ruch** języka to wyłącznie n. podjęzykowy (XII), więc C i E błędne; czucie prowadzi V3 (żuchwowy), nie szczękowy (D błędne). Poprawna B.$E$,
   'unerwienie języka', 'ANATLEK-218'),
(175, 'ANA-CZA',
   'W kanale wzrokowym, poza nerwem wzrokowym, przebiega:',
   '[{"id": "a", "text": "Nerw oczny"}, {"id": "b", "text": "Żyła oczna górna"}, {"id": "c", "text": "Nerw okoruchowy"}, {"id": "d", "text": "Nerw bloczkowy"}, {"id": "e", "text": "Tętnica oczna"}]'::jsonb,
   'e',
   $E$Przez **kanał wzrokowy** kości klinowej przechodzą **nerw wzrokowy (II)** oraz **tętnica oczna** (pierwsza wewnątrzczaszkowa gałąź t. szyjnej wewnętrznej). Nerwy okoruchowy, bloczkowy, oczny (V1) i odwodzący oraz żyły oczne biegną przez **szczelinę oczodołową górną** — nie przez kanał wzrokowy. Poprawna E.$E$,
   'oczodół — kanał wzrokowy', 'ANATLEK-219'),
(176, 'ANA-KON',
   'Wyniosłość łokciową nadgarstka tworzy/tworzą:',
   '[{"id": "a", "text": "Wyrostek rylcowaty kości łokciowej"}, {"id": "b", "text": "Kość grochowata i haczyk kości haczykowatej"}, {"id": "c", "text": "Guzek kości łódeczkowatej i guzek kości czworobocznej większej"}, {"id": "d", "text": "Haczyk kości haczykowatej i guzek kości czworobocznej większej"}, {"id": "e", "text": "Haczyk kości haczykowatej i guzek kości łódeczkowatej"}]'::jsonb,
   'b',
   $E$**Wyniosłość łokciową nadgarstka** (eminentia carpi ulnaris) tworzą **kość grochowata** i **haczyk kości haczykowatej** — po stronie przyśrodkowej (łokciowej). **Wyniosłość promieniową** tworzą **guzek kości łódeczkowatej** i **guzek kości czworobocznej większej**. Między nimi rozpięty jest troczek zginaczy, zamykając kanał nadgarstka. Poprawna B.$E$,
   'kości nadgarstka', 'ANATLEK-220'),
(177, 'ANA-OBW',
   'Nerw uszny wielki jest nerwem:',
   '[{"id": "a", "text": "Czuciowym"}, {"id": "b", "text": "Czuciowym i ruchowym"}, {"id": "c", "text": "Ruchowym"}, {"id": "d", "text": "Czuciowym i autonomicznym"}, {"id": "e", "text": "Autonomicznym"}]'::jsonb,
   'a',
   $E$**Nerw uszny wielki** (C2–C3) to gałąź skórna **splotu szyjnego** — jest nerwem czysto **czuciowym**. Zaopatruje skórę małżowiny usznej, okolicy zażuchwowej i nad ślinanką przyuszną. Wszystkie gałęzie skórne splotu szyjnego (uszny wielki, potyliczny mniejszy, poprzeczny szyi, nadobojczykowe) są czuciowe; gałęzie ruchowe splotu tworzą m.in. pętlę szyjną i nerw przeponowy. Poprawna A.$E$,
   'splot szyjny', 'ANATLEK-221'),
(178, 'ANA-TRZ',
   'Różnicą pomiędzy jelitem czczym a krętym nie jest:',
   '[{"id": "a", "text": "Grubsza ściana i lepiej zaznaczone fałdy okrężne w jelicie czczym"}, {"id": "b", "text": "Mniejsze światło w jelicie krętym"}, {"id": "c", "text": "Lepsze ukrwienie jelita czczego"}, {"id": "d", "text": "Wszystkie powyższe to różnice pomiędzy jelitem czczym a krętym"}, {"id": "e", "text": "Obecność skupisk grudek chłonnych w jelicie krętym"}]'::jsonb,
   'd',
   $E$**Jelito czcze** ma grubszą ścianę, liczniejsze i wyższe **fałdy okrężne**, szersze światło i obfitsze ukrwienie (mniej arkad, dłuższe naczynia proste). **Jelito kręte** ma węższe światło, słabsze fałdy, więcej arkad naczyniowych i charakterystyczne **kępki Peyera** (grudki chłonne). Wszystkie wymienione (A, B, C, E) są więc rzeczywistymi różnicami — stąd odpowiedź „wszystkie powyższe to różnice". Poprawna D.$E$,
   'jelito cienkie', 'ANATLEK-222'),
(179, 'ANA-KON',
   'Teoretyczny zakres ruchów w tym stawie zbliżony jest do kulistego, ale praktycznie przypomina staw płaski. Ma krążek stawowy dzielący jamę na piętro górno-boczne i dolno-przyśrodkowe, wzmacniają go silne więzadła. O jakim stawie mowa?',
   '[{"id": "a", "text": "Staw promieniowo-nadgarstkowy"}, {"id": "b", "text": "Staw ramienny"}, {"id": "c", "text": "Staw kolanowy"}, {"id": "d", "text": "Staw mostkowo-obojczykowy"}, {"id": "e", "text": "Staw łokciowy"}]'::jsonb,
   'd',
   $E$**Staw mostkowo-obojczykowy** to jedyne połączenie maziowe obręczy barkowej ze szkieletem osiowym. Zawiera **krążek stawowy** dzielący jamę na dwa piętra, co czyni go funkcjonalnie **siodełkowatym/kulistym** o ograniczonym zakresie (praktycznie jak płaski). Wzmacniają go więzadła mostkowo-obojczykowe i żebrowo-obojczykowe. Krążek amortyzuje i zwiększa zborność. Poprawna D.$E$,
   'staw mostkowo-obojczykowy', 'ANATLEK-223'),
(180, 'ANA-NER',
   'Z którego nerwu czaszkowego włókna autonomiczne przedzwojowe otrzymuje zwój rzęskowy?',
   '[{"id": "a", "text": "III"}, {"id": "b", "text": "VII"}, {"id": "c", "text": "X"}, {"id": "d", "text": "V"}, {"id": "e", "text": "IX"}]'::jsonb,
   'a',
   $E$**Zwój rzęskowy** otrzymuje przedzwojowe włókna **przywspółczulne** z **nerwu okoruchowego (III)** (z jądra Edingera-Westphala, drogą gałęzi do mięśnia dźwigacza/skośnego dolnego). Włókna zazwojowe (nerwy rzęskowe krótkie) unerwiają **zwieracz źrenicy** i **mięsień rzęskowy**. Pozostałe zwoje głowy: skrzydłowo-podniebienny i podżuchwowy — z VII, uszny — z IX. Poprawna A.$E$,
   'zwoje przywspółczulne głowy', 'ANATLEK-224'),
(181, 'ANA-OBW',
   '„Ręka błogosławiąca" i „ręka małpia" występują w przebiegu porażenia nerwu:',
   '[{"id": "a", "text": "Promieniowego"}, {"id": "b", "text": "Mięśniowo-skórnego"}, {"id": "c", "text": "Pachowego"}, {"id": "d", "text": "Pośrodkowego"}, {"id": "e", "text": "Łokciowego"}]'::jsonb,
   'd',
   $E$Uszkodzenie **nerwu pośrodkowego** daje obraz **„ręki błogosławiącej"** (przy próbie zaciśnięcia pięści nie zginają się palce I–III z powodu porażenia zginaczy) oraz **„ręki małpiej"** (zanik kłębu i przywiedzenie kciuka — utrata przeciwstawiania). Nerw łokciowy daje „rękę szponiastą", promieniowy „rękę opadającą". Poprawna D. Pośrodkowy unerwia kłąb i większość zginaczy przedramienia.$E$,
   'nerw pośrodkowy', 'ANATLEK-225'),
(182, 'ANA-KON',
   'Wcięcie łopatki zamykane jest przez:',
   '[{"id": "a", "text": "Więzadło kruczo-barkowe"}, {"id": "b", "text": "Więzadło poprzeczne łopatki dolne"}, {"id": "c", "text": "Więzadło poprzeczne łopatki górne"}, {"id": "d", "text": "Więzadło kruczo-ramienne"}, {"id": "e", "text": "Brak prawidłowej odpowiedzi"}]'::jsonb,
   'c',
   $E$**Wcięcie łopatki** (incisura scapulae) na brzegu górnym zamyka **więzadło poprzeczne łopatki górne**, przekształcając je w otwór. Pod więzadłem przechodzi **nerw nadłopatkowy**, a nad nim **naczynia nadłopatkowe** (mnemonik: „Army over the bridge, Navy under the bridge" — nerw pod więzadłem). Może ono kostnieć, uciskając nerw (neuropatia z uwięźnięcia). Poprawna C.$E$,
   'łopatka — więzadła', 'ANATLEK-226'),
(183, 'ANA-TUL',
   'Zastawka przedsionkowo-komorowa prawa jest:',
   '[{"id": "a", "text": "zastawką trójdzielną"}, {"id": "b", "text": "zastawką pnia płucnego"}, {"id": "c", "text": "zastawką dwudzielną"}, {"id": "d", "text": "pozostałością krążenia płodowego"}, {"id": "e", "text": "zastawką aorty"}]'::jsonb,
   'a',
   $E$**Zastawka przedsionkowo-komorowa prawa** to **zastawka trójdzielna** (valva tricuspidalis) — ma trzy płatki: przedni, tylny i przegrodowy. Oddziela przedsionek prawy od komory prawej, zapobiegając cofaniu krwi podczas skurczu. Po stronie lewej znajduje się zastawka **dwudzielna (mitralna)**. Zastawki pnia płucnego i aorty to zastawki półksiężycowate (tętnicze), nie przedsionkowo-komorowe. Poprawna A.$E$,
   'zastawki serca', 'ANATLEK-227'),
(184, 'ANA-TUL',
   'Układ wrotny to układ naczyniowy:',
   '[{"id": "a", "text": "Żylno-żylny"}, {"id": "b", "text": "Żylno-tętniczy"}, {"id": "c", "text": "Tętniczo-tętniczy"}, {"id": "d", "text": "Naczyń włosowatych"}, {"id": "e", "text": "Naczyń chłonnych"}]'::jsonb,
   'a',
   $E$**Układ wrotny** to taki, w którym między dwiema sieciami **naczyń włosowatych** znajduje się naczynie żylne — krew płynie „od żył do żył". W żyle wrotnej wątroby krew z sieci kapilar przewodu pokarmowego (żołądek, jelita, śledziona, trzustka) trafia do **drugiej sieci** zatok wątrobowych, zanim wróci do serca. To umożliwia wątrobie metabolizm wchłoniętych substancji. Stąd układ **żylno-żylny**. Poprawna A.$E$,
   'układ wrotny', 'ANATLEK-228'),
(185, 'ANA-TRZ',
   'Więzadło podstawowe (kardynalne) stanowi rusztowanie dla:',
   '[{"id": "a", "text": "Więzadła wieszadłowego jajnika"}, {"id": "b", "text": "Więzadła obłego macicy"}, {"id": "c", "text": "Więzadła szerokiego macicy"}, {"id": "d", "text": "Więzadła łonowo-sterczowego"}, {"id": "e", "text": "Więzadła odbytniczo-macicznego"}]'::jsonb,
   'c',
   $E$**Więzadło podstawowe (kardynalne, poprzeczne szyjki macicy)** to zagęszczenie tkanki łącznej u podstawy **więzadła szerokiego macicy**, biegnące od szyjki i sklepienia pochwy do ścian bocznych miednicy. Stanowi główne **rusztowanie podtrzymujące macicę** i prowadzi naczynia maciczne. Więzadło szerokie to fałd otrzewnej, którego dolną, zagęszczoną podstawę tworzy właśnie więzadło kardynalne. Poprawna C.$E$,
   'aparat więzadłowy macicy', 'ANATLEK-229'),
(186, 'ANA-OUN',
   'Komora III układu komorowego mózgu otoczona jest przez:',
   '[{"id": "a", "text": "Tyłomózgowie"}, {"id": "b", "text": "Międzymózgowie"}, {"id": "c", "text": "Kresomózgowie"}, {"id": "d", "text": "Rdzeniomózgowie"}, {"id": "e", "text": "Śródmózgowie"}]'::jsonb,
   'b',
   $E$**Komora trzecia** to wąska szczelinowata jama leżąca w linii pośrodkowej, otoczona przez struktury **międzymózgowia** — jej ściany boczne tworzą **wzgórza**, a dno **podwzgórze**. Łączy się z komorami bocznymi przez otwory międzykomorowe (Monroego) i z komorą czwartą przez **wodociąg mózgu**. Komory boczne leżą w kresomózgowiu, komora czwarta w tyłomózgowiu. Poprawna B.$E$,
   'układ komorowy', 'ANATLEK-230'),
(187, 'ANA-TUL',
   'Unaczynienie żylne wielu narządów jamy brzusznej i miednicy ma postać:',
   '[{"id": "a", "text": "Żadna odpowiedź nie jest prawidłowa"}, {"id": "b", "text": "Zasady jeden narząd – jedna żyła"}, {"id": "c", "text": "Splotów"}, {"id": "d", "text": "Pojedynczych dopływów"}, {"id": "e", "text": "Sieci wrotnej"}]'::jsonb,
   'c',
   $E$Wiele narządów miednicy i jamy brzusznej (zwłaszcza miednicy) otacza obfite **sploty żylne**: pęcherzowy, sterczowy, maciczno-pochwowy, odbytniczy. Taka budowa zapewnia sprawny odpływ krwi przy zmiennym wypełnieniu narządów i przy uciskach. Sploty te uchodzą głównie do żyły biodrowej wewnętrznej, a część (np. odbytnicze) tworzy zespolenia wrotno-układowe. Poprawna C (sploty).$E$,
   'unaczynienie żylne trzewi', 'ANATLEK-231'),
(188, 'ANA-OUN',
   'Struktury tworzące brzuszną część rdzenia przedłużonego to:',
   '[{"id": "a", "text": "Piramidy"}, {"id": "b", "text": "Oliwki"}, {"id": "c", "text": "Rogi tylne"}, {"id": "d", "text": "Rogi przednie"}, {"id": "e", "text": "Pęczek smukły i klinowaty"}]'::jsonb,
   'a',
   $E$**Piramidy** (pyramides) to dwa podłużne wyniosłości na **brzusznej (przedniej) powierzchni** rdzenia przedłużonego, utworzone przez zstępujące włókna **dróg korowo-rdzeniowych**; u ich dołu zachodzi **skrzyżowanie piramid**. **Oliwki** leżą bocznie od piramid. Pęczki smukły i klinowaty znajdują się na powierzchni **grzbietowej**. Rogi to struktury istoty szarej rdzenia kręgowego. Poprawna A.$E$,
   'rdzeń przedłużony', 'ANATLEK-232'),
(189, 'ANA-KON',
   'Która odpowiedź przedstawia mięsień warstwy II grupy przedniej przedramienia? (I – zginacz łokciowy nadgarstka, II – dłoniowy długi, III – nawrotny czworoboczny, IV – zginacz długi kciuka, V – zginacz głęboki palców, VI – zginacz powierzchowny palców, VII – zginacz promieniowy nadgarstka, VIII – nawrotny obły)',
   '[{"id": "a", "text": "VI"}, {"id": "b", "text": "II, V"}, {"id": "c", "text": "I, II, VII, VIII"}, {"id": "d", "text": "III"}, {"id": "e", "text": "IV, V"}]'::jsonb,
   'a',
   $E$Grupa przednia (zginaczy) przedramienia ma **cztery warstwy**: I (powierzchowna) — nawrotny obły, zginacz promieniowy nadgarstka, dłoniowy długi, zginacz łokciowy nadgarstka; **II — zginacz powierzchowny palców (VI)**; III — zginacz głęboki palców i zginacz długi kciuka; IV (najgłębsza) — nawrotny czworoboczny. Zginacz powierzchowny palców stanowi samodzielną warstwę środkową. Poprawna A (VI).$E$,
   'mięśnie przedramienia', 'ANATLEK-233'),
(190, 'ANA-TUL',
   'Żyła główna dolna, przechodząc przez przeponę, wchodzi do śródpiersia na poziomie trzonu kręgu:',
   '[{"id": "a", "text": "Th12"}, {"id": "b", "text": "Th8"}, {"id": "c", "text": "C6"}, {"id": "d", "text": "Th10"}, {"id": "e", "text": "C7"}]'::jsonb,
   'b',
   $E$**Żyła główna dolna** przechodzi przez **otwór żyły głównej** w części ścięgnistej przepony na poziomie **Th8**. Mnemonik otworów przepony: **T8 – żyła główna dolna** (Vena cava), **T10 – przełyk** (Esophagus, + nn. błędne), **T12 – aorta** (+ przewód piersiowy i żyła nieparzysta). Liczby parzyste idą w górę: 8-10-12. Poprawna B.$E$,
   'przepona — otwory', 'ANATLEK-234'),
(191, 'ANA-OBW',
   'Za zginanie w stawie łokciowym odpowiedzialne są mięśnie unerwiane przez nerw pochodzący z korzenia:',
   '[{"id": "a", "text": "C8"}, {"id": "b", "text": "C4"}, {"id": "c", "text": "Th1"}, {"id": "d", "text": "C7"}, {"id": "e", "text": "C6"}]'::jsonb,
   'e',
   $E$**Zginanie w stawie łokciowym** (m. dwugłowy ramienia, ramienny — przez nerw mięśniowo-skórny) zależy głównie od korzeni **C5–C6**, z dominacją **C6**. Odruch z mięśnia dwugłowego bada poziom **C6**. Prostowanie łokcia (triceps, nerw promieniowy) to **C7**. Mnemonik korzeni: C5–C6 zginanie łokcia, C7 prostowanie. Poprawna E (C6).$E$,
   'unerwienie segmentowe kończyny górnej', 'ANATLEK-235'),
(192, 'ANA-NER',
   'Gałęzie sercowe przywspółczulne odchodzą od:',
   '[{"id": "a", "text": "Z nerwów sercowych szyjnych i piersiowych (współczulnych)"}, {"id": "b", "text": "Nerwu krtaniowego wstecznego"}, {"id": "c", "text": "Części szyjnej i piersiowej nerwu błędnego"}, {"id": "d", "text": "Części szyjnej nerwu błędnego"}, {"id": "e", "text": "Części piersiowej nerwu błędnego"}]'::jsonb,
   'c',
   $E$Przywspółczulne **gałęzie sercowe** (zwalniające rytm) odchodzą od **nerwu błędnego (X)** zarówno w jego **części szyjnej** (gałęzie sercowe górne), jak i **piersiowej** (gałęzie sercowe dolne) i dochodzą do splotu sercowego. Współczulne gałęzie sercowe (przyspieszające) pochodzą z pnia współczulnego (nerwy sercowe szyjne i piersiowe — opcja A). Poprawna C.$E$,
   'nerw błędny — gałęzie sercowe', 'ANATLEK-237'),
(193, 'ANA-MIE',
   'Unoszenie żuchwy w stawie skroniowo-żuchwowym wywołują:',
   '[{"id": "a", "text": "Mm. skrzydłowe boczne"}, {"id": "b", "text": "Mm. nadgnykowe"}, {"id": "c", "text": "Mm. podgnykowe"}, {"id": "d", "text": "Mm. żwacze"}, {"id": "e", "text": "Poziome włókna mm. skroniowych"}]'::jsonb,
   'd',
   $E$**Unoszenie (przywodzenie) żuchwy** — zamykanie ust — wykonują główne mięśnie żucia: **żwacz**, **skroniowy** (włókna pionowe) i **skrzydłowy przyśrodkowy**. Wśród opcji prawidłowe są **żwacze** (D). Mięsień skrzydłowy **boczny** opuszcza i wysuwa żuchwę (A błędne), a **poziome włókna skroniowego** cofają żuchwę (E błędne). Mięśnie nad- i podgnykowe obniżają żuchwę. Poprawna D.$E$,
   'mięśnie żucia', 'ANATLEK-239'),
(194, 'ANA-OUN',
   'Płatem kresomózgowia niewidocznym z zewnątrz, przysłoniętym przez pozostałe płaty, jest:',
   '[{"id": "a", "text": "Płat wyspowy"}, {"id": "b", "text": "Płat ciemieniowy"}, {"id": "c", "text": "Płat skroniowy"}, {"id": "d", "text": "Płat potyliczny"}, {"id": "e", "text": "Płat czołowy"}]'::jsonb,
   'a',
   $E$**Płat wyspowy (wyspa, insula)** leży ukryty w głębi **bruzdy bocznej (Sylwiusza)**, przykryty przez **wieczka** płatów czołowego, ciemieniowego i skroniowego — dlatego nie jest widoczny na powierzchni mózgu bez rozchylenia bruzdy. Uczestniczy m.in. w przetwarzaniu smaku, czucia trzewnego i emocji. Pozostałe płaty (czołowy, ciemieniowy, skroniowy, potyliczny) są widoczne z zewnątrz. Poprawna A.$E$,
   'płaty kresomózgowia', 'ANATLEK-240'),
(195, 'ANA-KON',
   'Wskaż element, który nie bierze udziału w tworzeniu sklepienia stawu ramiennego:',
   '[{"id": "a", "text": "Wyrostek kruczy"}, {"id": "b", "text": "Powięź ponadramienna"}, {"id": "c", "text": "Wszystkie powyższe elementy wchodzą w skład sklepienia stawu ramiennego"}, {"id": "d", "text": "Więzadło kruczo-barkowe"}, {"id": "e", "text": "Wyrostek barkowy"}]'::jsonb,
   'c',
   $E$**Sklepienie stawu ramiennego (więzozrost barkowo-kruczy)** tworzy łuk kostno-więzadłowy nad głową kości ramiennej, chroniąc ją od góry. W jego skład wchodzą: **wyrostek barkowy** i **wyrostek kruczy** łopatki oraz rozpięte między nimi **więzadło kruczo-barkowe**. Strop dopełnia **powięź ponadramienna** zamykająca przestrzeń podbarkową. Wszystkie wymienione struktury należą zatem do sklepienia, dlatego prawidłowa jest odpowiedź zbiorcza. Pod łukiem przebiega ścięgno mięśnia nadgrzebieniowego i kaletka podbarkowa.$E$,
   'Staw ramienny', 'ANATLEK-241'),
(196, 'ANA-NAC',
   'Gałęziami końcowymi tętnicy szyjnej zewnętrznej są:',
   '[{"id": "a", "text": "Tętnica skroniowa powierzchowna i tętnica twarzowa"}, {"id": "b", "text": "Tętnica twarzowa"}, {"id": "c", "text": "Wszystkie prawidłowe"}, {"id": "d", "text": "Tętnica szczękowa"}, {"id": "e", "text": "Tętnica skroniowa powierzchowna"}]'::jsonb,
   'a',
   $E$Tętnica szyjna zewnętrzna w obrębie ślinianki przyusznej dzieli się na dwie **gałęzie końcowe**: tętnicę **skroniową powierzchowną** oraz tętnicę **szczękową**. Tętnica twarzowa jest gałęzią przednią (boczną), a nie końcową. Żadna z opcji nie zestawia prawidłowo skroniowej powierzchownej ze szczękową, więc$E$,
   'Tętnica szyjna zewnętrzna', 'ANATLEK-242'),
(197, 'ANA-TUL',
   'Cieśń aorty leży pomiędzy:',
   '[{"id": "a", "text": "Aortą wstępującą i łukiem aorty"}, {"id": "b", "text": "Tętnicą szyjną wspólną lewą i tętnicą podobojczykową prawą"}, {"id": "c", "text": "Tętnicą podobojczykową lewą a więzadłem tętniczym"}, {"id": "d", "text": "Tętnicą wieńcową lewą i tętnicą wieńcową prawą"}, {"id": "e", "text": "Aortą piersiową i aortą brzuszną"}]'::jsonb,
   'c',
   $E$**Cieśń aorty (isthmus aortae)** to fizjologiczne zwężenie na granicy łuku i części zstępującej aorty, zlokalizowane między odejściem **lewej tętnicy podobojczykowej** a przyczepem **więzadła tętniczego** (pozostałość przewodu tętniczego Botalla). Jest to typowe miejsce koarktacji aorty oraz urazowego pęknięcia przy gwałtownym hamowaniu. Tuż za cieśnią aorta przechodzi w część zstępującą i przylega do kręgosłupa piersiowego.$E$,
   'Aorta piersiowa', 'ANATLEK-243'),
(198, 'ANA-OUN',
   'Z którą częścią mózgu utrzymują połączenia struktury układu limbicznego?',
   '[{"id": "a", "text": "Korą czołową"}, {"id": "b", "text": "Podwzgórzem"}, {"id": "c", "text": "Rdzeniem przedłużonym"}, {"id": "d", "text": "Mostem"}, {"id": "e", "text": "Robakiem móżdżku"}]'::jsonb,
   'b',
   $E$**Układ limbiczny** (hipokamp, ciało migdałowate, zakręt obręczy, sklepienie, ciała suteczkowate) ściśle współpracuje z **podwzgórzem**, które stanowi jego główny ośrodek wykonawczy dla reakcji emocjonalnych, autonomicznych i hormonalnych. Kluczowym połączeniem jest pęczek sklepienia biegnący od hipokampa do ciał suteczkowatych, a stąd dalej do jąder przednich wzgórza (obwód Papeza). Dzięki temu emocje przekładają się na odpowiedzi wegetatywne i endokrynne organizmu.$E$,
   'Układ limbiczny', 'ANATLEK-244'),
(199, 'ANA-OUN',
   'Komora boczna łączy się z komorą trzecią:',
   '[{"id": "a", "text": "szczeliną naczyniówkową"}, {"id": "b", "text": "nie łączy się bezpośrednio"}, {"id": "c", "text": "otworem międzykomorowym"}, {"id": "d", "text": "bruzdą podwzgórzową"}, {"id": "e", "text": "wodociągiem mózgu"}]'::jsonb,
   'c',
   $E$Każda **komora boczna** komunikuje się z nieparzystą **komorą trzecią** przez **otwór międzykomorowy (Monroego)**. Tędy płynie płyn mózgowo-rdzeniowy produkowany przez sploty naczyniówkowe komór bocznych. Komora trzecia łączy się następnie z komorą czwartą poprzez wodociąg mózgu (Sylwiusza). Niedrożność otworu Monroego prowadzi do jednostronnego wodogłowia komory bocznej po stronie zablokowania.$E$,
   'Układ komorowy mózgowia', 'ANATLEK-245'),
(200, 'ANA-TUL',
   'Zatoka wieńcowa jest to:',
   '[{"id": "a", "text": "miejsce odejścia tętnic wieńcowych"}, {"id": "b", "text": "bruzda pomiędzy przedsionkami i komorami na powierzchni serca"}, {"id": "c", "text": "inna nazwa zatoki aorty"}, {"id": "d", "text": "żyła zbierająca krew ze ścian serca"}, {"id": "e", "text": "zachyłek jamy surowiczej osierdzia pomiędzy tętnicami wieńcowymi"}]'::jsonb,
   'd',
   $E$**Zatoka wieńcowa** to główne naczynie żylne serca — szeroki pień zbierający odtlenowaną krew ze ścian serca, leżący w **bruździe wieńcowej** na powierzchni przeponowej. Uchodzi do **prawego przedsionka** między ujściem żyły głównej dolnej a otworem przedsionkowo-komorowym prawym, a jej ujście osłania zastawka zatoki wieńcowej (Tebezjusza). Zbiera m.in. żyłę wielką, średnią i małą serca.$E$,
   'Serce — układ żylny', 'ANATLEK-246'),
(201, 'ANA-TRZ',
   'Krtań leży zwykle na wysokości następujących kręgów:',
   '[{"id": "a", "text": "C3-C7"}, {"id": "b", "text": "C5-C7"}, {"id": "c", "text": "C4-C6"}, {"id": "d", "text": "C1-C3"}, {"id": "e", "text": "C7-Th2"}]'::jsonb,
   'c',
   $E$U dorosłego **krtań** położona jest zwykle na wysokości kręgów **C4–C6**. Chrząstka tarczowata odpowiada mniej więcej poziomowi C5, a dolny brzeg chrząstki pierścieniowatej — granicy C6, gdzie krtań przechodzi w tchawicę i gdzie gardło przechodzi w przełyk. U dzieci krtań leży wyżej, a wraz z wiekiem stopniowo się obniża, co ma znaczenie przy intubacji.$E$,
   'Krtań — topografia', 'ANATLEK-247'),
(202, 'ANA-KON',
   'Nieprawdą jest, że żyła odłokciowa:',
   '[{"id": "a", "text": "łączy się z żyłą pośrodkową łokcia"}, {"id": "b", "text": "odchodzi od sieci żylnej grzbietowej ręki po stronie łokciowej"}, {"id": "c", "text": "ku górze biegnie po stronie tylnej przedramienia"}, {"id": "d", "text": "układa się w bruździe przyśrodkowej m. dwugłowego ramienia"}, {"id": "e", "text": "uchodzi do żyły pachowej"}]'::jsonb,
   'e',
   $E$**Żyła odłokciowa (v. basilica)** rozpoczyna się po stronie łokciowej sieci grzbietowej ręki, biegnie ku górze i w okolicy łokcia łączy się z żyłą pośrodkową łokcia, następnie układa się w bruździe przyśrodkowej mięśnia dwugłowego. Na ramieniu przebija powięź i wpada do **żyły ramiennej** (lub bezpośrednio tworzy żyłę pachową), nie zaś samodzielnie do żyły pachowej w opisanym ujęciu — dlatego zdanie E jest nieprawdziwe i stanowi odpowiedź.$E$,
   'Żyły powierzchowne kończyny górnej', 'ANATLEK-248'),
(203, 'ANA-NAC',
   'Głównym spływem żylnym głowy i szyi jest:',
   '[{"id": "a", "text": "Żyła twarzowa"}, {"id": "b", "text": "Żyła skroniowa"}, {"id": "c", "text": "Żyła głowowa"}, {"id": "d", "text": "Żyła szyjna wewnętrzna"}, {"id": "e", "text": "Żyła szyjna zewnętrzna"}]'::jsonb,
   'd',
   $E$**Żyła szyjna wewnętrzna** jest głównym naczyniem odprowadzającym krew z głowy i szyi. Stanowi bezpośrednie przedłużenie zatoki esowatej opony twardej, odbierając krew z mózgowia, twarzy i szyi. Biegnie w pochewce naczyniowej szyi wraz z tętnicą szyjną wspólną i nerwem błędnym, a u podstawy szyi łączy się z żyłą podobojczykową, tworząc żyłę ramienno-głowową. Żyła szyjna zewnętrzna odprowadza krew z powierzchownych części głowy.$E$,
   'Odpływ żylny głowy i szyi', 'ANATLEK-249'),
(204, 'ANA-KON',
   'Na guzku większym kości ramiennej przyczep końcowy posiada/posiadają:',
   '[{"id": "a", "text": "Mięsień nadgrzebieniowy i mięsień obły mniejszy"}, {"id": "b", "text": "Mięsień obły mniejszy"}, {"id": "c", "text": "Mięsień podgrzebieniowy"}, {"id": "d", "text": "Mięsień nadgrzebieniowy"}, {"id": "e", "text": "Mięsień nadgrzebieniowy i mięsień podgrzebieniowy"}]'::jsonb,
   'e',
   $E$**Guzek większy kości ramiennej** ma trzy pola przyczepowe dla mięśni stożka rotatorów: górne dla **mięśnia nadgrzebieniowego**, środkowe dla **mięśnia podgrzebieniowego** i dolne dla mięśnia obłego mniejszego. Spośród podanych opcji właściwą parą obejmującą przyczepy na guzku większym jest nadgrzebieniowy z podgrzebieniowym. Mięsień podłopatkowy przyczepia się odmiennie — do guzka mniejszego.$E$,
   'Mięśnie stożka rotatorów', 'ANATLEK-250'),
(205, 'ANA-KON',
   'Na której powierzchni kości ramiennej znajduje się bruzda dla nerwu promieniowego?',
   '[{"id": "a", "text": "Przyśrodkowej"}, {"id": "b", "text": "Na głowie"}, {"id": "c", "text": "Tylnej"}, {"id": "d", "text": "Przedniej"}, {"id": "e", "text": "Bocznej"}]'::jsonb,
   'c',
   $E$**Bruzda nerwu promieniowego (bruzda spiralna)** przebiega skośnie po **tylnej** powierzchni trzonu kości ramiennej, kierując się z góry i przyśrodkowo ku dołowi i bocznie. Biegnie w niej nerw promieniowy wraz z tętnicą głęboką ramienia. Ze względu na bezpośrednie przyleganie nerwu do kości złamania trzonu w tej okolicy często powikłane są porażeniem nerwu promieniowego (opadająca ręka).$E$,
   'Kość ramienna — topografia nerwu promieniowego', 'ANATLEK-251'),
(206, 'ANA-TUL',
   'Z poniższych odpowiedzi wybierz odpowiedź zawierającą struktury unaczyniane jedynie przez lewą tętnicę wieńcową:',
   '[{"id": "a", "text": "Prawy przedsionek serca"}, {"id": "b", "text": "Mięsień brodawkowaty przedni komory prawej serca"}, {"id": "c", "text": "Łuk aorty"}, {"id": "d", "text": "Brak prawidłowej odpowiedzi"}, {"id": "e", "text": "Ściana przednia lewej komory serca"}]'::jsonb,
   'e',
   $E$**Lewa tętnica wieńcowa** poprzez gałąź międzykomorową przednią (LAD) i gałąź okalającą zaopatruje głównie lewą komorę, w tym jej **ścianę przednią**, większość przegrody międzykomorowej oraz koniuszek. Prawy przedsionek i ściany prawej komory unaczynia tętnica wieńcowa prawa, a łuk aorty nie należy do obszaru wieńcowego. Spośród wymienionych tylko ściana przednia lewej komory jest domeną wyłącznie lewej tętnicy wieńcowej.$E$,
   'Unaczynienie tętnicze serca', 'ANATLEK-252'),
(207, 'ANA-NER',
   'Nerw odwodzący unerwia:',
   '[{"id": "a", "text": "Mięsień prosty dolny (gałki ocznej)"}, {"id": "b", "text": "Mięsień skośny górny (gałki ocznej)"}, {"id": "c", "text": "Mięsień prosty górny (gałki ocznej)"}, {"id": "d", "text": "Mięsień prosty boczny (gałki ocznej)"}, {"id": "e", "text": "Mięsień skośny dolny (gałki ocznej)"}]'::jsonb,
   'd',
   $E$**Nerw odwodzący (VI)** unerwia ruchowo wyłącznie **mięsień prosty boczny** gałki ocznej, odpowiadający za odwodzenie (ruch oka na zewnątrz). Jego uszkodzenie powoduje zeza zbieżnego i podwójne widzenie przy patrzeniu w bok. Mięsień skośny górny zaopatruje nerw bloczkowy (IV), a pozostałe mięśnie zewnątrzgałkowe — nerw okoruchowy (III). Reguła LR6SO4: prosty boczny — VI, skośny górny — IV, reszta — III.$E$,
   'Nerw odwodzący (VI)', 'ANATLEK-253'),
(208, 'ANA-TRZ',
   'Która z małżowin nosowych nie występuje u człowieka?',
   '[{"id": "a", "text": "Wszystkie z podanych występują u człowieka"}, {"id": "b", "text": "Środkowa"}, {"id": "c", "text": "Najwyższa"}, {"id": "d", "text": "Dolna"}, {"id": "e", "text": "Górna"}]'::jsonb,
   'a',
   $E$W jamie nosowej człowieka stale obecne są trzy małżowiny: **dolna** (samodzielna kość), **środkowa** i **górna** (wyrostki kości sitowej). U części osób występuje dodatkowo niewielka **małżowina najwyższa (Santoriniego)** ponad małżowiną górną. Wszystkie wymienione w pytaniu małżowiny mogą zatem występować u człowieka, dlatego prawidłowa jest odpowiedź zbiorcza. Pod każdą małżowiną znajduje się odpowiadający jej przewód nosowy.$E$,
   'Jama nosowa — małżowiny nosowe', 'ANATLEK-254'),
(209, 'ANA-NER',
   'U 22-letniego pacjenta po przebytym zapaleniu ucha środkowego po stronie lewej wystąpiło tożstronne porażenie mięśni mimicznych twarzy. Powikłaniem postępu procesu chorobowego było uszkodzenie którego z nerwów?',
   '[{"id": "a", "text": "N. trójdzielny"}, {"id": "b", "text": "N. dodatkowy"}, {"id": "c", "text": "N. twarzowy"}, {"id": "d", "text": "N. przedsionkowo-ślimakowy"}, {"id": "e", "text": "N. językowo-gardłowy"}]'::jsonb,
   'c',
   $E$Mięśnie mimiczne twarzy unerwia ruchowo **nerw twarzowy (VII)**. Przebiega on w kanale nerwu twarzowego w obrębie kości skroniowej, w bezpośrednim sąsiedztwie jamy bębenkowej ucha środkowego. Dlatego zapalenie ucha środkowego może przez ciągłość uszkodzić nerw VII, dając tożstronne **porażenie obwodowe** mięśni mimicznych — opadnięcie kąta ust, niedomykanie powieki i zniesienie zmarszczek czoła po stronie chorej.$E$,
   'Nerw twarzowy (VII) — przebieg w kości skroniowej', 'ANATLEK-255'),
(210, 'ANA-KON',
   'Która z odpowiedzi przedstawia mięśnie warstwy I grupy przedniej mięśni przedramienia? I – m. zginacz łokciowy nadgarstka, II – m. dłoniowy długi, III – m. nawrotny czworoboczny, IV – m. zginacz długi kciuka, V – m. zginacz głęboki palców, VI – m. zginacz powierzchowny palców, VII – m. zginacz promieniowy nadgarstka, VIII – m. nawrotny obły',
   '[{"id": "a", "text": "I, II, VII, VIII"}, {"id": "b", "text": "III"}, {"id": "c", "text": "VI"}, {"id": "d", "text": "II, V"}, {"id": "e", "text": "IV, V"}]'::jsonb,
   'a',
   $E$**Warstwę powierzchowną (I) grupy przedniej przedramienia** tworzą cztery mięśnie, licząc od strony promieniowej do łokciowej: **nawrotny obły, zginacz promieniowy nadgarstka, dłoniowy długi i zginacz łokciowy nadgarstka** (I, II, VII, VIII). Warstwę pośrednią stanowi zginacz powierzchowny palców (VI), a warstwę głęboką — zginacz głęboki palców, zginacz długi kciuka i nawrotny czworoboczny. Wszystkie unerwia nerw pośrodkowy poza zginaczem łokciowym i częścią głębokiego (nerw łokciowy).$E$,
   'Mięśnie przedramienia — grupa przednia', 'ANATLEK-256')
),
maxes AS (
  SELECT topic_id, COALESCE(MAX( (regexp_match(id, '([0-9]+)$'))[1]::int ), 0) AS mx
    FROM public.questions WHERE topic_id IN ('ANA-CZA', 'ANA-JAM', 'ANA-KON', 'ANA-MIE', 'ANA-NAC', 'ANA-NER', 'ANA-OBW', 'ANA-OUN', 'ANA-TRZ', 'ANA-TUL') GROUP BY topic_id
)
INSERT INTO public.questions
  (id, topic_id, text, options, correct_option_id, explanation,
   subtheme_label, source_code, batch_label, source_exam)
SELECT
  LOWER(n.topic_id) || '-' || LPAD((COALESCE(m.mx,0) + ROW_NUMBER() OVER (PARTITION BY n.topic_id ORDER BY n.seq))::text, 3, '0'),
  n.topic_id, n.qtext, n.opts, n.correct, n.expl,
  n.subtheme, n.srccode, 'e_anat_2021/1', 'Egzamin anatomia LEK SUM 2021 (ANATLEK e2021-1)'
FROM new_rows n LEFT JOIN maxes m ON m.topic_id = n.topic_id;

UPDATE public.topics t SET question_count = sub.cnt
  FROM (SELECT topic_id, COUNT(*) AS cnt FROM public.questions
         WHERE topic_id IN ('ANA-CZA', 'ANA-JAM', 'ANA-KON', 'ANA-MIE', 'ANA-NAC', 'ANA-NER', 'ANA-OBW', 'ANA-OUN', 'ANA-TRZ', 'ANA-TUL') AND COALESCE(is_active,true)=true GROUP BY topic_id) sub
 WHERE t.id = sub.topic_id;
